    function setCompSpeedInternal(CToken cToken, uint compSpeed) internal {
        uint currentCompSpeed = compSpeeds[address(cToken)];
        if (currentCompSpeed != 0) {

            Exp memory borrowIndex = Exp({mantissa: cToken.borrowIndex()});
            updateCompSupplyIndex(address(cToken));
            updateCompBorrowIndex(address(cToken), borrowIndex);
        } else if (compSpeed != 0) {

            Market storage market = markets[address(cToken)];
            require(market.isListed == true, "comp market is not listed");

            if (compSupplyState[address(cToken)].index == 0 && compSupplyState[address(cToken)].block == 0) {
                compSupplyState[address(cToken)] = CompMarketState({
                    index: compInitialIndex,
                    block: safe32(getBlockNumber(), "block number exceeds 32 bits")
                });
            }

            if (compBorrowState[address(cToken)].index == 0 && compBorrowState[address(cToken)].block == 0) {
                compBorrowState[address(cToken)] = CompMarketState({
                    index: compInitialIndex,
                    block: safe32(getBlockNumber(), "block number exceeds 32 bits")
                });
            }
        }

        if (currentCompSpeed != compSpeed) {
            compSpeeds[address(cToken)] = compSpeed;
            emit CompSpeedUpdated(cToken, compSpeed);
        }
    }


    function updateCompSupplyIndex(address cToken) internal {
        CompMarketState storage supplyState = compSupplyState[cToken];
        uint supplySpeed = compSpeeds[cToken];
        uint blockNumber = getBlockNumber();
        uint deltaBlocks = sub_(blockNumber, uint(supplyState.block));
        if (deltaBlocks > 0 && supplySpeed > 0) {
            uint supplyTokens = CToken(cToken).totalSupply();
            uint compAccrued = mul_(deltaBlocks, supplySpeed);
            Double memory ratio = supplyTokens > 0 ? fraction(compAccrued, supplyTokens) : Double({mantissa: 0});
            Double memory index = add_(Double({mantissa: supplyState.index}), ratio);
            compSupplyState[cToken] = CompMarketState({
                index: safe224(index.mantissa, "new index exceeds 224 bits"),
                block: safe32(blockNumber, "block number exceeds 32 bits")
            });
        } else if (deltaBlocks > 0) {
            supplyState.block = safe32(blockNumber, "block number exceeds 32 bits");
        }
    }


    function updateCompBorrowIndex(address cToken, Exp memory marketBorrowIndex) internal {
        CompMarketState storage borrowState = compBorrowState[cToken];
        uint borrowSpeed = compSpeeds[cToken];
        uint blockNumber = getBlockNumber();
        uint deltaBlocks = sub_(blockNumber, uint(borrowState.block));
        if (deltaBlocks > 0 && borrowSpeed > 0) {
            uint borrowAmount = div_(CToken(cToken).totalBorrows(), marketBorrowIndex);
            uint compAccrued = mul_(deltaBlocks, borrowSpeed);
            Double memory ratio = borrowAmount > 0 ? fraction(compAccrued, borrowAmount) : Double({mantissa: 0});
            Double memory index = add_(Double({mantissa: borrowState.index}), ratio);
            compBorrowState[cToken] = CompMarketState({
                index: safe224(index.mantissa, "new index exceeds 224 bits"),
                block: safe32(blockNumber, "block number exceeds 32 bits")
            });
        } else if (deltaBlocks > 0) {
            borrowState.block = safe32(blockNumber, "block number exceeds 32 bits");
        }
    }


    function distributeSupplierComp(address cToken, address supplier) internal {
        CompMarketState storage supplyState = compSupplyState[cToken];
        Double memory supplyIndex = Double({mantissa: supplyState.index});
        Double memory supplierIndex = Double({mantissa: compSupplierIndex[cToken][supplier]});
        compSupplierIndex[cToken][supplier] = supplyIndex.mantissa;

        if (supplierIndex.mantissa == 0 && supplyIndex.mantissa > 0) {
            supplierIndex.mantissa = compInitialIndex;
        }

        Double memory deltaIndex = sub_(supplyIndex, supplierIndex);
        uint supplierTokens = CToken(cToken).balanceOf(supplier);
        uint supplierDelta = mul_(supplierTokens, deltaIndex);
        uint supplierAccrued = add_(compAccrued[supplier], supplierDelta);
        compAccrued[supplier] = supplierAccrued;
        emit DistributedSupplierComp(CToken(cToken), supplier, supplierDelta, supplyIndex.mantissa);
    }


    function distributeBorrowerComp(address cToken, address borrower, Exp memory marketBorrowIndex) internal {
        CompMarketState storage borrowState = compBorrowState[cToken];
        Double memory borrowIndex = Double({mantissa: borrowState.index});
        Double memory borrowerIndex = Double({mantissa: compBorrowerIndex[cToken][borrower]});
        compBorrowerIndex[cToken][borrower] = borrowIndex.mantissa;

        if (borrowerIndex.mantissa > 0) {
            Double memory deltaIndex = sub_(borrowIndex, borrowerIndex);
            uint borrowerAmount = div_(CToken(cToken).borrowBalanceStored(borrower), marketBorrowIndex);
            uint borrowerDelta = mul_(borrowerAmount, deltaIndex);
            uint borrowerAccrued = add_(compAccrued[borrower], borrowerDelta);
            compAccrued[borrower] = borrowerAccrued;
            emit DistributedBorrowerComp(CToken(cToken), borrower, borrowerDelta, borrowIndex.mantissa);
        }
    }


    function updateContributorRewards(address contributor) public {
        uint compSpeed = compContributorSpeeds[contributor];
        uint blockNumber = getBlockNumber();
        uint deltaBlocks = sub_(blockNumber, lastContributorBlock[contributor]);
        if (deltaBlocks > 0 && compSpeed > 0) {
            uint newAccrued = mul_(deltaBlocks, compSpeed);
            uint contributorAccrued = add_(compAccrued[contributor], newAccrued);

            compAccrued[contributor] = contributorAccrued;
            lastContributorBlock[contributor] = blockNumber;
        }
    }


    function claimComp(address holder) public {
        return claimComp(holder, allMarkets);
    }


    function claimComp(address holder, CToken[] memory cTokens) public {
        address[] memory holders = new address[](1);
        holders[0] = holder;
        claimComp(holders, cTokens, true, true);
    }


    function claimComp(address[] memory holders, CToken[] memory cTokens, bool borrowers, bool suppliers) public {
        for (uint i = 0; i < cTokens.length; i++) {
            CToken cToken = cTokens[i];
            require(markets[address(cToken)].isListed, "market must be listed");
            if (borrowers == true) {
                Exp memory borrowIndex = Exp({mantissa: cToken.borrowIndex()});
                updateCompBorrowIndex(address(cToken), borrowIndex);
                for (uint j = 0; j < holders.length; j++) {
                    distributeBorrowerComp(address(cToken), holders[j], borrowIndex);
                }
            }
            if (suppliers == true) {
                updateCompSupplyIndex(address(cToken));
                for (uint j = 0; j < holders.length; j++) {
                    distributeSupplierComp(address(cToken), holders[j]);
                }
            }
        }
        for (uint j = 0; j < holders.length; j++) {
            compAccrued[holders[j]] = grantCompInternal(holders[j], compAccrued[holders[j]]);
        }
    }


    function grantCompInternal(address user, uint amount) internal returns (uint) {
        Comp comp = Comp(getCompAddress());
        uint compRemaining = comp.balanceOf(address(this));
        if (amount > 0 && amount <= compRemaining) {
            comp.transfer(user, amount);
            return 0;
        }
        return amount;
    }




    function _grantComp(address recipient, uint amount) public {
        require(adminOrInitializing(), "only admin can grant comp");
        uint amountLeft = grantCompInternal(recipient, amount);
        require(amountLeft == 0, "insufficient comp for grant");
        emit CompGranted(recipient, amount);
    }


    function _setCompSpeed(CToken cToken, uint compSpeed) public {
        require(adminOrInitializing(), "only admin can set comp speed");
        setCompSpeedInternal(cToken, compSpeed);
    }


    function _setContributorCompSpeed(address contributor, uint compSpeed) public {
        require(adminOrInitializing(), "only admin can set comp speed");


        updateContributorRewards(contributor);
        if (compSpeed == 0) {

            delete lastContributorBlock[contributor];
        } else {
            lastContributorBlock[contributor] = getBlockNumber();
        }
        compContributorSpeeds[contributor] = compSpeed;

        emit ContributorCompSpeedUpdated(contributor, compSpeed);
    }


    function getAllMarkets() public view returns (CToken[] memory) {
        return allMarkets;
    }


    function isDeprecated(CToken cToken) public view returns (bool) {
        return
            markets[address(cToken)].collateralFactorMantissa == 0 &&
            borrowGuardianPaused[address(cToken)] == true &&
            cToken.reserveFactorMantissa() == 1e18
        ;
    }

    function getBlockNumber() virtual public view returns (uint) {
        return block.number;
    }


    function getCompAddress() virtual public view returns (address) {
        return 0xc00e94Cb662C3520282E6f5717214004A7f26888;
    }
}

pragma solidity ^0.8.6;

import "./ComptrollerInterface.sol";
import "./CTokenInterfaces.sol";
import "./ErrorReporter.sol";
import "./EIP20Interface.sol";
import "./InterestRateModel.sol";
import "./ExponentialNoError.sol";


abstract contract CToken is CTokenInterface, ExponentialNoError, TokenErrorReporter {

    function initialize(ComptrollerInterface comptroller_,
                        InterestRateModel interestRateModel_,
                        uint initialExchangeRateMantissa_,
                        string memory name_,
                        string memory symbol_,
                        uint8 decimals_) public {
        require(msg.sender == admin, "only admin may initialize the market");
        require(accrualBlockNumber == 0 && borrowIndex == 0, "market may only be initialized once");


        initialExchangeRateMantissa = initialExchangeRateMantissa_;
        require(initialExchangeRateMantissa > 0, "initial exchange rate must be greater than zero.");


        uint err = _setComptroller(comptroller_);
        require(err == NO_ERROR, "setting comptroller failed");


        accrualBlockNumber = getBlockNumber();
        borrowIndex = mantissaOne;


        err = _setInterestRateModelFresh(interestRateModel_);
        require(err == NO_ERROR, "setting interest rate model failed");

        name = name_;
        symbol = symbol_;
        decimals = decimals_;


        _notEntered = true;
    }


    function transferTokens(address spender, address src, address dst, uint tokens) internal returns (uint) {

        uint allowed = comptroller.transferAllowed(address(this), src, dst, tokens);
        if (allowed != 0) {
            revert TransferComptrollerRejection(allowed);
        }


        if (src == dst) {
            revert TransferNotAllowed();
        }


        uint startingAllowance = 0;
        if (spender == src) {
            startingAllowance = type(uint).max;
        } else {
            startingAllowance = transferAllowances[src][spender];
        }


        uint allowanceNew = startingAllowance - tokens;
        uint srcTokensNew = accountTokens[src] - tokens;
        uint dstTokensNew = accountTokens[dst] + tokens;





        accountTokens[src] = srcTokensNew;
        accountTokens[dst] = dstTokensNew;


        if (startingAllowance != type(uint).max) {
            transferAllowances[src][spender] = allowanceNew;
        }


        emit Transfer(src, dst, tokens);




        return NO_ERROR;
    }


    function transfer(address dst, uint256 amount) override external nonReentrant returns (bool) {
        return transferTokens(msg.sender, msg.sender, dst, amount) == NO_ERROR;
    }


    function transferFrom(address src, address dst, uint256 amount) override external nonReentrant returns (bool) {
        return transferTokens(msg.sender, src, dst, amount) == NO_ERROR;
    }


    function approve(address spender, uint256 amount) override external returns (bool) {
        address src = msg.sender;
        transferAllowances[src][spender] = amount;
        emit Approval(src, spender, amount);
        return true;
    }


    function allowance(address owner, address spender) override external view returns (uint256) {
        return transferAllowances[owner][spender];
    }


    function balanceOf(address owner) override external view returns (uint256) {
        return accountTokens[owner];
    }


    function balanceOfUnderlying(address owner) override external returns (uint) {
        Exp memory exchangeRate = Exp({mantissa: exchangeRateCurrent()});
        return mul_ScalarTruncate(exchangeRate, accountTokens[owner]);
    }


    function getAccountSnapshot(address account) override external view returns (uint, uint, uint, uint) {
        return (
            NO_ERROR,
            accountTokens[account],
            borrowBalanceStoredInternal(account),
            exchangeRateStoredInternal()
        );
    }


    function getBlockNumber() virtual internal view returns (uint) {
        return block.number;
    }


    function borrowRatePerBlock() override external view returns (uint) {
        return interestRateModel.getBorrowRate(getCashPrior(), totalBorrows, totalReserves);
    }


    function supplyRatePerBlock() override external view returns (uint) {
        return interestRateModel.getSupplyRate(getCashPrior(), totalBorrows, totalReserves, reserveFactorMantissa);
    }


    function totalBorrowsCurrent() override external nonReentrant returns (uint) {
        require(accrueInterest() == NO_ERROR, "accrue interest failed");
        return totalBorrows;
    }


    function borrowBalanceCurrent(address account) override external nonReentrant returns (uint) {
        require(accrueInterest() == NO_ERROR, "accrue interest failed");
        return borrowBalanceStored(account);
    }


    function borrowBalanceStored(address account) override public view returns (uint) {
        return borrowBalanceStoredInternal(account);
    }


    function borrowBalanceStoredInternal(address account) internal view returns (uint) {

        BorrowSnapshot storage borrowSnapshot = accountBorrows[account];


        if (borrowSnapshot.principal == 0) {
            return 0;
        }


        uint principalTimesIndex = borrowSnapshot.principal * borrowIndex;
        return principalTimesIndex / borrowSnapshot.interestIndex;
    }


    function exchangeRateCurrent() override public nonReentrant returns (uint) {
        require(accrueInterest() == NO_ERROR, "accrue interest failed");
        return exchangeRateStored();
    }


    function exchangeRateStored() override public view returns (uint) {
        return exchangeRateStoredInternal();
    }


    function exchangeRateStoredInternal() virtual internal view returns (uint) {
        uint _totalSupply = totalSupply;
        if (_totalSupply == 0) {

            return initialExchangeRateMantissa;
        } else {

            uint totalCash = getCashPrior();
            uint cashPlusBorrowsMinusReserves = totalCash + totalBorrows - totalReserves;
            Exp memory exchangeRate = Exp({mantissa: cashPlusBorrowsMinusReserves * expScale / _totalSupply});

            return exchangeRate.mantissa;
        }
    }


    function getCash() override external view returns (uint) {
        return getCashPrior();
    }


    function accrueInterest() virtual override public returns (uint) {

        uint currentBlockNumber = getBlockNumber();
        uint accrualBlockNumberPrior = accrualBlockNumber;


        if (accrualBlockNumberPrior == currentBlockNumber) {
            return NO_ERROR;
        }


        uint cashPrior = getCashPrior();
        uint borrowsPrior = totalBorrows;
        uint reservesPrior = totalReserves;
        uint borrowIndexPrior = borrowIndex;


        uint borrowRateMantissa = interestRateModel.getBorrowRate(cashPrior, borrowsPrior, reservesPrior);
        require(borrowRateMantissa <= borrowRateMaxMantissa, "borrow rate is absurdly high");


        uint blockDelta = currentBlockNumber - accrualBlockNumberPrior;



        Exp memory simpleInterestFactor = mul_(Exp({mantissa: borrowRateMantissa}), blockDelta);
        uint interestAccumulated = mul_ScalarTruncate(simpleInterestFactor, borrowsPrior);
        uint totalBorrowsNew = interestAccumulated + borrowsPrior;
        uint totalReservesNew = mul_ScalarTruncateAddUInt(Exp({mantissa: reserveFactorMantissa}), interestAccumulated, reservesPrior);
        uint borrowIndexNew = mul_ScalarTruncateAddUInt(simpleInterestFactor, borrowIndexPrior, borrowIndexPrior);






        accrualBlockNumber = currentBlockNumber;
        borrowIndex = borrowIndexNew;
        totalBorrows = totalBorrowsNew;
        totalReserves = totalReservesNew;


        emit AccrueInterest(cashPrior, interestAccumulated, borrowIndexNew, totalBorrowsNew);

        return NO_ERROR;
    }


    function mintInternal(uint mintAmount) internal nonReentrant {
        uint error = accrueInterest();
        if (error != NO_ERROR) {

            revert MintAccrueInterestFailed(error);
        }

        mintFresh(msg.sender, mintAmount);
    }


    function mintFresh(address minter, uint mintAmount) internal {

        uint allowed = comptroller.mintAllowed(address(this), minter, mintAmount);
        if (allowed != 0) {
            revert MintComptrollerRejection(allowed);
        }


        if (accrualBlockNumber != getBlockNumber()) {
            revert MintFreshnessCheck();
        }

        Exp memory exchangeRate = Exp({mantissa: exchangeRateStoredInternal()});






        uint actualMintAmount = doTransferIn(minter, mintAmount);



        uint mintTokens = div_(actualMintAmount, exchangeRate);


        totalSupply = totalSupply + mintTokens;
        accountTokens[minter] = accountTokens[minter] + mintTokens;


        emit Mint(minter, actualMintAmount, mintTokens);
        emit Transfer(address(this), minter, mintTokens);




    }


    function redeemInternal(uint redeemTokens) internal nonReentrant {
        uint error = accrueInterest();
        if (error != NO_ERROR) {

            revert RedeemAccrueInterestFailed(error);
        }

        redeemFresh(payable(msg.sender), redeemTokens, 0);
    }


    function redeemUnderlyingInternal(uint redeemAmount) internal nonReentrant {
        uint error = accrueInterest();
        if (error != NO_ERROR) {

            revert RedeemAccrueInterestFailed(error);
        }

        redeemFresh(payable(msg.sender), 0, redeemAmount);
    }


    function redeemFresh(address payable redeemer, uint redeemTokensIn, uint redeemAmountIn) internal {
        require(redeemTokensIn == 0 || redeemAmountIn == 0, "one of redeemTokensIn or redeemAmountIn must be zero");


        Exp memory exchangeRate = Exp({mantissa: exchangeRateStoredInternal() });

        uint redeemTokens;
        uint redeemAmount;

        if (redeemTokensIn > 0) {

            redeemTokens = redeemTokensIn;
            redeemAmount = mul_ScalarTruncate(exchangeRate, redeemTokensIn);
        } else {

            redeemTokens = div_(redeemAmountIn, exchangeRate);
            redeemAmount = redeemAmountIn;
        }


        uint allowed = comptroller.redeemAllowed(address(this), redeemer, redeemTokens);
        if (allowed != 0) {
            revert RedeemComptrollerRejection(allowed);
        }


        if (accrualBlockNumber != getBlockNumber()) {
            revert RedeemFreshnessCheck();
        }


        if (getCashPrior() < redeemAmount) {
            revert RedeemTransferOutNotPossible();
        }







        totalSupply = totalSupply - redeemTokens;
        accountTokens[redeemer] = accountTokens[redeemer] - redeemTokens;


        doTransferOut(redeemer, redeemAmount);


        emit Transfer(redeemer, address(this), redeemTokens);
        emit Redeem(redeemer, redeemAmount, redeemTokens);


        comptroller.redeemVerify(address(this), redeemer, redeemAmount, redeemTokens);
    }


    function borrowInternal(uint borrowAmount) internal nonReentrant {
        uint error = accrueInterest();
        if (error != NO_ERROR) {

            revert BorrowAccrueInterestFailed(error);
        }

        borrowFresh(payable(msg.sender), borrowAmount);
    }


    function borrowFresh(address payable borrower, uint borrowAmount) internal {

        uint allowed = comptroller.borrowAllowed(address(this), borrower, borrowAmount);
        if (allowed != 0) {
            revert BorrowComptrollerRejection(allowed);
        }


        if (accrualBlockNumber != getBlockNumber()) {
            revert BorrowFreshnessCheck();
        }


        if (getCashPrior() < borrowAmount) {
            revert BorrowCashNotAvailable();
        }


        uint accountBorrowsPrev = borrowBalanceStoredInternal(borrower);
        uint accountBorrowsNew = accountBorrowsPrev + borrowAmount;
        uint totalBorrowsNew = totalBorrows + borrowAmount;






        accountBorrows[borrower].principal = accountBorrowsNew;
        accountBorrows[borrower].interestIndex = borrowIndex;
        totalBorrows = totalBorrowsNew;


        doTransferOut(borrower, borrowAmount);


        emit Borrow(borrower, borrowAmount, accountBorrowsNew, totalBorrowsNew);
    }


    function repayBorrowInternal(uint repayAmount) internal nonReentrant {
        uint error = accrueInterest();
        if (error != NO_ERROR) {

            revert RepayBorrowAccrueInterestFailed(error);
        }

        repayBorrowFresh(msg.sender, msg.sender, repayAmount);
    }


    function repayBorrowBehalfInternal(address borrower, uint repayAmount) internal nonReentrant {
        uint error = accrueInterest();
        if (error != NO_ERROR) {

            revert RepayBehalfAccrueInterestFailed(error);
        }

        repayBorrowFresh(msg.sender, borrower, repayAmount);
    }


    function repayBorrowFresh(address payer, address borrower, uint repayAmount) internal returns (uint) {

        uint allowed = comptroller.repayBorrowAllowed(address(this), payer, borrower, repayAmount);
        if (allowed != 0) {
            revert RepayBorrowComptrollerRejection(allowed);
        }


        if (accrualBlockNumber != getBlockNumber()) {
            revert RepayBorrowFreshnessCheck();
        }


        uint accountBorrowsPrev = borrowBalanceStoredInternal(borrower);


        uint repayAmountFinal = repayAmount == type(uint).max ? accountBorrowsPrev : repayAmount;






        uint actualRepayAmount = doTransferIn(payer, repayAmountFinal);


        uint accountBorrowsNew = accountBorrowsPrev - actualRepayAmount;
        uint totalBorrowsNew = totalBorrows - actualRepayAmount;


        accountBorrows[borrower].principal = accountBorrowsNew;
        accountBorrows[borrower].interestIndex = borrowIndex;
        totalBorrows = totalBorrowsNew;


        emit RepayBorrow(payer, borrower, actualRepayAmount, accountBorrowsNew, totalBorrowsNew);

        return actualRepayAmount;
    }


    function liquidateBorrowInternal(address borrower, uint repayAmount, CTokenInterface cTokenCollateral) internal nonReentrant {
        uint error = accrueInterest();
        if (error != NO_ERROR) {

            revert LiquidateAccrueBorrowInterestFailed(error);
        }

        error = cTokenCollateral.accrueInterest();
        if (error != NO_ERROR) {

            revert LiquidateAccrueCollateralInterestFailed(error);
        }


        liquidateBorrowFresh(msg.sender, borrower, repayAmount, cTokenCollateral);
    }


    function liquidateBorrowFresh(address liquidator, address borrower, uint repayAmount, CTokenInterface cTokenCollateral) internal {

        uint allowed = comptroller.liquidateBorrowAllowed(address(this), address(cTokenCollateral), liquidator, borrower, repayAmount);
        if (allowed != 0) {
            revert LiquidateComptrollerRejection(allowed);
        }


        if (accrualBlockNumber != getBlockNumber()) {
            revert LiquidateFreshnessCheck();
        }


        if (cTokenCollateral.accrualBlockNumber() != getBlockNumber()) {
            revert LiquidateCollateralFreshnessCheck();
        }


        if (borrower == liquidator) {
            revert LiquidateLiquidatorIsBorrower();
        }


        if (repayAmount == 0) {
            revert LiquidateCloseAmountIsZero();
        }


        if (repayAmount == type(uint).max) {
            revert LiquidateCloseAmountIsUintMax();
        }


        uint actualRepayAmount = repayBorrowFresh(liquidator, borrower, repayAmount);






        (uint amountSeizeError, uint seizeTokens) = comptroller.liquidateCalculateSeizeTokens(address(this), address(cTokenCollateral), actualRepayAmount);
        require(amountSeizeError == NO_ERROR, "LIQUIDATE_COMPTROLLER_CALCULATE_AMOUNT_SEIZE_FAILED");


        require(cTokenCollateral.balanceOf(borrower) >= seizeTokens, "LIQUIDATE_SEIZE_TOO_MUCH");


        if (address(cTokenCollateral) == address(this)) {
            seizeInternal(address(this), liquidator, borrower, seizeTokens);
        } else {
            require(cTokenCollateral.seize(liquidator, borrower, seizeTokens) == NO_ERROR, "token seizure failed");
        }


        emit LiquidateBorrow(liquidator, borrower, actualRepayAmount, address(cTokenCollateral), seizeTokens);
    }


    function seize(address liquidator, address borrower, uint seizeTokens) override external nonReentrant returns (uint) {
        seizeInternal(msg.sender, liquidator, borrower, seizeTokens);

        return NO_ERROR;
    }


    function seizeInternal(address seizerToken, address liquidator, address borrower, uint seizeTokens) internal {

        uint allowed = comptroller.seizeAllowed(address(this), seizerToken, liquidator, borrower, seizeTokens);
        if (allowed != 0) {
            revert LiquidateSeizeComptrollerRejection(allowed);
        }


        if (borrower == liquidator) {
            revert LiquidateSeizeLiquidatorIsBorrower();
        }


        uint protocolSeizeTokens = mul_(seizeTokens, Exp({mantissa: protocolSeizeShareMantissa}));
        uint liquidatorSeizeTokens = seizeTokens - protocolSeizeTokens;
        Exp memory exchangeRate = Exp({mantissa: exchangeRateStoredInternal()});
        uint protocolSeizeAmount = mul_ScalarTruncate(exchangeRate, protocolSeizeTokens);
        uint totalReservesNew = totalReserves + protocolSeizeAmount;







        totalReserves = totalReservesNew;
        totalSupply = totalSupply - protocolSeizeTokens;
        accountTokens[borrower] = accountTokens[borrower] - seizeTokens;
        accountTokens[liquidator] = accountTokens[liquidator] + liquidatorSeizeTokens;


        emit Transfer(borrower, liquidator, liquidatorSeizeTokens);
        emit Transfer(borrower, address(this), protocolSeizeTokens);
        emit ReservesAdded(address(this), protocolSeizeAmount, totalReservesNew);
    }





    function _setPendingAdmin(address payable newPendingAdmin) override external returns (uint) {

        if (msg.sender != admin) {
            revert SetPendingAdminOwnerCheck();
        }


        address oldPendingAdmin = pendingAdmin;


        pendingAdmin = newPendingAdmin;


        emit NewPendingAdmin(oldPendingAdmin, newPendingAdmin);

        return NO_ERROR;
    }


    function _acceptAdmin() override external returns (uint) {

        if (msg.sender != pendingAdmin || msg.sender == address(0)) {
            revert AcceptAdminPendingAdminCheck();
        }


        address oldAdmin = admin;
        address oldPendingAdmin = pendingAdmin;


        admin = pendingAdmin;


        pendingAdmin = payable(address(0));

        emit NewAdmin(oldAdmin, admin);
        emit NewPendingAdmin(oldPendingAdmin, pendingAdmin);

        return NO_ERROR;
    }



    function _setComptroller(ComptrollerInterface newComptroller) override public returns (uint) {

        if (msg.sender != admin) {
            revert SetComptrollerOwnerCheck();
        }

        ComptrollerInterface oldComptroller = comptroller;

        require(newComptroller.isComptroller(), "marker method returned false");


        comptroller = newComptroller;


        emit NewComptroller(oldComptroller, newComptroller);

        return NO_ERROR;
    }


    function _setReserveFactor(uint newReserveFactorMantissa) override external nonReentrant returns (uint) {
        uint error = accrueInterest();
        if (error != NO_ERROR) {

            revert SetReserveFactorAccrueInterestFailed(error);
        }

        return _setReserveFactorFresh(newReserveFactorMantissa);
    }


    function _setReserveFactorFresh(uint newReserveFactorMantissa) internal returns (uint) {

        if (msg.sender != admin) {
            revert SetReserveFactorAdminCheck();
        }


        if (accrualBlockNumber != getBlockNumber()) {
            revert SetReserveFactorFreshCheck();
        }


        if (newReserveFactorMantissa > reserveFactorMaxMantissa) {
            revert SetReserveFactorBoundsCheck();
        }

        uint oldReserveFactorMantissa = reserveFactorMantissa;
        reserveFactorMantissa = newReserveFactorMantissa;

        emit NewReserveFactor(oldReserveFactorMantissa, newReserveFactorMantissa);

        return NO_ERROR;
    }


    function _addReservesInternal(uint addAmount) internal nonReentrant returns (uint) {
        uint error = accrueInterest();
        if (error != NO_ERROR) {

            revert AddReservesAccrueInterestFailed(error);
        }


        (error, ) = _addReservesFresh(addAmount);
        return error;
    }


    function _addReservesFresh(uint addAmount) internal returns (uint, uint) {

        uint totalReservesNew;
        uint actualAddAmount;


        if (accrualBlockNumber != getBlockNumber()) {
            revert AddReservesFactorFreshCheck(actualAddAmount);
        }







        actualAddAmount = doTransferIn(msg.sender, addAmount);

        totalReservesNew = totalReserves + actualAddAmount;


        totalReserves = totalReservesNew;


        emit ReservesAdded(msg.sender, actualAddAmount, totalReservesNew);


        return (NO_ERROR, actualAddAmount);
    }



    function _reduceReserves(uint reduceAmount) override external nonReentrant returns (uint) {
        uint error = accrueInterest();
        if (error != NO_ERROR) {

            revert ReduceReservesAccrueInterestFailed(error);
        }

        return _reduceReservesFresh(reduceAmount);
    }


    function _reduceReservesFresh(uint reduceAmount) internal returns (uint) {

        uint totalReservesNew;


        if (msg.sender != admin) {
            revert ReduceReservesAdminCheck();
        }


        if (accrualBlockNumber != getBlockNumber()) {
            revert ReduceReservesFreshCheck();
        }


        if (getCashPrior() < reduceAmount) {
            revert ReduceReservesCashNotAvailable();
        }


        if (reduceAmount > totalReserves) {
            revert ReduceReservesCashValidation();
        }





        totalReservesNew = totalReserves - reduceAmount;


        totalReserves = totalReservesNew;


        doTransferOut(admin, reduceAmount);

        emit ReservesReduced(admin, reduceAmount, totalReservesNew);

        return NO_ERROR;
    }


    function _setInterestRateModel(InterestRateModel newInterestRateModel) override public returns (uint) {
        uint error = accrueInterest();
        if (error != NO_ERROR) {

            revert SetInterestRateModelAccrueInterestFailed(error);
        }

        return _setInterestRateModelFresh(newInterestRateModel);
    }


    function _setInterestRateModelFresh(InterestRateModel newInterestRateModel) internal returns (uint) {


        InterestRateModel oldInterestRateModel;


        if (msg.sender != admin) {
            revert SetInterestRateModelOwnerCheck();
        }


        if (accrualBlockNumber != getBlockNumber()) {
            revert SetInterestRateModelFreshCheck();
        }


        oldInterestRateModel = interestRateModel;


        require(newInterestRateModel.isInterestRateModel(), "marker method returned false");


        interestRateModel = newInterestRateModel;


        emit NewMarketInterestRateModel(oldInterestRateModel, newInterestRateModel);

        return NO_ERROR;
    }




    function getCashPrior() virtual internal view returns (uint);


    function doTransferIn(address from, uint amount) virtual internal returns (uint);


    function doTransferOut(address payable to, uint amount) virtual internal;





    modifier nonReentrant() {
        require(_notEntered, "re-entered");
        _notEntered = false;
        _;
        _notEntered = true; 
    }
}

pragma solidity 0.7.5;

import "@openzeppelin/contracts/math/SafeMath.sol";
import "@openzeppelin/contracts/token/ERC20/SafeERC20.sol";
import "../../../interfaces/IERC677.sol";
import "../../../libraries/Bytes.sol";
import "../../ReentrancyGuard.sol";
import "../../BasicAMBMediator.sol";


abstract contract TokensRelayer is BasicAMBMediator, ReentrancyGuard {
    using SafeMath for uint256;
    using SafeERC20 for IERC677;


    function onTokenTransfer(
        address _from,
        uint256 _value,
        bytes memory _data
    ) external returns (bool) {
        if (!lock()) {
            bytes memory data = new bytes(0);
            address receiver = _from;
            if (_data.length >= 20) {
                receiver = Bytes.bytesToAddress(_data);
                if (_data.length > 20) {
                    assembly {
                        let size := sub(mload(_data), 20)
                        data := add(_data, 20)
                        mstore(data, size)
                    }
                }
            }
            bridgeSpecificActionsOnTokenTransfer(msg.sender, _from, receiver, _value, data);
        }
        return true;
    }


    function relayTokens(
        IERC677 token,
        address _receiver,
        uint256 _value
    ) external {
        _relayTokens(token, _receiver, _value, new bytes(0));
    }


    function relayTokens(IERC677 token, uint256 _value) external {
        _relayTokens(token, msg.sender, _value, new bytes(0));
    }


    function relayTokensAndCall(
        IERC677 token,
        address _receiver,
        uint256 _value,
        bytes memory _data
    ) external {
        _relayTokens(token, _receiver, _value, _data);
    }



    function _relayTokens(
        IERC677 token,
        address _receiver,
        uint256 _value,
        bytes memory _data
    ) internal {



        require(!lock());

        uint256 balanceBefore = token.balanceOf(address(this));
        setLock(true);
        token.safeTransferFrom(msg.sender, address(this), _value);
        setLock(false);
        uint256 balanceDiff = token.balanceOf(address(this)).sub(balanceBefore);
        require(balanceDiff <= _value);
        bridgeSpecificActionsOnTokenTransfer(address(token), msg.sender, _receiver, balanceDiff, _data);
    }

    function bridgeSpecificActionsOnTokenTransfer(
        address _token,
        address _from,
        address _receiver,
        uint256 _value,
        bytes memory _data
    ) internal virtual;
}

pragma solidity ^0.6.0;

import "./interfaces/IReferralFeeReceiver.sol";
import "./libraries/UniERC20.sol";
import "./utils/Converter.sol";


contract ReferralFeeReceiver is IReferralFeeReceiver, Converter {
    using UniERC20 for IERC20;

    struct UserInfo {
        uint256 balance;
        mapping(IERC20 => mapping(uint256 => uint256)) share;
        mapping(IERC20 => uint256) firstUnprocessedEpoch;
    }

    struct EpochBalance {
        uint256 totalSupply;
        uint256 token0Balance;
        uint256 token1Balance;
        uint256 inchBalance;
    }

    struct TokenInfo {
        mapping(uint256 => EpochBalance) epochBalance;
        uint256 firstUnprocessedEpoch;
        uint256 currentEpoch;
    }

    mapping(address => UserInfo) public userInfo;
    mapping(IERC20 => TokenInfo) public tokenInfo;


    constructor(IERC20 _inchToken, IMooniswapFactory _mooniswapFactory) public Converter(_inchToken, _mooniswapFactory) {}

    function updateReward(address referral, uint256 amount) external override {
        Mooniswap mooniswap = Mooniswap(msg.sender);
        TokenInfo storage token = tokenInfo[mooniswap];
        UserInfo storage user = userInfo[referral];
        uint256 currentEpoch = token.currentEpoch;


        user.share[mooniswap][currentEpoch] = user.share[mooniswap][currentEpoch].add(amount);
        token.epochBalance[currentEpoch].totalSupply = token.epochBalance[currentEpoch].totalSupply.add(amount);


        _collectProcessedEpochs(user, token, mooniswap, currentEpoch);
    }

    function freezeEpoch(Mooniswap mooniswap) external validPool(mooniswap) validSpread(mooniswap) {
        TokenInfo storage token = tokenInfo[mooniswap];
        uint256 currentEpoch = token.currentEpoch;
        require(token.firstUnprocessedEpoch == currentEpoch, "Previous epoch is not finalized");

        IERC20[] memory tokens = mooniswap.getTokens();
        uint256 token0Balance = tokens[0].uniBalanceOf(address(this));
        uint256 token1Balance = tokens[1].uniBalanceOf(address(this));
        mooniswap.withdraw(mooniswap.balanceOf(address(this)), new uint256[](0));
        token.epochBalance[currentEpoch].token0Balance = tokens[0].uniBalanceOf(address(this)).sub(token0Balance);
        token.epochBalance[currentEpoch].token1Balance = tokens[1].uniBalanceOf(address(this)).sub(token1Balance);
        token.currentEpoch = currentEpoch.add(1);
    }

    function trade(Mooniswap mooniswap, IERC20[] memory path) external validPool(mooniswap) validPath(path) {
        TokenInfo storage token = tokenInfo[mooniswap];
        uint256 firstUnprocessedEpoch = token.firstUnprocessedEpoch;
        EpochBalance storage epochBalance = token.epochBalance[firstUnprocessedEpoch];
        require(firstUnprocessedEpoch.add(1) == token.currentEpoch, "Prev epoch already finalized");

        IERC20[] memory tokens = mooniswap.getTokens();
        uint256 availableBalance;
        if (path[0] == tokens[0]) {
            availableBalance = epochBalance.token0Balance;
        } else if (path[0] == tokens[1]) {
            availableBalance = epochBalance.token1Balance;
        } else {
            revert("Invalid first token");
        }

        (uint256 amount, uint256 returnAmount) = _maxAmountForSwap(path, availableBalance);
        if (returnAmount == 0) {

            if (availableBalance > 0) {
                require(availableBalance == amount, "availableBalance is not dust");
                for (uint256 i = 0; i + 1 < path.length; i += 1) {
                    Mooniswap _mooniswap = mooniswapFactory.pools(path[i], path[i+1]);
                    require(_validateSpread(_mooniswap), "Spread is too high");
                }
                if (path[0].isETH()) {
                    tx.origin.transfer(availableBalance);  
                } else {
                    path[0].safeTransfer(address(mooniswap), availableBalance);
                }
            }
        } else {
            uint256 receivedAmount = _swap(path, amount, payable(address(this)));
            epochBalance.inchBalance = epochBalance.inchBalance.add(receivedAmount);
        }

        if (path[0] == tokens[0]) {
            epochBalance.token0Balance = epochBalance.token0Balance.sub(amount);
        } else {
            epochBalance.token1Balance = epochBalance.token1Balance.sub(amount);
        }

        if (epochBalance.token0Balance == 0 && epochBalance.token1Balance == 0) {
            token.firstUnprocessedEpoch = firstUnprocessedEpoch.add(1);
        }
    }

    function claim(Mooniswap[] memory pools) external {
        UserInfo storage user = userInfo[msg.sender];
        for (uint256 i = 0; i < pools.length; ++i) {
            Mooniswap mooniswap = pools[i];
            TokenInfo storage token = tokenInfo[mooniswap];
            _collectProcessedEpochs(user, token, mooniswap, token.currentEpoch);
        }

        uint256 balance = user.balance;
        if (balance > 1) {

            user.balance = 1;
            inchToken.transfer(msg.sender, balance - 1);
        }
    }

    function claimCurrentEpoch(Mooniswap mooniswap) external validPool(mooniswap) {
        TokenInfo storage token = tokenInfo[mooniswap];
        UserInfo storage user = userInfo[msg.sender];
        uint256 currentEpoch = token.currentEpoch;
        uint256 balance = user.share[mooniswap][currentEpoch];
        if (balance > 0) {
            user.share[mooniswap][currentEpoch] = 0;
            token.epochBalance[currentEpoch].totalSupply = token.epochBalance[currentEpoch].totalSupply.sub(balance);
            mooniswap.transfer(msg.sender, balance);
        }
    }

    function claimFrozenEpoch(Mooniswap mooniswap) external validPool(mooniswap) {
        TokenInfo storage token = tokenInfo[mooniswap];
        UserInfo storage user = userInfo[msg.sender];
        uint256 firstUnprocessedEpoch = token.firstUnprocessedEpoch;
        uint256 currentEpoch = token.currentEpoch;

        require(firstUnprocessedEpoch.add(1) == currentEpoch, "Epoch already finalized");
        require(user.firstUnprocessedEpoch[mooniswap] == firstUnprocessedEpoch, "Epoch funds already claimed");

        user.firstUnprocessedEpoch[mooniswap] = currentEpoch;
        uint256 share = user.share[mooniswap][firstUnprocessedEpoch];

        if (share > 0) {
            EpochBalance storage epochBalance = token.epochBalance[firstUnprocessedEpoch];
            uint256 totalSupply = epochBalance.totalSupply;
            user.share[mooniswap][firstUnprocessedEpoch] = 0;
            epochBalance.totalSupply = totalSupply.sub(share);

            IERC20[] memory tokens = mooniswap.getTokens();
            epochBalance.token0Balance = _transferTokenShare(tokens[0], epochBalance.token0Balance, share, totalSupply);
            epochBalance.token1Balance = _transferTokenShare(tokens[1], epochBalance.token1Balance, share, totalSupply);
            epochBalance.inchBalance = _transferTokenShare(inchToken, epochBalance.inchBalance, share, totalSupply);
        }
    }

    function _transferTokenShare(IERC20 token, uint256 balance, uint256 share, uint256 totalSupply) private returns(uint256 newBalance) {
        uint256 amount = balance.mul(share).div(totalSupply);
        if (amount > 0) {
            token.uniTransfer(msg.sender, amount);
        }
        return balance.sub(amount);
    }

    function _collectProcessedEpochs(UserInfo storage user, TokenInfo storage token, Mooniswap mooniswap, uint256 currentEpoch) private {

        if (user.share[mooniswap][user.firstUnprocessedEpoch[mooniswap]] == 0) {
            user.firstUnprocessedEpoch[mooniswap] = currentEpoch;
            return;
        }

        uint256 userEpoch = user.firstUnprocessedEpoch[mooniswap];
        uint256 tokenEpoch = token.firstUnprocessedEpoch;
        uint256 epochCount = Math.min(2, tokenEpoch.sub(userEpoch)); 
        if (epochCount == 0) {
            return;
        }


        uint256 collected = _collectEpoch(user, token, mooniswap, userEpoch);
        if (epochCount > 1) {
            collected = collected.add(_collectEpoch(user, token, mooniswap, userEpoch + 1));
        }
        user.balance = user.balance.add(collected);


        bool emptySecondEpoch = user.share[mooniswap][userEpoch + 1] == 0;
        user.firstUnprocessedEpoch[mooniswap] = (epochCount == 2 || emptySecondEpoch) ? currentEpoch : userEpoch + 1;
    }

    function _collectEpoch(UserInfo storage user, TokenInfo storage token, Mooniswap mooniswap, uint256 epoch) private returns(uint256 collected) {
        uint256 inchBalance = token.epochBalance[epoch].inchBalance;
        uint256 share = user.share[mooniswap][epoch];
        uint256 totalSupply = token.epochBalance[epoch].totalSupply;

        collected = inchBalance.mul(share).div(totalSupply);

        user.share[mooniswap][epoch] = 0;
        token.epochBalance[epoch].totalSupply = totalSupply.sub(share);
        token.epochBalance[epoch].inchBalance = inchBalance.sub(collected);
    }
}

pragma solidity 0.6.12;
pragma experimental ABIEncoderV2;

import "./libraries/ReentrancyGuard.sol";
import "./libraries/SafeERC20.sol";
import "./libraries/SafeMath.sol";
import "./interfaces/IArchangel.sol";
import "./interfaces/IAngel.sol";
import "./interfaces/IFountain.sol";
import "./interfaces/IFountainFactory.sol";
import "./utils/ErrorMsg.sol";
import "./FountainToken.sol";


abstract contract FountainBase is FountainToken, ReentrancyGuard, ErrorMsg {
    using SafeERC20 for IERC20;
    using SafeMath for uint256;


    IERC20 public immutable stakingToken;

    IFountainFactory public immutable factory;
    IArchangel public immutable archangel;


    struct AngelInfo {
        bool isSet;
        uint256 pid;
        uint256 totalBalance;
    }


    mapping(address => IAngel[]) private _joinedAngels;

    mapping(IAngel => AngelInfo) private _angelInfos;

    event Join(address user, address angel);
    event Quit(address user, address angel);
    event Deposit(address indexed user, uint256 amount, address indexed to);
    event Withdraw(address indexed user, uint256 amount, address indexed to);
    event EmergencyWithdraw(
        address indexed user,
        uint256 amount,
        address indexed to
    );
    event Harvest(address indexed user);

    constructor(IERC20 token) public {
        stakingToken = token;
        IFountainFactory f = IFountainFactory(msg.sender);
        factory = f;
        archangel = IArchangel(f.archangel());
    }



    function getContractName() public pure override returns (string memory) {
        return "Fountain";
    }




    function joinedAngel(address user) public view returns (IAngel[] memory) {
        return _joinedAngels[user];
    }






    function angelInfo(IAngel angel) public view returns (uint256, uint256) {
        AngelInfo storage info = _angelInfos[angel];
        _requireMsg(info.isSet, "angelInfo", "Fountain: angel not set");
        return (info.pid, info.totalBalance);
    }





    function setPoolId(uint256 pid) external {
        IAngel angel = IAngel(_msgSender());
        AngelInfo storage info = _angelInfos[angel];
        _requireMsg(info.isSet == false, "setPoolId", "Fountain: angel is set");
        _requireMsg(
            angel.lpToken(pid) == address(stakingToken),
            "setPoolId",
            "Fountain: token not matched"
        );
        info.isSet = true;
        info.pid = pid;
    }






    function deposit(uint256 amount) external {

        _mint(_msgSender(), amount);


        stakingToken.safeTransferFrom(_msgSender(), address(this), amount);

        emit Deposit(_msgSender(), amount, _msgSender());
    }







    function depositTo(uint256 amount, address to) external {

        _mint(to, amount);


        stakingToken.safeTransferFrom(_msgSender(), address(this), amount);
        emit Deposit(_msgSender(), amount, to);
    }





    function withdraw(uint256 amount) external {

        amount = amount == type(uint256).max ? balanceOf(_msgSender()) : amount;


        _burn(_msgSender(), amount);


        stakingToken.safeTransfer(_msgSender(), amount);
        emit Withdraw(_msgSender(), amount, _msgSender());
    }






    function withdrawTo(uint256 amount, address to) external {

        amount = amount == type(uint256).max ? balanceOf(_msgSender()) : amount;


        _burn(_msgSender(), amount);


        stakingToken.safeTransfer(to, amount);
        emit Withdraw(_msgSender(), amount, to);
    }



    function harvest(IAngel angel) external {
        _harvestAngel(angel, _msgSender(), _msgSender());
        emit Harvest(_msgSender());
    }


    function harvestAll() external {

        IAngel[] storage angels = _joinedAngels[_msgSender()];
        for (uint256 i = 0; i < angels.length; i++) {
            IAngel angel = angels[i];
            _harvestAngel(angel, _msgSender(), _msgSender());
        }
        emit Harvest(_msgSender());
    }


    function emergencyWithdraw() external {
        uint256 amount = balanceOf(_msgSender());


        _burn(_msgSender(), type(uint256).max);


        stakingToken.safeTransfer(_msgSender(), amount);
        emit EmergencyWithdraw(_msgSender(), amount, _msgSender());
    }



    function joinAngel(IAngel angel) external {
        _joinAngel(angel, _msgSender());
    }



    function joinAngels(IAngel[] calldata angels) external {
        for (uint256 i = 0; i < angels.length; i++) {
            _joinAngel(angels[i], _msgSender());
        }
    }



    function quitAngel(IAngel angel) external {
        IAngel[] storage angels = _joinedAngels[_msgSender()];
        uint256 len = angels.length;
        if (angels[len - 1] == angel) {
            angels.pop();
        } else {
            for (uint256 i = 0; i < len - 1; i++) {
                if (angels[i] == angel) {
                    angels[i] = angels[len - 1];
                    angels.pop();
                    break;
                }
            }
        }
        _requireMsg(
            angels.length != len,
            "quitAngel",
            "Fountain: unjoined angel"
        );

        emit Quit(_msgSender(), address(angel));


        _withdrawAngel(_msgSender(), angel, balanceOf(_msgSender()));
    }


    function quitAllAngel() external {
        IAngel[] storage angels = _joinedAngels[_msgSender()];
        for (uint256 i = 0; i < angels.length; i++) {
            IAngel angel = angels[i];
            emit Quit(_msgSender(), address(angel));

            _withdrawAngel(_msgSender(), angel, balanceOf(_msgSender()));
        }
        delete _joinedAngels[_msgSender()];
    }




    function _beforeTokenTransfer(
        address from,
        address to,
        uint256 amount
    ) internal override {
        if (from != address(0)) {
            IAngel[] storage angels = _joinedAngels[from];
            if (amount < type(uint256).max) {
                for (uint256 i = 0; i < angels.length; i++) {
                    IAngel angel = angels[i];
                    _withdrawAngel(from, angel, amount);
                }
            } else {
                for (uint256 i = 0; i < angels.length; i++) {
                    IAngel angel = angels[i];
                    _emergencyWithdrawAngel(from, angel);
                }
            }
        }
        if (to != address(0)) {
            IAngel[] storage angels = _joinedAngels[to];
            for (uint256 i = 0; i < angels.length; i++) {
                IAngel angel = angels[i];
                _depositAngel(to, angel, amount);
            }
        }
    }




    function _depositAngel(
        address user,
        IAngel angel,
        uint256 amount
    ) internal nonReentrant {
        AngelInfo storage info = _angelInfos[angel];
        _requireMsg(
            info.isSet,
            "_depositAngel",
            "Fountain: not added by angel"
        );
        angel.deposit(info.pid, amount, user);
        info.totalBalance = info.totalBalance.add(amount);
    }


    function _withdrawAngel(
        address user,
        IAngel angel,
        uint256 amount
    ) internal nonReentrant {
        AngelInfo storage info = _angelInfos[angel];
        _requireMsg(
            info.isSet,
            "_withdrawAngel",
            "Fountain: not added by angel"
        );
        angel.withdraw(info.pid, amount, user);
        info.totalBalance = info.totalBalance.sub(amount);
    }

    function _harvestAngel(
        IAngel angel,
        address from,
        address to
    ) internal nonReentrant {
        AngelInfo storage info = _angelInfos[angel];
        _requireMsg(
            info.isSet,
            "_harvestAngel",
            "Fountain: not added by angel"
        );
        angel.harvest(info.pid, from, to);
    }

    function _emergencyWithdrawAngel(address user, IAngel angel)
        internal
        nonReentrant
    {
        AngelInfo storage info = _angelInfos[angel];
        _requireMsg(
            info.isSet,
            "_emergencyAngel",
            "Fountain: not added by angel"
        );
        uint256 amount = balanceOf(user);
        angel.emergencyWithdraw(info.pid, user);
        info.totalBalance = info.totalBalance.sub(amount);
    }

    function _joinAngel(IAngel angel, address user) internal {
        IAngel[] storage angels = _joinedAngels[user];
        for (uint256 i = 0; i < angels.length; i++) {
            _requireMsg(angels[i] != angel, "_joinAngel", "Angel joined");
        }
        angels.push(angel);

        emit Join(user, address(angel));


        _depositAngel(user, angel, balanceOf(user));
    }
}

