    function addStake(uint256 amount)
        public
        Active
        hasApprovedTokens(_woopERC20, _msgSender(), amount)
        returns (bool)
    {
        require(amount >= getfractionUnit(), "WO:-am");

        IERC20 _token = IERC20(_woopERC20);

        require(
            _token.transferFrom(_msgSender(), address(this), amount),
            "WO:-etf"
        );

        require(_addStake(_msgSender(), amount), "WO:eas");

        return true;
    }

    function _addStake(address account, uint256 amount)
        internal
        Active
        returns (bool)
    {
        if (!_stakes.StakeExist(account)) {
            _stakes.newStake(account, amount);
        } else {
            _stakes.addToStake(account, amount);
        }

        return true;
    }

    function _withdrawFunds(address account, uint256 amount)
        internal
        Active
        returns (uint256)
    {
        require(_stakes.StakeExist(account), "WO:!");
        uint256 fund;
        bool autoC;

        (fund, autoC) = _stakes.getStake(account);

        require(amount <= fund, "WO:eef");

        uint256 remainder = fund.sub(amount);

        if (remainder == 0) {
            _stakes.removeStake(account);
        } else {
            _stakes.renewStake(account, remainder);
        }

        emit WithdrawFunds(account, amount, remainder);

        return amount;
    }

    function withdrawFunds(uint256 amount)
        public
        Active
        nonReentrant
        returns (bool)
    {
        require(_stakes.StakeExist(_msgSender()), "WO:!");
        require(
            _inv.canWithdrawFunds(
                _msgSender(),
                amount,
                _stakes.balanceOf(_msgSender())
            ),
            "WO:!i"
        );

        IERC20 _token = IERC20(_woopERC20);

        require(_token.transfer(_msgSender(), amount), "WO:ewf");
        _withdrawFunds(_msgSender(), amount);

        _inv.updateFund(_msgSender(), amount);
        return true;
    }

    function _withdrawReward(
        address sc,
        address account,
        uint256 amount
    ) internal Active nonReentrant returns (uint256) {
        IERC20 _token = IERC20(sc);

        uint256 rew = rewarded(sc, account);

        require(amount <= rew, "WO:amew");

        require(amount <= getMyTokensBalance(sc), "WO:-tk");

        require(_token.transfer(account, amount));

        uint256 remainder = rew.sub(amount);



        _doreward(sc, account, remainder);


       emit RewardWithdrawed(sc, account, amount, remainder);

        return amount;
    }

    function _compoundReward(address account, uint256 amount)
        internal
        Active
        returns (uint256)
    {
        uint256 rew = rewarded(_woopERC20, account);

        require(amount <= rew, "WO: am>w");

        require(amount <= getMyTokensBalance(_woopERC20), "WO:-tk");

        uint256 remainder = rew.sub(amount);



        _doreward(_woopERC20, account, remainder);


        _stakes.addToStake(account, amount);

        emit RewardToCompound(account, amount);

        return amount;
    }

    function WithdrawReward(address sc, uint256 amount)
        public
        Active
        returns (bool)
    {
        _withdrawReward(sc, _msgSender(), amount);

        return true;
    }

    function CompoundReward(uint256 amount)
        public
        Active
        nonReentrant
        returns (bool)
    {
        _compoundReward(_msgSender(), amount);

        return true;
    }

    function _withdrawRewardCOIN(address account, uint256 amount)
        internal
        Active
        nonReentrant
        returns (uint256)
    {
        uint256 rew = rewardedCOIN(account);

        require(amount <= rew, "WO:am++");

        require(amount <= getMyCoinBalance(), "WO:tk-");

        address payable acc = address(uint160(address(account)));

        acc.transfer(amount);

        uint256 remainder = rew.sub(amount);



        _dorewardCOIN(account,remainder);

        emit RewardCOINWithdrawed(account, amount, remainder);

        return amount;
    }

    function WithdrawRewardCOIN(uint256 amount) public Active returns (bool) {
        _withdrawRewardCOIN(_msgSender(), amount);

        return true;
    }

    function getCalcRewardAmount(address account, uint256 amount)
        public
        view
        returns (uint256, uint256)
    {
        if (!_stakes.StakeExist(account)) return (0, 0);

        uint256 fund = 0;
        bool autoC;

        (fund, autoC) = _stakes.getStake(account);

        if (fund < getfractionUnit()) return (0, 0);

        uint256 factor = fund.div(getfractionUnit());

        if (factor < 1) return (0, 0);

        uint256 remainder = fund.sub(factor.mul(getfractionUnit()));

        uint256 woopsRewards = calcReward(amount, factor);

        if (woopsRewards < 1) return (0, 0);

        return (woopsRewards, remainder);
    }

    function calcReward(uint256 amount, uint256 factor)
        public
        view
        returns (uint256)
    {
        return amount.mul(factor).div(_factor);
    }

    function calcTotalRewards(uint256 amount) public view returns (uint256) {
        uint256 remainder;
        uint256 woopsRewards;
        uint256 ind = 0;
        uint256 total = 0;

        Stake memory p;

        uint256 last = _stakes.getLastIndexStakes();

        for (uint256 i = 0; i < (last + 1); i++) {
            (p.account, p.bal, p.autoCompound, p.flag) = _stakes
                .getStakeByIndex(i);

            if (p.flag == 1) {
                (woopsRewards, remainder) = getCalcRewardAmount(
                    p.account,
                    amount
                );
                if (woopsRewards > 0) {
                    total = total.add(woopsRewards);
                }
                ind++;
            }
        }

        return total;
    }

    function _processReward_1(
        IERC20 _token,
        address account,
        uint256 amount
    ) internal returns (bool) {
        require(_token.transferFrom(account, address(this), amount), "WO:etr");
        return true;
    }

    function _processReward_2(address sc, uint256 amount)
        internal
        returns (uint256)
    {
        processRewardInfo memory slot;

        Stake memory p;

        uint256 last = _stakes.getLastIndexStakes();

        for (uint256 i = 0; i < (last + 1); i++) {
            (p.account, p.bal, p.autoCompound, p.flag) = _stakes
                .getStakeByIndex(i);

            if (p.flag == 1) {
                (slot.woopsRewards, slot.remainder) = getCalcRewardAmount(
                    p.account,
                    amount
                );
                if (slot.woopsRewards > 0) {
                    if (
                        _stakes.getAutoCompoundStatus(p.account) &&
                        sc == _woopERC20
                    ) {
                        _stakes.addToStake(p.account, slot.woopsRewards);
                    } else {
                        _increaseRewards(sc, p.account, slot.woopsRewards);
                    }

                    slot.dealed = slot.dealed.add(slot.woopsRewards);
                } else {
                    emit InsuficientRewardFund(sc, p.account);
                }
            }
        } 

        _distributeds[sc] = _distributeds[sc].add(slot.dealed);

        return slot.dealed;
    }


    function processReward(address sc, uint256 amount)
        public
        nonReentrant
        Active
        hasApprovedTokens(sc, _msgSender(), amount)
        ProviderHasToken(sc, amount)
        returns (bool)
    {
        if (!ERC20Exist(sc)) {
            newERC20(sc);
        }

        processRewardInfo memory slot;

        IERC20 _token = IERC20(sc);
        _processReward_1(_token, _msgSender(), amount);

        slot.dealed = _processReward_2(sc, amount);

        uint256 leftover = amount.sub(slot.dealed);
        if (leftover > 0) {
            require(_token.transfer(_remainder, leftover), "WO:trf");
            emit NewLeftover(sc, _remainder, leftover);
        }

        return true;
    }

    function _processReward_2COIN(uint256 amount) internal returns (uint256) {
        processRewardInfo memory slot;
        Stake memory p;

        uint256 last = _stakes.getLastIndexStakes();

        for (uint256 i = 0; i < (last + 1); i++) {
            (p.account, p.bal, p.autoCompound, p.flag) = _stakes
                .getStakeByIndex(i);

            if (p.flag == 1) {
                (slot.woopsRewards, slot.remainder) = getCalcRewardAmount(
                    p.account,
                    amount
                );

                if (slot.woopsRewards > 0) {
                    _increaseRewardsCOIN(p.account, slot.woopsRewards);

                    slot.dealed = slot.dealed.add(slot.woopsRewards);
                } else {
                    emit InsuficientRewardFundCOIN(p.account);
                }
            }
        } 

        return slot.dealed;
    }

    function _processRewardCOIN(uint256 amount)
        internal
        nonReentrant
        Active
        returns (bool)
    {
        processRewardInfo memory slot;

        address payable nrem = address(uint160(_remainder));

        slot.dealed = _processReward_2COIN(amount);

        _distributedCOIN = _distributedCOIN.add(slot.dealed);

        uint256 leftover = amount.sub(slot.dealed);
        if (leftover > 0) {
            nrem.transfer(leftover);
            emit NewLeftoverCOIN(_remainder, leftover);
        }

        return true;
    }

    function closeStakes() public onlyIsInOwners nonReentrant returns (bool) {
        uint256 totRew = 0;

        uint256 toSC = _lastIndexE20s + 1;

        for (uint32 i = 0; i < (_lastIndexE20s + 1); i++) {
            E20 memory p = _E20s[i];
            if (p.flag == 1) {
                totRew = totRew.add(_withdrawAllrewards(p.sc));
            }
        }

        totRew = totRew.add(_withdrawAllrewardsCOIN());

        uint256 fund;
        bool autoC;
        uint256 funds = 0;

        Stake memory p;

        uint256 last = _stakes.getLastIndexStakes();

        for (uint256 i = 0; i < (last + 1); i++) {
            (p.account, p.bal, p.autoCompound, p.flag) = _stakes
                .getStakeByIndex(i);
            if (p.flag == 1) {
                (fund, autoC) = _stakes.getStake(p.account);
                _withdrawFunds(p.account, fund);
                funds = funds.add(fund);
            }
        }

        setPause(true);
        _stakes.removeAllStake();

        emit StakeClosed(toSC, (last + 1), funds, totRew);
        return true;
    }

    function _withdrawAllrewardsCOIN()
        internal
        SolvencyCOIN()
        nonReentrant
        returns (uint256)
    {
        uint256 total = 0;
        uint256 rew = 0;
        Stake memory p;

        uint256 last = _stakes.getLastIndexStakes();

        for (uint256 i = 0; i < (last + 1); i++) {
            (p.account, p.bal, p.autoCompound, p.flag) = _stakes
                .getStakeByIndex(i);

            if (p.flag == 1) {
                rew = rewardedCOIN(p.account);

                if (rew > 0) {
                    _withdrawRewardCOIN(p.account, rew);
                    total = total.add(rew);
                }
            }
        }

        uint256 eth_reserve = address(this).balance;

        if (eth_reserve > 0) {
            address payable ow = address(uint160(_remainder));
            ow.transfer(eth_reserve);
        }

        return total;
    }

    function _withdrawAllrewards(address sc)
        internal
        Solvency(sc)
        returns (uint256)
    {
        uint256 total = 0;
        uint256 rew = 0;

        Stake memory p;

        uint256 last = _stakes.getLastIndexStakes();

        for (uint256 i = 0; i < (last + 1); i++) {
            (p.account, p.bal, p.autoCompound, p.flag) = _stakes
                .getStakeByIndex(i);

            if (p.flag == 1) {
                rew = rewarded(sc, p.account);

                if (rew > 0) {
                    _withdrawReward(sc, p.account, rew);
                    total = total.add(rew);
                }
            }
        }

        IERC20 _token = IERC20(sc);

        uint256 token_reserve = _token.balanceOf(address(this));

        if (token_reserve > 0) {
            require(_token.transfer(_remainder, token_reserve), "WO:trf");
        }

        return total;
    }

    function getSolvencyCOIN() public view returns (bool, uint256) {
        uint256 ind = 0;
        uint256 funds = 0;
        uint256 rews = 0;
        uint256 rewsc = 0;
        uint256 autos = 0;

        (ind, funds, rews, rewsc, autos) = getStatistics(_woopERC20);

        uint256 coins = getMyCoinBalance();

        if (coins < rewsc) {
            return (false, rewsc - coins);
        } else {
            return (true, coins - rewsc);
        }
    }

    function getSolvency(address sc) public view returns (bool, uint256) {
        Stadistic memory s;

        (s.ind, s.funds, s.rews, , ) = getStatistics(sc);

        uint256 tokens = getMyTokensBalance(sc);

        uint256 tot = s.funds + s.rews;

        if (tokens < tot) {
            return (false, tot - tokens);
        } else {
            return (true, tokens - tot);
        }
    }

    function getStatistics(address sc)
        public
        view
        returns (
            uint256,
            uint256,
            uint256,
            uint256,
            uint256
        )
    {
        uint256 fund;
        bool autoC;

        Stadistic memory s;

        Stake memory p;

        uint256 last = _stakes.getLastIndexStakes();

        for (uint256 i = 0; i < (last + 1); i++) {
            (p.account, p.bal, p.autoCompound, p.flag) = _stakes
                .getStakeByIndex(i);

            if (p.flag == 1) {
                (fund, autoC) = _stakes.getStake(p.account);

                if (sc == _woopERC20) {
                    s.funds = s.funds.add(fund);
                }

                fund = rewarded(sc, p.account);

                s.rews = s.rews.add(fund);

                fund = rewardedCOIN(p.account);

                s.rewsCOIN = s.rewsCOIN.add(fund);

                if (autoC) {
                    s.autocs++;
                }
                s.ind++;
            }
        }

        return (s.ind, s.funds, s.rews, s.rewsCOIN, s.autocs);
    }
}

pragma solidity 0.8.6;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";

import "./amm/interfaces/ITempusAMM.sol";
import "./amm/interfaces/IVault.sol";
import "./ITempusPool.sol";
import "./math/Fixed256x18.sol";
import "./utils/PermanentlyOwnable.sol";

contract TempusController is PermanentlyOwnable {
    using Fixed256x18 for uint256;
    using SafeERC20 for IERC20;










    event Deposited(
        address indexed pool,
        address indexed depositor,
        address indexed recipient,
        uint256 yieldTokenAmount,
        uint256 backingTokenValue,
        uint256 shareAmounts,
        uint256 interestRate
    );










    event Redeemed(
        address indexed pool,
        address indexed redeemer,
        address indexed recipient,
        uint256 principalShareAmount,
        uint256 yieldShareAmount,
        uint256 yieldBearingAmount,
        uint256 backingTokenValue,
        uint256 interestRate
    );






    function depositAndProvideLiquidity(
        ITempusAMM tempusAMM,
        uint256 tokenAmount,
        bool isBackingToken
    ) external payable {
        (
            IVault vault,
            bytes32 poolId,
            IERC20[] memory ammTokens,
            uint256[] memory ammBalances
        ) = getAMMDetailsAndEnsureInitialized(tempusAMM);

        ITempusPool targetPool = tempusAMM.tempusPool();

        if (isBackingToken) {
            depositBacking(targetPool, tokenAmount, address(this));
        } else {
            depositYieldBearing(targetPool, tokenAmount, address(this));
        }

        uint256[2] memory ammDepositPercentages = getAMMBalancesRatio(ammBalances);
        uint256[] memory ammLiquidityProvisionAmounts = new uint256[](2);

        (ammLiquidityProvisionAmounts[0], ammLiquidityProvisionAmounts[1]) = (
            ammTokens[0].balanceOf(address(this)).mulf18(ammDepositPercentages[0]),
            ammTokens[1].balanceOf(address(this)).mulf18(ammDepositPercentages[1])
        );

        ammTokens[0].safeIncreaseAllowance(address(vault), ammLiquidityProvisionAmounts[0]);
        ammTokens[1].safeIncreaseAllowance(address(vault), ammLiquidityProvisionAmounts[1]);

        IVault.JoinPoolRequest memory request = IVault.JoinPoolRequest({
            assets: ammTokens,
            maxAmountsIn: ammLiquidityProvisionAmounts,
            userData: abi.encode(uint8(ITempusAMM.JoinKind.EXACT_TOKENS_IN_FOR_BPT_OUT), ammLiquidityProvisionAmounts),
            fromInternalBalance: false
        });


        vault.joinPool(poolId, address(this), msg.sender, request);


        if (ammDepositPercentages[0] < Fixed256x18.ONE) {
            ammTokens[0].safeTransfer(msg.sender, ammTokens[0].balanceOf(address(this)));
        }
        if (ammDepositPercentages[1] < Fixed256x18.ONE) {
            ammTokens[1].safeTransfer(msg.sender, ammTokens[1].balanceOf(address(this)));
        }
    }







    function depositAndFix(
        ITempusAMM tempusAMM,
        uint256 tokenAmount,
        bool isBackingToken,
        uint256 minTYSRate
    ) external payable {
        (IVault vault, bytes32 poolId, , ) = getAMMDetailsAndEnsureInitialized(tempusAMM);

        ITempusPool targetPool = tempusAMM.tempusPool();

        if (isBackingToken) {
            depositBacking(targetPool, tokenAmount, address(this));
        } else {
            depositYieldBearing(targetPool, tokenAmount, address(this));
        }

        IERC20 principalShares = IERC20(address(targetPool.principalShare()));
        IERC20 yieldShares = IERC20(address(targetPool.yieldShare()));
        uint256 swapAmount = yieldShares.balanceOf(address(this));
        yieldShares.safeIncreaseAllowance(address(vault), swapAmount);


        IVault.SingleSwap memory singleSwap = IVault.SingleSwap({
            poolId: poolId,
            kind: IVault.SwapKind.GIVEN_IN,
            assetIn: yieldShares,
            assetOut: principalShares,
            amount: swapAmount,
            userData: ""
        });

        IVault.FundManagement memory fundManagement = IVault.FundManagement({
            sender: address(this),
            fromInternalBalance: false,
            recipient: payable(address(this)),
            toInternalBalance: false
        });

        uint256 minReturn = swapAmount.mulf18(minTYSRate);
        vault.swap(singleSwap, fundManagement, minReturn, block.timestamp);

        uint256 TPSBalance = principalShares.balanceOf(address(this));
        assert(TPSBalance > 0);
        assert(yieldShares.balanceOf(address(this)) == 0);

        principalShares.safeTransfer(msg.sender, TPSBalance);
    }





    function depositYieldBearing(
        ITempusPool targetPool,
        uint256 yieldTokenAmount,
        address recipient
    ) public {
        require(yieldTokenAmount > 0, "yieldTokenAmount is 0");

        IERC20 yieldBearingToken = IERC20(targetPool.yieldBearingToken());


        yieldBearingToken.safeTransferFrom(msg.sender, address(this), yieldTokenAmount);
        yieldBearingToken.safeIncreaseAllowance(address(targetPool), yieldTokenAmount);
        (uint256 mintedShares, uint256 depositedBT, uint256 interestRate) = targetPool.deposit(
            yieldTokenAmount,
            recipient
        );

        emit Deposited(
            address(targetPool),
            msg.sender,
            recipient,
            yieldTokenAmount,
            depositedBT,
            mintedShares,
            interestRate
        );
    }






    function depositBacking(
        ITempusPool targetPool,
        uint256 backingTokenAmount,
        address recipient
    ) public payable {
        require(backingTokenAmount > 0, "backingTokenAmount is 0");

        IERC20 backingToken = IERC20(targetPool.backingToken());

        if (msg.value == 0) {
            backingToken.safeTransferFrom(msg.sender, address(this), backingTokenAmount);
            backingToken.safeIncreaseAllowance(address(targetPool), backingTokenAmount);
        } else {
            require(address(backingToken) == address(0), "given TempusPool's Backing Token is not ETH");
        }

        (uint256 mintedShares, uint256 depositedYBT, uint256 interestRate) = targetPool.depositBacking{
            value: msg.value
        }(backingTokenAmount, recipient);

        emit Deposited(
            address(targetPool),
            msg.sender,
            recipient,
            depositedYBT,
            backingTokenAmount,
            mintedShares,
            interestRate
        );
    }










    function redeemToYieldBearing(
        ITempusPool targetPool,
        address sender,
        uint256 principalAmount,
        uint256 yieldAmount,
        address recipient
    ) public {
        require((principalAmount > 0) || (yieldAmount > 0), "principalAmount and yieldAmount cannot both be 0");

        (uint256 redeemedYBT, uint256 interestRate) = targetPool.redeem(
            sender,
            principalAmount,
            yieldAmount,
            recipient
        );

        uint256 redeemedBT = targetPool.numAssetsPerYieldToken(redeemedYBT, targetPool.currentInterestRate());
        emit Redeemed(
            address(targetPool),
            sender,
            recipient,
            principalAmount,
            yieldAmount,
            redeemedYBT,
            redeemedBT,
            interestRate
        );
    }











    function redeemToBacking(
        ITempusPool targetPool,
        address sender,
        uint256 principalAmount,
        uint256 yieldAmount,
        address recipient
    ) public {
        require((principalAmount > 0) || (yieldAmount > 0), "principalAmount and yieldAmount cannot both be 0");

        (uint256 redeemedYBT, uint256 redeemedBT, uint256 interestRate) = targetPool.redeemToBacking(
            sender,
            principalAmount,
            yieldAmount,
            recipient
        );

        emit Redeemed(
            address(targetPool),
            sender,
            recipient,
            principalAmount,
            yieldAmount,
            redeemedYBT,
            redeemedBT,
            interestRate
        );
    }









    function exitTempusAMM(
        ITempusAMM tempusAMM,
        uint256 lpTokensAmount,
        uint256 principalAmountOutMin,
        uint256 yieldAmountOutMin,
        bool toInternalBalances
    ) external {
        tempusAMM.transferFrom(msg.sender, address(this), lpTokensAmount);

        doExitTempusAMMGivenLP(
            tempusAMM,
            address(this),
            msg.sender,
            lpTokensAmount,
            getAMMOrderedAmounts(tempusAMM.tempusPool(), principalAmountOutMin, yieldAmountOutMin),
            toInternalBalances
        );

        assert(tempusAMM.balanceOf(address(this)) == 0);
    }















    function exitTempusAMMAndRedeem(
        ITempusAMM tempusAMM,
        uint256 sharesAmount,
        bool toBackingToken
    ) external {
        ITempusPool tempusPool = tempusAMM.tempusPool();
        require(!tempusPool.matured(), "Pool already finalized");
        uint256 userPrincipalBalance = IERC20(address(tempusPool.principalShare())).balanceOf(msg.sender);
        uint256 userYieldBalance = IERC20(address(tempusPool.yieldShare())).balanceOf(msg.sender);

        uint256 ammExitAmountPrincipal = sharesAmount - userPrincipalBalance;
        uint256 ammExitAmountYield = sharesAmount - userYieldBalance;


        uint256 userBalanceLP = tempusAMM.balanceOf(msg.sender);
        tempusAMM.transferFrom(msg.sender, address(this), userBalanceLP);

        doExitTempusAMMGivenAmountsOut(
            tempusAMM,
            address(this),
            msg.sender,
            getAMMOrderedAmounts(tempusPool, ammExitAmountPrincipal, ammExitAmountYield),
            userBalanceLP,
            false
        );


        tempusAMM.transferFrom(address(this), msg.sender, tempusAMM.balanceOf(address(this)));

        if (toBackingToken) {
            redeemToBacking(tempusPool, msg.sender, sharesAmount, sharesAmount, msg.sender);
        } else {
            redeemToYieldBearing(tempusPool, msg.sender, sharesAmount, sharesAmount, msg.sender);
        }
    }








    function completeExitAndRedeem(ITempusAMM tempusAMM, bool toBackingToken) external {
        ITempusPool tempusPool = tempusAMM.tempusPool();
        require(tempusPool.matured(), "Not supported before maturity");

        IERC20 principalShare = IERC20(address(tempusPool.principalShare()));
        IERC20 yieldShare = IERC20(address(tempusPool.yieldShare()));

        uint256 userPrincipalBalance = principalShare.balanceOf(msg.sender);
        uint256 userYieldBalance = yieldShare.balanceOf(msg.sender);
        principalShare.safeTransferFrom(msg.sender, address(this), userPrincipalBalance);
        yieldShare.safeTransferFrom(msg.sender, address(this), userYieldBalance);

        uint256 userBalanceLP = tempusAMM.balanceOf(msg.sender);

        if (userBalanceLP > 0) {

            tempusAMM.transferFrom(msg.sender, address(this), userBalanceLP);

            uint256[] memory minAmountsOut = new uint256[](2);


            doExitTempusAMMGivenLP(tempusAMM, address(this), address(this), userBalanceLP, minAmountsOut, false);
        }

        if (toBackingToken) {
            redeemToBacking(
                tempusPool,
                address(this),
                principalShare.balanceOf(address(this)),
                yieldShare.balanceOf(address(this)),
                msg.sender
            );
        } else {
            redeemToYieldBearing(
                tempusPool,
                address(this),
                principalShare.balanceOf(address(this)),
                yieldShare.balanceOf(address(this)),
                msg.sender
            );
        }
    }

    function doExitTempusAMMGivenLP(
        ITempusAMM tempusAMM,
        address sender,
        address recipient,
        uint256 lpTokensAmount,
        uint256[] memory minAmountsOut,
        bool toInternalBalances
    ) private {
        require(lpTokensAmount > 0, "LP token amount is 0");

        (IVault vault, bytes32 poolId, IERC20[] memory ammTokens, ) = getAMMDetailsAndEnsureInitialized(tempusAMM);

        IVault.ExitPoolRequest memory request = IVault.ExitPoolRequest({
            assets: ammTokens,
            minAmountsOut: minAmountsOut,
            userData: abi.encode(uint8(ITempusAMM.ExitKind.EXACT_BPT_IN_FOR_TOKENS_OUT), lpTokensAmount),
            toInternalBalance: toInternalBalances
        });
        vault.exitPool(poolId, sender, payable(recipient), request);
    }

    function doExitTempusAMMGivenAmountsOut(
        ITempusAMM tempusAMM,
        address sender,
        address recipient,
        uint256[] memory amountsOut,
        uint256 lpTokensAmountInMax,
        bool toInternalBalances
    ) private {
        (IVault vault, bytes32 poolId, IERC20[] memory ammTokens, ) = getAMMDetailsAndEnsureInitialized(tempusAMM);

        IVault.ExitPoolRequest memory request = IVault.ExitPoolRequest({
            assets: ammTokens,
            minAmountsOut: amountsOut,
            userData: abi.encode(
                uint8(ITempusAMM.ExitKind.BPT_IN_FOR_EXACT_TOKENS_OUT),
                amountsOut,
                lpTokensAmountInMax
            ),
            toInternalBalance: toInternalBalances
        });
        vault.exitPool(poolId, sender, payable(recipient), request);
    }

    function getAMMDetailsAndEnsureInitialized(ITempusAMM tempusAMM)
        private
        view
        returns (
            IVault vault,
            bytes32 poolId,
            IERC20[] memory ammTokens,
            uint256[] memory ammBalances
        )
    {
        vault = tempusAMM.getVault();
        poolId = tempusAMM.getPoolId();
        (ammTokens, ammBalances, ) = vault.getPoolTokens(poolId);
        require(
            ammTokens.length == 2 && ammBalances.length == 2 && ammBalances[0] > 0 && ammBalances[1] > 0,
            "AMM not initialized"
        );
    }

    function getAMMBalancesRatio(uint256[] memory ammBalances) private pure returns (uint256[2] memory balancesRatio) {
        uint256 rate = ammBalances[0].divf18(ammBalances[1]);

        (balancesRatio[0], balancesRatio[1]) = rate > Fixed256x18.ONE
            ? (Fixed256x18.ONE, Fixed256x18.ONE.divf18(rate))
            : (rate, Fixed256x18.ONE);
    }

    function getAMMOrderedAmounts(
        ITempusPool tempusPool,
        uint256 principalAmount,
        uint256 yieldAmount
    ) private view returns (uint256[] memory) {
        uint256[] memory amounts = new uint256[](2);
        (amounts[0], amounts[1]) = (tempusPool.principalShare() < tempusPool.yieldShare())
            ? (principalAmount, yieldAmount)
            : (yieldAmount, principalAmount);
        return amounts;
    }
}

