            from, from, recipient, amount, "", ""
        );

        _callTokensReceived(
            from, from, recipient, amount, "", "", false
        );

        return true;
    }


    function burn(uint256 amount, bytes calldata data) external {
        _burn(
            msg.sender, msg.sender, amount, data, ""
        );
    }


    function authorizeOperator(address operator) external {
        require(msg.sender != operator, "ERC777: authorizing self as operator");

        if (_defaultOperators[operator]) {
            delete _revokedDefaultOperators[msg.sender][operator];
        } else {
            _operators[msg.sender][operator] = true;
        }

        emit AuthorizedOperator(operator, msg.sender);
    }


    function revokeOperator(address operator) external {
        require(operator != msg.sender, "ERC777: revoking self as operator");

        if (_defaultOperators[operator]) {
            _revokedDefaultOperators[msg.sender][operator] = true;
        } else {
            delete _operators[msg.sender][operator];
        }

        emit RevokedOperator(operator, msg.sender);
    }


    function operatorSend(
        address sender,
        address recipient,
        uint256 amount,
        bytes calldata data,
        bytes calldata operatorData
    )
    external
    {
        require(isOperatorFor(msg.sender, sender), "ERC777: caller is not an operator for holder");
        _send(
            msg.sender, sender, recipient, amount, data, operatorData, true
        );
    }


    function operatorBurn(
        address account, uint256 amount, bytes calldata data, bytes calldata operatorData
    ) external
    {
        require(isOperatorFor(msg.sender, account), "ERC777: caller is not an operator for holder");
        _burn(
            msg.sender, account, amount, data, operatorData
        );
    }


    function approve(address spender, uint256 value) external returns (bool) {
        address holder = msg.sender;
        _approve(holder, spender, value);
        return true;
    }


    function transferFrom(address holder, address recipient, uint256 amount) external returns (bool) {
        require(recipient != address(0), "ERC777: transfer to the zero address");
        require(holder != address(0), "ERC777: transfer from the zero address");

        address spender = msg.sender;

        _callTokensToSend(
            spender, holder, recipient, amount, "", ""
        );

        _move(
            spender, holder, recipient, amount, "", ""
        );
        _approve(holder, spender, _allowances[holder][spender].sub(amount));

        _callTokensReceived(
            spender, holder, recipient, amount, "", "", false
        );

        return true;
    }


    function name() public view returns (string memory) {
        return _name;
    }


    function symbol() public view returns (string memory) {
        return _symbol;
    }


    function decimals() public pure returns (uint8) {
        return 18;
    }


    function granularity() public view returns (uint256) {
        return 1;
    }


    function totalSupply() public view returns (uint256) {
        return _totalSupply;
    }


    function balanceOf(address tokenHolder) public view returns (uint256) {
        return _balances[tokenHolder];
    }


    function isOperatorFor(
        address operator,
        address tokenHolder
    ) public view returns (bool)
    {
        return operator == tokenHolder ||
            (_defaultOperators[operator] && !_revokedDefaultOperators[tokenHolder][operator]) ||
            _operators[tokenHolder][operator];
    }


    function defaultOperators() public view returns (address[] memory) {
        return _defaultOperatorsArray;
    }


    function allowance(address holder, address spender) public view returns (uint256) {
        return _allowances[holder][spender];
    }


    function _mint(
        address operator,
        address account,
        uint256 amount,
        bytes memory userData,
        bytes memory operatorData
    )
    internal
    {
        require(account != address(0), "ERC777: mint to the zero address");


        _totalSupply = _totalSupply.add(amount);
        _balances[account] = _balances[account].add(amount);

        _callTokensReceived(
            operator, address(0), account, amount, userData, operatorData, true
        );

        emit Minted(
            operator, account, amount, userData, operatorData
        );
        emit Transfer(address(0), account, amount);
    }


    function _getLockedOf(address wallet) internal returns (uint);



    function _send(
        address operator,
        address from,
        address to,
        uint256 amount,
        bytes memory userData,
        bytes memory operatorData,
        bool requireReceptionAck
    )
        private
    {
        require(from != address(0), "ERC777: send from the zero address");
        require(to != address(0), "ERC777: send to the zero address");

        _callTokensToSend(
            operator, from, to, amount, userData, operatorData
        );

        _move(
            operator, from, to, amount, userData, operatorData
        );

        _callTokensReceived(
            operator, from, to, amount, userData, operatorData, requireReceptionAck
        );
    }



    function _burn(
        address operator,
        address from,
        uint256 amount,
        bytes memory data,
        bytes memory operatorData
    )
        private
    {
        require(from != address(0), "ERC777: burn from the zero address");

        _callTokensToSend(
            operator, from, address(0), amount, data, operatorData
        );


        _totalSupply = _totalSupply.sub(amount);
        _balances[from] = _balances[from].sub(amount);

        emit Burned(
            operator, from, amount, data, operatorData
        );
        emit Transfer(from, address(0), amount);
    }

    function _move(
        address operator,
        address from,
        address to,
        uint256 amount,
        bytes memory userData,
        bytes memory operatorData
    )
        private
    {

        uint locked = _getLockedOf(from);
        if (locked > 0) {
            require(_balances[from] >= locked + amount, "Token should be unlocked for transferring");
        }

        _balances[from] = _balances[from].sub(amount);
        _balances[to] = _balances[to].add(amount);

        emit Sent(
            operator, from, to, amount, userData, operatorData
        );
        emit Transfer(from, to, amount);
    }

    function _approve(address holder, address spender, uint256 value) private {



        require(spender != address(0), "ERC777: approve to the zero address");

        _allowances[holder][spender] = value;
        emit Approval(holder, spender, value);
    }


    function _callTokensToSend(
        address operator,
        address from,
        address to,
        uint256 amount,
        bytes memory userData,
        bytes memory operatorData
    )
        private
    {
        address implementer = _erc1820.getInterfaceImplementer(from, TOKENS_SENDER_INTERFACE_HASH);
        if (implementer != address(0)) {
            IERC777Sender(implementer).tokensToSend(
                operator, from, to, amount, userData, operatorData
            );
        }
    }


    function _callTokensReceived(
        address operator,
        address from,
        address to,
        uint256 amount,
        bytes memory userData,
        bytes memory operatorData,
        bool requireReceptionAck
    )
        private
    {
        address implementer = _erc1820.getInterfaceImplementer(to, TOKENS_RECIPIENT_INTERFACE_HASH);
        if (implementer != address(0)) {
            IERC777Recipient(implementer).tokensReceived(
                operator, from, to, amount, userData, operatorData
            );
        } else if (requireReceptionAck) {
            require(!to.isContract(), "Token recipient contract has no implementer for ERC777TokensRecipient");
        }
    }
}

pragma solidity ^0.5.16;
pragma experimental ABIEncoderV2;

import "../utils/Ownable.sol";
import "../interfaces/ISWSupplyManager.sol";
import "multi-token-standard/contracts/interfaces/IERC1155.sol";
import "multi-token-standard/contracts/utils/SafeMath.sol";


contract EternalHeroesFactory is Ownable {
  using SafeMath for uint256;






  uint256 constant internal decimals = 2; 


  ISWSupplyManager internal factoryManager;  
  IERC1155 internal arcadeumCoin;            
  uint256 internal arcadeumCoinID;           


  struct Order {
    address recipient;             
    uint256[] tokensBoughtIDs;     
    uint256[] tokensBoughtAmounts; 
    uint256[] expectedTiers;       
  }


  mapping(uint256 => bool) internal isPurchasable;  


  uint256 internal floorPrice;     
  uint256 internal tierSize;       
  uint256 internal priceIncrement; 



  event AssetsPurchased(address indexed recipient, uint256[] tokensBoughtIds, uint256[] tokensBoughtAmounts, uint256 totalCost);
  event IDsRegistration(uint256[] ids);
  event IDsDeregistration(uint256[] ids);




  constructor(
    address _factoryManagerAddr,
    address _arcadeumCoinAddr,
    uint256 _arcadeumCoinID,
    uint256 _floorPrice,
    uint256 _tierSize,
    uint256 _priceIncrement
  ) public {


    require(
      _factoryManagerAddr != address(0) &&
      _arcadeumCoinAddr != address(0) &&
      _floorPrice > 100000000 && 
      _tierSize > 0 &&
      _priceIncrement > 0,
      "EternalHeroesFactory#constructor: INVALID_INPUT"
    );


    factoryManager = ISWSupplyManager(_factoryManagerAddr);
    arcadeumCoin = IERC1155(_arcadeumCoinAddr);
    arcadeumCoinID = _arcadeumCoinID;
    floorPrice = _floorPrice;
    tierSize = _tierSize;
    priceIncrement = _priceIncrement;
  }




  function registerIDs(uint256[] calldata _ids) external onlyOwner() {
    uint256[] memory maxSupplies = factoryManager.getMaxSupplies(_ids);
    for (uint256 i = 0; i < _ids.length; i++) {
      require(maxSupplies[i] > 0, "EternalHeroesFactory#registerIDs: UNCAPPED_SUPPLY");
      isPurchasable[_ids[i]] = true;
    }
    emit IDsRegistration(_ids);
  }


  function deregisterIDs(uint256[] calldata _ids) external onlyOwner() {
    for (uint256 i = 0; i < _ids.length; i++) {
      isPurchasable[_ids[i]] = false;
    }
    emit IDsDeregistration(_ids);
  }


  function withdraw(address _recipient) external onlyOwner() {
    require(_recipient != address(0x0), "EternalHeroesFactory#withdraw: INVALID_RECIPIENT");
    uint256 thisBalance = arcadeumCoin.balanceOf(address(this), arcadeumCoinID);
    arcadeumCoin.safeTransferFrom(address(this), _recipient, arcadeumCoinID, thisBalance, "");
  }





  bytes4 constant internal ERC1155_RECEIVED_VALUE = 0xf23a6e61;
  bytes4 constant internal ERC1155_BATCH_RECEIVED_VALUE = 0xbc197c81;


  function () external {
    revert("UNSUPPORTED_METHOD");
  }


  function onERC1155Received(address, address _from, uint256 _id, uint256 _amount, bytes memory _data)
    public returns(bytes4)
  {

    require(msg.sender == address(arcadeumCoin), "EternalHeroesFactory#onERC1155Received: INVALID_ARC_ADDRESS");
    require(_id == arcadeumCoinID, "EternalHeroesFactory#onERC1155Received: INVALID_ARC_ID");


    Order memory order = abi.decode(_data, (Order));
    address recipient = order.recipient == address(0x0) ? _from : order.recipient;
    _buy(order.tokensBoughtIDs, order.tokensBoughtAmounts, order.expectedTiers, _amount, recipient);

    return ERC1155_RECEIVED_VALUE;
  }


  function onERC1155BatchReceived(
    address _operator,
    address _from,
    uint256[] memory _ids,
    uint256[] memory _amounts,
    bytes memory _data)
    public returns(bytes4)
  {
    require(_ids.length == 1, "EternalHeroesFactory#onERC1155BatchReceived: INVALID_BATCH_TRANSFER");
    require(
      ERC1155_RECEIVED_VALUE == onERC1155Received(_operator, _from, _ids[0], _amounts[0], _data),
      "EternalHeroesFactory#onERC1155BatchReceived: INVALID_ONRECEIVED_MESSAGE"
    );

    return ERC1155_BATCH_RECEIVED_VALUE;
  }





  function _buy(
    uint256[] memory _ids,
    uint256[] memory _amounts,
    uint256[] memory _expectedTiers,
    uint256 _arcAmount,
    address _recipient)
    internal
  {

    uint256 nTokens = _ids.length;
    uint256 tier_size = tierSize;


    uint256[] memory current_supplies = factoryManager.getCurrentSupplies(_ids);


    uint256 total_cost = 0;




    uint256[] memory amounts_to_mint = new uint256[](nTokens);


    for (uint256 i = 0; i < nTokens; i++) {
      uint256 id = _ids[i];
      uint256 supply = current_supplies[i];
      uint256 to_mint = 0;
      uint256 amount = _amounts[i];


      require(isPurchasable[id], "EternalHeroesFactory#_buy: ID_NOT_PURCHASABLE");



      if (i > 0) {
        require(_ids[i-1] < id, "EternalHeroesFactory#_buy: UNSORTED_OR_DUPLICATE_TOKEN_IDS");
      }


      uint256 current_tier = supply.div(tier_size);


      if (_expectedTiers[i] != current_tier) {
        amounts_to_mint[i] = 0; 
        continue;
      }


      uint256 current_price = floorPrice.add(current_tier.mul(priceIncrement));


      uint256 amount_left = tier_size.sub(supply.mod(tier_size));


      to_mint = amount < amount_left ? amount : amount_left;


      total_cost = total_cost.add(to_mint.mul(current_price));
      amounts_to_mint[i] = to_mint;
    }




    uint256 refundAmount = _arcAmount.sub(total_cost);
    if (refundAmount > 0) {
      arcadeumCoin.safeTransferFrom(address(this), _recipient, arcadeumCoinID, refundAmount, "");
    }


    factoryManager.batchMint(_recipient, _ids, amounts_to_mint, "");


    emit AssetsPurchased(_recipient, _ids, amounts_to_mint, total_cost);
  }





  function getPurchasableStatus(uint256[] calldata _ids) external view returns (bool[] memory) {
    uint256 nIds = _ids.length;
    bool[] memory purchasableStatus = new bool[](nIds);


    for (uint256 i = 0; i < nIds; i++) {
      purchasableStatus[i] = isPurchasable[_ids[i]];
    }

    return purchasableStatus;
  }


  function getFactoryManager() external view returns (address) {
    return address(factoryManager);
  }


  function getArcadeumCoin() external view returns (address) {
    return address(arcadeumCoin);
  }


  function getArcadeumCoinID() external view returns (uint256) {
    return arcadeumCoinID;
  }


  function getPrices(uint256[] calldata _ids) external view returns (uint256[] memory) {
    uint256[] memory current_prices = new uint256[](_ids.length);
    uint256[] memory current_supplies = factoryManager.getCurrentSupplies(_ids);
    for (uint256 i = 0;  i < _ids.length; i++) {
      uint256 current_tier = current_supplies[i].div(tierSize);
      current_prices[i] = floorPrice.add(current_tier.mul(priceIncrement));
    }
    return current_prices;
  }


  function getPriceTiers(uint256[] calldata _ids) external view returns (uint256[] memory) {
    uint256[] memory current_tiers = new uint256[](_ids.length);
    uint256[] memory current_supplies = factoryManager.getCurrentSupplies(_ids);
    for (uint256 i = 0;  i < _ids.length; i++) {
      current_tiers[i] = current_supplies[i].div(tierSize);
    }
    return current_tiers;
  }


  function getSuppliesCurrentTier(uint256[] calldata _ids) external view returns (uint256[] memory tiers, uint256[] memory supplies) {
    tiers = new uint256[](_ids.length);
    supplies = new uint256[](_ids.length);


    uint256[] memory current_supplies = factoryManager.getCurrentSupplies(_ids);
    uint256 tier_size = tierSize;


    for (uint256 i = 0;  i < _ids.length; i++) {
      tiers[i] = current_supplies[i].div(tier_size);
      supplies[i] = tier_size.sub(current_supplies[i].mod(tier_size));
    }
    return (tiers, supplies);
  }


  function getFloorPrice() external view returns (uint256) {
    return floorPrice;
  }


  function getTierSize() external view returns (uint256) {
    return tierSize;
  }


  function getPriceIncrement() external view returns (uint256) {
    return priceIncrement;
  }





  function supportsInterface(bytes4 interfaceID) external view returns (bool) {
    return  interfaceID == 0x01ffc9a7 || 
      interfaceID == 0x4e2312e0;         
  }

}

pragma solidity 0.6.12;
import "../../../converter/types/liquid-token/LiquidTokenConverter.sol";


contract DynamicLiquidTokenConverter is LiquidTokenConverter {
    uint32 public minimumWeight = 30000;
    uint32 public stepWeight = 10000;
    uint256 public marketCapThreshold = 10000 ether;
    uint256 public lastWeightAdjustmentMarketCap = 0;

    event ReserveTokenWeightUpdate(uint32 _prevWeight, uint32 _newWeight, uint256 _percentage, uint256 _balance);
    event StepWeightUpdated(uint32 stepWeight);
    event MinimumWeightUpdated(uint32 minumumWeight);
    event MarketCapThresholdUpdated(uint256 marketCapThreshold);
    event LastWeightAdjustmentMarketCapUpdated(uint256 lastWeightAdjustmentMarketCap);


    constructor(
        IDSToken _token,
        IContractRegistry _registry,
        uint32 _maxConversionFee
    )
        LiquidTokenConverter(_token, _registry, _maxConversionFee)
        public
    {
    }


    function converterType() public pure override returns (uint16) {
        return 3;
    }


    function setMarketCapThreshold(uint256 _marketCapThreshold)
        public
        ownerOnly
        inactive
    {
        marketCapThreshold = _marketCapThreshold;
        emit MarketCapThresholdUpdated(_marketCapThreshold);
    }


    function setMinimumWeight(uint32 _minimumWeight)
        public
        ownerOnly
        inactive
    {


        minimumWeight = _minimumWeight;
        emit MinimumWeightUpdated(_minimumWeight);
    }


    function setStepWeight(uint32 _stepWeight)
        public
        ownerOnly
        inactive
    {


        stepWeight = _stepWeight;
        emit StepWeightUpdated(_stepWeight);
    }

    function setLastWeightAdjustmentMarketCap(uint256 _lastWeightAdjustmentMarketCap)
        public
        ownerOnly
        inactive
    {
        lastWeightAdjustmentMarketCap = _lastWeightAdjustmentMarketCap;
        emit LastWeightAdjustmentMarketCapUpdated(_lastWeightAdjustmentMarketCap);
    }




    function reduceWeight(IERC20Token _reserveToken)
        public
        validReserve(_reserveToken)
        ownerOnly
    {
        _protected();
        uint256 currentMarketCap = getMarketCap(_reserveToken);
        require(currentMarketCap > (lastWeightAdjustmentMarketCap.add(marketCapThreshold)), "ERR_MARKET_CAP_BELOW_THRESHOLD");

        Reserve storage reserve = reserves[_reserveToken];
        uint256 newWeight = uint256(reserve.weight).sub(stepWeight);
        uint32 oldWeight = reserve.weight;
        require(newWeight >= minimumWeight, "ERR_INVALID_RESERVE_WEIGHT");

        uint256 percentage = uint256(PPM_RESOLUTION).sub(newWeight.mul(PPM_RESOLUTION).div(reserve.weight));

        uint32 weight = uint32(newWeight);
        reserve.weight = weight;
        reserveRatio = weight;

        uint256 balance = reserveBalance(_reserveToken).mul(percentage).div(PPM_RESOLUTION);

        lastWeightAdjustmentMarketCap = currentMarketCap;

        if (_reserveToken == ETH_RESERVE_ADDRESS)
          msg.sender.transfer(balance);
        else
          safeTransfer(_reserveToken, msg.sender, balance);

        syncReserveBalance(_reserveToken);

        emit ReserveTokenWeightUpdate(oldWeight, weight, percentage, reserve.balance);
    }

    function getMarketCap(IERC20Token _reserveToken)
        public
        view
        returns(uint256)
    {
        Reserve storage reserve = reserves[_reserveToken];
        return reserveBalance(_reserveToken).mul(1e6).div(reserve.weight);
    }
}

pragma solidity ^0.8.4;





import "@openzeppelin/contracts/token/ERC1155/presets/ERC1155PresetMinterPauser.sol";
import "@openzeppelin/contracts/token/ERC20/presets/ERC20PresetMinterPauser.sol";
import "hardhat/console.sol";

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";

contract IDO is Ownable {
    IERC20 public GZT;

    bool public idoStatus;

    uint256 public idoStart;
    uint256 public idoFinish;

    uint256 public cooldownToClaim;
    uint256 public allowedAmountToClaim;

    address[] public _allowedTokens;

    struct WhitelistInstance {
        uint256 maxAmountToClaim;
        bool isWhitelisted;
    }

    struct IDOParticipant {
        uint256 start;
        uint256 amountToClaim;
        uint256 claimedLastTime;
        uint256 claimedAmount;
        bool hasClaimed;
    }

    mapping(address => WhitelistInstance) public whitelist;
    mapping(address => IDOParticipant) public pool;

    mapping(IERC20 => bool) public allowedTokens;
    mapping(IERC20 => uint256[2]) public rates; 

    event UserIsWhitelisted(address indexed user, uint256 indexed amount);
    event NewIDOParticipant(IERC20 indexed token, address indexed user, uint256 amount);

    constructor(IERC20 _IDO_TOKEN) {
        GZT = _IDO_TOKEN;
    }

    function participate(uint256 amountToSpent, IERC20 token) external {
        uint256[2] memory rate = rates[token];
        uint256 amountToClaim = ((amountToSpent * rate[0]) / rate[1]);

        require(idoStatus, "The IDO is not started!");
        require(block.timestamp < idoFinish, "The IDO is already finished!");
        require(pool[msg.sender].start == 0, "You're already participating in IDO");
        require(token.balanceOf(msg.sender) >= amountToSpent, "You don't have enough money!");
        require(whitelist[msg.sender].maxAmountToClaim >= amountToClaim, "You're not permited to claim this amount!");
        require(whitelist[msg.sender].isWhitelisted, "You're not whitelisted");

        require(allowedTokens[token], "This token is not allowed to participate");

        token.transferFrom(msg.sender, address(this), amountToSpent);

        pool[msg.sender] = IDOParticipant({
            start: block.timestamp,
            amountToClaim: amountToClaim,
            claimedLastTime: 0,
            claimedAmount: 0,
            hasClaimed: false
        });

        emit NewIDOParticipant(token, msg.sender, amountToSpent);
    }



    function claim() external {
        require(block.timestamp > idoFinish, "The IDO is not finished yet");
        require(pool[msg.sender].start != 0, "You're not participating in IDO");
        require(
            (block.timestamp - pool[msg.sender].claimedLastTime) > cooldownToClaim,
            "You are not allowed to claime more at this time"
        );
        require(!pool[msg.sender].hasClaimed, "You already claimed");

        if (
            (pool[msg.sender].claimedAmount < pool[msg.sender].amountToClaim) &&
            ((pool[msg.sender].amountToClaim - pool[msg.sender].claimedAmount) >= allowedAmountToClaim)
        ) {

            GZT.transfer(msg.sender, allowedAmountToClaim);
            pool[msg.sender].claimedLastTime = block.timestamp;
        } else if (
            (pool[msg.sender].claimedAmount < pool[msg.sender].amountToClaim) &&
            ((pool[msg.sender].amountToClaim - pool[msg.sender].claimedAmount) < allowedAmountToClaim)
        ) {
            GZT.transfer(msg.sender, (pool[msg.sender].amountToClaim - pool[msg.sender].claimedAmount));
            pool[msg.sender].claimedLastTime = block.timestamp;
            pool[msg.sender].hasClaimed = true;
        }
    }

    function addUsersToWhitelist(address[] memory users, uint256[] memory amounts) external onlyOwner {
        require(users.length == amounts.length, "invalid array lengths");
        for (uint256 i = 0; i < amounts.length; i++) {
            whitelist[users[i]] = WhitelistInstance({maxAmountToClaim: amounts[i], isWhitelisted: true});
            emit UserIsWhitelisted(users[i], amounts[i]);
        }
    }

    function allowToken(
        IERC20 token,
        uint256 rateNumerator,
        uint256 rateDenominator
    ) external onlyOwner {
        allowedTokens[token] = true;
        rates[token] = [rateNumerator, rateDenominator];
        _allowedTokens.push(address(token));
    }

    function disallowTokens(IERC20 token) external onlyOwner {
        allowedTokens[token] = false;
    }

    function setIDO(
        uint256 start,
        uint256 finish,
        uint256 cooldown,
        uint256 _allowedAmountToClaim
    ) external onlyOwner {
        idoStatus = true;
        idoStart = start;
        idoFinish = finish;

        cooldownToClaim = cooldown;
        allowedAmountToClaim = _allowedAmountToClaim;
    }


    function claimTheInvestments(IERC20 token, uint256 amount) external onlyOwner {
        require(block.timestamp > idoFinish, "The IDO is not finished yet");


        token.transfer(msg.sender, amount);
    }

    function infoBundler(address user)
        external
        view
        onlyOwner
        returns (
            WhitelistInstance memory whitelistInstance,
            IDOParticipant memory icoParticipantInstance,
            uint256[] memory _balancesOfAUser
        )
    {
        uint256[] memory balancesOfAUser;
        for (uint256 i = 0; i < _allowedTokens.length; i++) {
            IERC20 token = IERC20(_allowedTokens[i]);
            balancesOfAUser[i] = token.balanceOf(user);
        }

        return (whitelist[user], pool[user], balancesOfAUser);
    }
}

pragma solidity 0.8.9;

import "@openzeppelin/contracts-upgradeable/token/ERC20/IERC20Upgradeable.sol";
import "@openzeppelin/contracts-upgradeable/token/ERC20/ERC20Upgradeable.sol";
import "@openzeppelin/contracts-upgradeable/token/ERC20/utils/SafeERC20Upgradeable.sol";
import "@openzeppelin/contracts-upgradeable/security/ReentrancyGuardUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/security/PausableUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/access/OwnableUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/UUPSUpgradeable.sol";

interface IRouter {
    function swapExactTokensForTokens(
        uint amountIn,
        uint amountOutMin,
        address[] calldata path,
        address to,
        uint deadline
    ) external returns (uint[] memory amounts);

    function getAmountsOut(uint amountIn, address[] memory path) external view returns (uint[] memory amounts);
}

interface IPool {
    function add_liquidity(uint[3] memory amounts, uint _min_mint_amount) external returns (uint);

    function add_liquidity(
        uint[3] memory amounts, uint _min_mint_amount, bool _use_underlying
    ) external returns (uint);

    function remove_liquidity_one_coin(uint _token_amount, int128 i, uint _min_amount) external returns (uint);

    function remove_liquidity_one_coin(
        uint _token_amount, int128 i, uint _min_amount, bool _use_underlying
    ) external returns (uint);

    function lp_token() external view returns (address);
    function get_virtual_price() external view returns (uint);
    function balances(uint i) external view returns (uint);
    function price_oracle(uint i) external view returns (uint);
}

interface IGauge {
    function deposit(uint amount) external;
    function withdraw(uint amount) external;
    function claim_rewards() external;
    function claimable_reward_write(address _addr, address _token) external returns (uint);
    function balanceOf(address account) external view returns (uint);
}

interface ILendingPool {
    function deposit(address asset, uint amount, address onBehalfOf, uint16 referralCode) external;
    function withdraw(address asset, uint amount, address to) external;
    function getReserveData(address asset) external view returns (
        uint, uint128, uint128, uint128, uint128, uint128, uint40, address
    );
}

interface IIncentivesController {
    function getRewardsBalance(address[] calldata assets, address user) external view returns (uint);
    function claimRewards(address[] calldata assets, uint amount, address to) external returns (uint);
}

interface IWAVAX is IERC20Upgradeable {
    function withdraw(uint amount) external;
}

contract PowerBombAvaxCurve is Initializable, UUPSUpgradeable, OwnableUpgradeable, ReentrancyGuardUpgradeable, PausableUpgradeable {
    using SafeERC20Upgradeable for IERC20Upgradeable;
    using SafeERC20Upgradeable for IWAVAX;

    IERC20Upgradeable constant USDT = IERC20Upgradeable(0xc7198437980c041c805A1EDcbA50c1Ce5db95118);
    IERC20Upgradeable constant USDC = IERC20Upgradeable(0xA7D7079b0FEaD91F3e65f86E8915Cb59c1a4C664);
    IERC20Upgradeable constant DAI = IERC20Upgradeable(0xd586E7F844cEa2F87f50152665BCbc2C279D8d70);
    IWAVAX constant WAVAX = IWAVAX(0xB31f66AA3C1e785363F0875A1B74E27b85FD66c7);
    IERC20Upgradeable constant CRV = IERC20Upgradeable(0x47536F17F4fF30e64A96a7555826b8f9e66ec468);
    IERC20Upgradeable public lpToken;
    IERC20Upgradeable public rewardToken;

    IRouter constant router = IRouter(0x60aE616a2155Ee3d9A68541Ba4544862310933d4); 
    IPool public pool;
    IGauge public gauge;

    address public treasury;
    address public proxy;
    address public bot;

    uint public yieldFeePerc;
    uint public slippagePerc;
    uint public tvlMaxLimit;

    uint public accRewardPerlpToken;
    mapping(address => uint) internal userAccReward;
    ILendingPool constant lendingPool = ILendingPool(0x4F01AeD16D97E3aB5ab2B501154DC9bb0F1A5A2C); 
    IERC20Upgradeable public ibRewardToken; 
    IIncentivesController constant incentivesController = IIncentivesController(0x01D83Fe6A10D2f2B7AF17034343746188272cAc9); 
    uint public ibRewardTokenBaseAmt;
    uint public lastIbRewardTokenAmt;

    struct User {
        uint lpTokenBalance;
        uint rewardStartAt;
    }
    mapping(address => User) public userInfo;
    mapping(address => uint) internal depositedBlock;

    event Deposit(address tokenDeposit, uint amountToken, uint amountlpToken);
    event Withdraw(address tokenWithdraw, uint amountToken);
    event Harvest(uint harvestedfarmToken, uint swappedRewardTokenAfterFee, uint fee);
    event ClaimReward(address receiver, uint claimedIbRewardTokenAfterFee, uint rewardToken);
    event SetTreasury(address oldTreasury, address newTreasury);
    event SetProxy(address oldProxy, address newProxy);
    event SetBot(address oldBot, address newBot);
    event SetYieldFeePerc(uint oldYieldFeePerc, uint newYieldFeePerc);
    event SetSlippagePerc(uint oldSlippagePerc, uint newSlippagePerc);
    event SetTVLMaxLimit(uint oldTVLMaxLimit, uint newTVLMaxLimit);

    function _authorizeUpgrade(address) internal override onlyOwner {}

    function deposit(IERC20Upgradeable token, uint amount, uint slippage) external virtual {
        _deposit(token, amount, msg.sender, slippage);
    }

    function depositByProxy(IERC20Upgradeable token, uint amount, address depositor, uint slippage) external virtual {
        require(msg.sender == proxy, "Only proxy");
        _deposit(token, amount, depositor, slippage);
    }

    function _deposit(IERC20Upgradeable token, uint amount, address depositor, uint slippage) internal virtual nonReentrant whenNotPaused {
        require(token == USDT || token == USDC || token == DAI || token == lpToken, "Invalid token");
        require(amount > 0, "Invalid amount");
        require(getAllPoolInUSD() < tvlMaxLimit, "TVL max Limit reach");

        uint currentPool = gauge.balanceOf(address(this));
        if (currentPool > 0) _harvest(true);

        token.safeTransferFrom(msg.sender, address(this), amount);
        depositedBlock[depositor] = block.number;

        uint lpTokenAmt;
        if (token != lpToken) {
            uint[3] memory amounts;
            if (token == USDT) amounts[2] = amount;
            else if (token == USDC) amounts[1] = amount;
            else if (token == DAI) amounts[0] = amount;

            if (token != DAI) amount *= 1e12;
            uint estimatedMintAmt = amount * 1e18 / pool.get_virtual_price();
            uint minMintAmt = estimatedMintAmt - (estimatedMintAmt * slippage / 10000);

            lpTokenAmt = pool.add_liquidity(amounts, minMintAmt, true);
        } else {
            lpTokenAmt = amount;
        }

        gauge.deposit(lpTokenAmt);
        User storage user = userInfo[depositor];
        user.lpTokenBalance += lpTokenAmt;
        user.rewardStartAt += (lpTokenAmt * accRewardPerlpToken / 1e36);

        emit Deposit(address(token), amount, lpTokenAmt);
    }

    function withdraw(IERC20Upgradeable token, uint amountOutLpToken, uint slippage) external virtual nonReentrant {
        require(token == USDT || token == USDC || token == DAI || token == lpToken, "Invalid token");
        User storage user = userInfo[msg.sender];
        require(amountOutLpToken > 0 && user.lpTokenBalance >= amountOutLpToken, "Invalid amountOutLpToken to withdraw");
        require(depositedBlock[msg.sender] != block.number, "Not allow withdraw within same block");

        claimReward(msg.sender);

        user.lpTokenBalance = user.lpTokenBalance - amountOutLpToken;
        user.rewardStartAt = user.lpTokenBalance * accRewardPerlpToken / 1e36;
        gauge.withdraw(amountOutLpToken);

        uint amountOutToken;
        if (token != lpToken) {
            int128 i;
            if (token == USDT) i = 2;
            else if (token == USDC) i = 1;
            else i = 0; 

            uint amount = amountOutLpToken * pool.get_virtual_price() / 1e18;
            if (token != DAI) amount /= 1e12;
            uint minAmount = amount - (amount * slippage / 10000);

            pool.remove_liquidity_one_coin(amountOutLpToken, i, minAmount, true);
            amountOutToken = token.balanceOf(address(this));
        } else {
            amountOutToken = amountOutLpToken;
        }
        token.safeTransfer(msg.sender, amountOutToken);

        emit Withdraw(address(token), amountOutToken);
    }

    function harvest() external nonReentrant {
        _harvest(false);
    }

    function _harvest(bool isDeposit) internal virtual {

        uint accruedAmt = ibRewardToken.balanceOf(address(this)) - lastIbRewardTokenAmt;
        uint currentPool = gauge.balanceOf(address(this));
        accRewardPerlpToken += (accruedAmt * 1e36 / currentPool);


        gauge.claim_rewards();

        uint WAVAXAmt = WAVAX.balanceOf(address(this));
        uint minSwapAmt = msg.sender == bot ? 50e16 : 25e16; 
        if (WAVAXAmt > minSwapAmt) {

            uint CRVAmt = CRV.balanceOf(address(this));
            if (CRVAmt > 1e18) WAVAXAmt += swap2(address(CRV), address(WAVAX), CRVAmt);


            if (msg.sender == bot || isDeposit) {
                uint amountRefund = msg.sender == bot ? 2e16 : 1e16; 
                WAVAXAmt -= amountRefund;
                WAVAX.withdraw(amountRefund);
                (bool success,) = tx.origin.call{value: address(this).balance}("");
                require(success, "AVAX transfer failed");
            }


            uint rewardTokenAmt = swap2(address(WAVAX), address(rewardToken), WAVAXAmt);


            uint fee = rewardTokenAmt * yieldFeePerc / 10000;
            rewardTokenAmt -= fee;
            ibRewardTokenBaseAmt += rewardTokenAmt; 


            address[] memory assets = new address[](1);
            assets[0] = address(ibRewardToken);
            uint unclaimedRewardsAmt = incentivesController.getRewardsBalance(assets, address(this)); 
            if (unclaimedRewardsAmt > 1e16) {
                uint _WAVAXAmt = incentivesController.claimRewards(assets, unclaimedRewardsAmt, address(this));


                uint _rewardTokenAmt = swap2(address(WAVAX), address(rewardToken), _WAVAXAmt);


                uint _fee = _rewardTokenAmt * yieldFeePerc / 10000;
                rewardTokenAmt += (_rewardTokenAmt - _fee);
                fee += _fee;
            }


            accRewardPerlpToken += (rewardTokenAmt * 1e36 / currentPool);


            rewardToken.safeTransfer(treasury, fee);


            lendingPool.deposit(address(rewardToken), rewardTokenAmt, address(this), 0);


            lastIbRewardTokenAmt = ibRewardToken.balanceOf(address(this));

            emit Harvest(WAVAXAmt, rewardTokenAmt, fee);
        }
    }

    receive() external payable {}

    function claimReward(address account) public virtual {
        _harvest(false);

        User storage user = userInfo[account];
        if (user.lpTokenBalance > 0) {

            uint ibRewardTokenAmt = (user.lpTokenBalance * accRewardPerlpToken / 1e36) - user.rewardStartAt;
            if (ibRewardTokenAmt > 0) {
                user.rewardStartAt += ibRewardTokenAmt;


                lendingPool.withdraw(address(rewardToken), ibRewardTokenAmt, address(this));


                lastIbRewardTokenAmt -= ibRewardTokenAmt;


                uint rewardTokenAmt = rewardToken.balanceOf(address(this));
                rewardToken.safeTransfer(account, rewardTokenAmt);
                userAccReward[account] += rewardTokenAmt;

                emit ClaimReward(account, ibRewardTokenAmt, rewardTokenAmt);
            }
        }
    }

    function swap2(address tokenIn, address tokenOut, uint amount) internal virtual returns (uint) {
        address[] memory path = getPath(tokenIn, tokenOut);
        return router.swapExactTokensForTokens(amount, 0, path, address(this), block.timestamp)[1];
    }

    function swap3(address tokenIn, address tokenOut, uint amount) internal virtual returns (uint) {
        address[] memory path = new address[](3);
        path[0] = tokenIn;
        path[1] = address(WAVAX);
        path[2] = tokenOut;
        return router.swapExactTokensForTokens(amount, 0, path, address(this), block.timestamp)[2];
    }

    function setTreasury(address _treasury) external virtual onlyOwner {
        address oldTreasury = treasury;
        treasury = _treasury;

        emit SetTreasury(oldTreasury, _treasury);
    }

    function setProxy(address _proxy) external virtual onlyOwner {
        address oldProxy = proxy;
        proxy = _proxy;

        emit SetProxy(oldProxy, _proxy);
    }

    function setBot(address _bot) external virtual onlyOwner {
        address oldBot = bot;
        bot = _bot;

        emit SetBot(oldBot, _bot);
    }

    function setYieldFeePerc(uint _yieldFeePerc) external virtual onlyOwner {
        require(_yieldFeePerc <= 2000, "Invalid yield fee percentage");
        uint oldYieldFeePerc = yieldFeePerc;
        yieldFeePerc = _yieldFeePerc;

        emit SetYieldFeePerc(oldYieldFeePerc, _yieldFeePerc);
    }

    function setSlippagePerc(uint _slippagePerc) external virtual onlyOwner {
        uint oldSlippagePerc = slippagePerc;
        slippagePerc = _slippagePerc;

        emit SetSlippagePerc(oldSlippagePerc, _slippagePerc);
    }


    function setTVLMaxLimit(uint _tvlMaxLimit) external virtual onlyOwner {
        uint oldTVLMaxLimit = tvlMaxLimit;
        tvlMaxLimit = _tvlMaxLimit;

        emit SetTVLMaxLimit(oldTVLMaxLimit, _tvlMaxLimit);
    }

    function pauseContract() external virtual onlyOwner {
        _pause();
    }

    function unpauseContract() external virtual onlyOwner {
        _unpause();
    }

    function getPath(address tokenIn, address tokenOut) internal pure returns (address[] memory path) {
        path = new address[](2);
        path[0] = tokenIn;
        path[1] = tokenOut;
    }

    function getImplementation() external view returns (address) {
        return _getImplementation();
    }

    function getAllPool() public virtual view returns (uint) {
        return gauge.balanceOf(address(this));
    }


    function getPricePerFullShareInUSD() public virtual view returns (uint) {
        return pool.get_virtual_price() / 1e12;
    }


    function getAllPoolInUSD() public virtual view returns (uint) {
        uint allPool = getAllPool();
        if (allPool == 0) return 0;
        return allPool * getPricePerFullShareInUSD() / 1e18;
    }

    function getPoolPendingReward(IERC20Upgradeable pendingRewardToken) external virtual returns (uint) {
        uint pendingRewardFromCurve = gauge.claimable_reward_write(address(this), address(pendingRewardToken));
        return pendingRewardFromCurve + pendingRewardToken.balanceOf(address(this));
    }


    function getUserPendingReward(address account) external virtual view returns (uint ibRewardTokenAmt) {
        User storage user = userInfo[account];
        ibRewardTokenAmt = (user.lpTokenBalance * accRewardPerlpToken / 1e36) - user.rewardStartAt;
    }


    function getUserBalance(address account) external virtual view returns (uint) {
        return userInfo[account].lpTokenBalance;
    }


    function getUserBalanceInUSD(address account) external virtual view returns (uint) {
        return userInfo[account].lpTokenBalance * getPricePerFullShareInUSD() / 1e18;
    }


    function getUserAccumulatedReward(address account) external virtual view returns (uint) {
        return userAccReward[account];
    }

    uint256[33] private __gap;
}

import "@openzeppelin/contracts/math/SafeMath.sol";
import "@openzeppelin/contracts/token/ERC20/SafeERC20.sol";
import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

pragma solidity 0.6.12;








contract MasterChef is Ownable {
    using SafeMath for uint256;
    using SafeERC20 for IERC20;


    struct UserInfo {
        uint256 amount; 
        uint256 rewardDebt; 
        uint256 unstakeTime; 











    }


    struct PoolInfo {
        IERC20 lpToken; 
        uint256 allocPoint; 
        uint256 lastRewardBlock; 
        uint256 accRewardTokenPerShare; 
    }


    IERC20 public rewardToken;



    uint256 public bonusEndBlock;

    uint256 public rewardTokenPerBlock;

    uint256 public constant BONUS_MULTIPLIER = 10;


    PoolInfo[] public poolInfo;

    mapping(uint256 => mapping(address => UserInfo)) public userInfo;

    uint256 public totalAllocPoint = 0;


    uint256 public startRewardBlock;


    uint256 public endRewardBlock;


    uint256 public unstakeFrozenTime = 72 hours;

    event Deposit(address indexed user, uint256 indexed pid, uint256 amount);
    event Withdraw(address indexed user, uint256 indexed pid, uint256 amount);
    event EmergencyWithdraw(
        address indexed user,
        uint256 indexed pid,
        uint256 amount
    );

    constructor(
        IERC20 _rewardToken,

        uint256 _rewardTokenPerBlock,
        uint256 _startRewardBlock,
        uint256 _endRewardBlock,
        uint256 _bonusEndBlock
    ) public {
        rewardToken = _rewardToken;
        rewardTokenPerBlock = _rewardTokenPerBlock;
        startRewardBlock = _startRewardBlock;
        endRewardBlock = _endRewardBlock;
        bonusEndBlock = _bonusEndBlock;
    }

    function setAll(
        IERC20 _rewardToken,
        uint256 _rewardTokenPerBlock,
        uint256 _startRewardBlock,
        uint256 _endRewardBlock,
        uint256 _bonusEndBlock,
        uint256 _unstakeFrozenTime
    ) public onlyOwner {
        rewardToken = _rewardToken;
        rewardTokenPerBlock = _rewardTokenPerBlock;
        startRewardBlock = _startRewardBlock;
        endRewardBlock = _endRewardBlock;
        bonusEndBlock = _bonusEndBlock;
        unstakeFrozenTime = _unstakeFrozenTime;
    }

    function setRewardToken(IERC20 _rewardToken) public onlyOwner {
        rewardToken = _rewardToken;
    }

    function setUnstakeFrozenTime(uint256 _unstakeFrozenTime) public onlyOwner {
        unstakeFrozenTime = _unstakeFrozenTime;
    }

    function setRewardTokenPerBlock(uint256 _rewardTokenPerBlock)
        public
        onlyOwner
    {
        rewardTokenPerBlock = _rewardTokenPerBlock;
    }

    function setStartRewardBlock(uint256 _startRewardBlock) public onlyOwner {
        startRewardBlock = _startRewardBlock;
    }

    function setEndRewardBlock(uint256 _endRewardBlock) public onlyOwner {
        endRewardBlock = _endRewardBlock;
    }

    function setBonusEndBlock(uint256 _bonusEndBlock) public onlyOwner {
        bonusEndBlock = _bonusEndBlock;
    }

    function poolLength() external view returns (uint256) {
        return poolInfo.length;
    }



    function add(
        uint256 _allocPoint,
        IERC20 _lpToken,
        bool _withUpdate
    ) public onlyOwner {
        if (_withUpdate) {
            massUpdatePools();
        }
        uint256 lastRewardBlock =
            block.number > startRewardBlock ? block.number : startRewardBlock;
        totalAllocPoint = totalAllocPoint.add(_allocPoint);
        poolInfo.push(
            PoolInfo({
                lpToken: _lpToken,
                allocPoint: _allocPoint,
                lastRewardBlock: lastRewardBlock,
                accRewardTokenPerShare: 0
            })
        );
    }


    function set(
        uint256 _pid,
        uint256 _allocPoint,
        bool _withUpdate
    ) public onlyOwner {
        if (_withUpdate) {
            massUpdatePools();
        }
        totalAllocPoint = totalAllocPoint.sub(poolInfo[_pid].allocPoint).add(
            _allocPoint
        );
        poolInfo[_pid].allocPoint = _allocPoint;
    }


    function getMultiplier(uint256 _from, uint256 _to)
        public
        view
        returns (uint256)
    {
        if (_to <= bonusEndBlock) {
            return _to.sub(_from).mul(BONUS_MULTIPLIER);
        } else if (_from >= bonusEndBlock) {
            return _to.sub(_from);
        } else {
            return
                bonusEndBlock.sub(_from).mul(BONUS_MULTIPLIER).add(
                    _to.sub(bonusEndBlock)
                );
        }
    }


    function pendingRewardToken(uint256 _pid, address _user)
        external
        view
        returns (uint256)
    {
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][_user];
        uint256 accRewardTokenPerShare = pool.accRewardTokenPerShare;
        uint256 lpSupply = pool.lpToken.balanceOf(address(this));
        if (block.number > pool.lastRewardBlock && lpSupply != 0) {
            uint256 multiplier =
                getMultiplier(pool.lastRewardBlock, block.number);
            uint256 rewardTokenReward =
                multiplier.mul(rewardTokenPerBlock).mul(pool.allocPoint).div(
                    totalAllocPoint
                );
            accRewardTokenPerShare = accRewardTokenPerShare.add(
                rewardTokenReward.mul(1e12).div(lpSupply)
            );
        }
        return
            user.amount.mul(accRewardTokenPerShare).div(1e12).sub(
                user.rewardDebt
            );
    }


    function massUpdatePools() public {
        uint256 length = poolInfo.length;
        for (uint256 pid = 0; pid < length; ++pid) {
            updatePool(pid);
        }
    }


    function updatePool(uint256 _pid) public {
        PoolInfo storage pool = poolInfo[_pid];
        if (block.number <= pool.lastRewardBlock) {
            return;
        }
        uint256 lpSupply = pool.lpToken.balanceOf(address(this));
        if (lpSupply == 0) {
            pool.lastRewardBlock = block.number;
            return;
        }
        uint256 multiplier = getMultiplier(pool.lastRewardBlock, block.number);
        uint256 rewardTokenReward =
            multiplier.mul(rewardTokenPerBlock).mul(pool.allocPoint).div(
                totalAllocPoint
            );


        pool.accRewardTokenPerShare = pool.accRewardTokenPerShare.add(
            rewardTokenReward.mul(1e12).div(lpSupply)
        );
        pool.lastRewardBlock = block.number;
    }



    function deposit(uint256 _pid, uint256 _amount) public {
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][msg.sender];
        updatePool(_pid);
        if (user.amount > 0) {
            uint256 pending =
                user.amount.mul(pool.accRewardTokenPerShare).div(1e12).sub(
                    user.rewardDebt
                );
            if (now > user.unstakeTime)
                safeRewardTokenTransfer(msg.sender, pending);
        }
        pool.lpToken.safeTransferFrom(
            address(msg.sender),
            address(this),
            _amount
        );
        user.unstakeTime = now + unstakeFrozenTime;
        user.amount = user.amount.add(_amount);
        user.rewardDebt = user.amount.mul(pool.accRewardTokenPerShare).div(
            1e12
        );
        emit Deposit(msg.sender, _pid, _amount);
    }


    function withdraw(uint256 _pid, uint256 _amount) public {
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][msg.sender];
        require(user.amount >= _amount, "withdraw: not good");

        if (now > user.unstakeTime) {
            updatePool(_pid);
            uint256 pending =
                user.amount.mul(pool.accRewardTokenPerShare).div(1e12).sub(
                    user.rewardDebt
                );
            safeRewardTokenTransfer(msg.sender, pending);
            user.amount = user.amount.sub(_amount);
            user.rewardDebt = user.amount.mul(pool.accRewardTokenPerShare).div(
                1e12
            );
            pool.lpToken.safeTransfer(address(msg.sender), _amount);
            emit Withdraw(msg.sender, _pid, _amount);
        }
    }



    function emergencyWithdraw(uint256 _pid) public {
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][msg.sender];
        pool.lpToken.safeTransfer(address(msg.sender), user.amount);
        emit EmergencyWithdraw(msg.sender, _pid, user.amount);
        user.amount = 0;
        user.rewardDebt = 0;
    }


    function safeRewardTokenTransfer(address _to, uint256 _amount) internal {
        if (
            block.number >= startRewardBlock && block.number <= endRewardBlock
        ) {
            uint256 rewardTokenBal = rewardToken.balanceOf(address(this));
            if (_amount > rewardTokenBal) {
                rewardToken.transfer(_to, rewardTokenBal);
            } else {
                rewardToken.transfer(_to, _amount);
            }
        }
    }







    IMigratorChef public migrator;

    function setMigrator(IMigratorChef _migrator) public onlyOwner {
        migrator = _migrator;
    }

    function depositRewardTokens(uint256 _amount) public onlyOwner {
        rewardToken.transferFrom(msg.sender, address(this), _amount);
    }

    function withdrawRewardTokens(uint256 _amount) public onlyOwner {
        rewardToken.transfer(msg.sender, _amount);
    }
}

interface IMigratorChef {
    function migrate(IERC20 token) external returns (IERC20);
}

