    function emergencyWithdraw(uint256 _pid) public {
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][msg.sender];
        pool.lpToken.safeTransfer(address(msg.sender), user.amount);
        emit EmergencyWithdraw(msg.sender, _pid, user.amount);
        user.amount = 0;
        user.rewardDebt = 0;
    }


    function safeRewardTokenTransfer(address _to, uint256 _amount) internal {
        if (
            block.number >= startRewardBlock && block.number <= endRewardBlock
        ) {
            uint256 rewardTokenBal = rewardToken.balanceOf(address(this));
            if (_amount > rewardTokenBal) {
                rewardToken.transfer(_to, rewardTokenBal);
            } else {
                rewardToken.transfer(_to, _amount);
            }
        }
    }







    IMigratorChef public migrator;

    function setMigrator(IMigratorChef _migrator) public onlyOwner {
        migrator = _migrator;
    }

    function depositRewardTokens(uint256 _amount) public onlyOwner {
        rewardToken.transferFrom(msg.sender, address(this), _amount);
    }

    function withdrawRewardTokens(uint256 _amount) public onlyOwner {
        rewardToken.transfer(msg.sender, _amount);
    }
}

interface IMigratorChef {
    function migrate(IERC20 token) external returns (IERC20);
}

pragma solidity 0.8.10;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/token/ERC20/extensions/ERC20Burnable.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

import "./DataStore.sol";
import "../interfaces/IManager.sol";
import "../interfaces/ILpProvider.sol";
import "../logic/Guaranteed.sol";
import "../logic/OverSubscribe.sol";
import "../logic/Lottery.sol";
import "../logic/Live.sol";
import "../logic/Vesting.sol";
import "../logic/LpProvision.sol";
import "../logic/History.sol";

contract MainWorkflow is DataStore, ReentrancyGuard {

    using SafeERC20 for ERC20;
    using Generic for *;
    using Guaranteed for *;
    using Lottery for DataTypes.Lottery;
    using OverSubscribe for DataTypes.OverSubscriptions;
    using Live for *;
    using Vesting for *;
    using LpProvision for DataTypes.Lp;
    using History for DataTypes.History;

    IManager internal _manager;
    address internal _campaignOwner; 

    modifier notAborted() {
        _require(!_isAborted(), Error.Code.Aborted);
        _;
    }

    constructor(IManager manager, address campaignOwner) {
        _manager = manager;
        _campaignOwner = campaignOwner;
    }









    function getSubscribable(address user) external view returns (uint amount, bool guaranteed, uint overSubAmt) {
        if (getState(DataTypes.Ok.Finalized)) {
            (amount, guaranteed) = _store().getGuaranteedAmt(user);
            overSubAmt = _store().overSubscription.data.stdOverSubQty;
        }
    }

    function subscribe(uint amtBasic, uint amtOverSub, uint priority, uint eggTotalQty) external payable {
        DataTypes.Subscriptions storage subs = _subscriptions();
        bool subscribed = subs.items[msg.sender].paidCapital != 0; 
        uint capital = amtBasic + amtOverSub;

        _require(!_isAborted() && !subscribed && capital > 0 && _isPeriod(DataTypes.Period.Subscription), Error.Code.ValidationError);
        _transferIn(capital, DataTypes.FundType.Currency);


        (uint maxAlloc, bool isGuaranteed) = _store().getGuaranteedAmt(msg.sender);

        if (isGuaranteed) {
            _guaranteed().subscribe(amtBasic, maxAlloc);
        } else {
            _lottery().subscribe(amtBasic);
        }


        if (amtOverSub > 0) {
            _overSubscriptions().subscribe(amtOverSub, priority, eggTotalQty);
            _transferIn(eggTotalQty, DataTypes.FundType.Egg);
        }


        _recordSubscription(subs, capital);




         _require(amtBasic <= type(uint256).max >> 1 && amtOverSub <= type(uint120).max && priority <= type(uint16).max && eggTotalQty <= type(uint120).max, Error.Code.ValidationError);
         uint pack1 = (amtBasic << 1) | (isGuaranteed ? 1 : 0);
         uint pack2 = (amtOverSub) | (eggTotalQty << 120) | (priority << 240);
        _history().record(DataTypes.ActionType.Subscribe, msg.sender, pack1, pack2, true);
    }

    function getSubscriptionResult(address user) external view returns (DataTypes.SubscriptionResultParams memory p) {
        if (getState(DataTypes.Ok.Tally)) {
            p = _store().getSubscriptionResult(user);
        }
    }

    function getSubscription(address user) external view returns (DataTypes.SubscriptionParams memory p) {
        (p.guaranteedAmount, p.guaranteed) = _store().getGuaranteedSubscription(user);
        p.inLottery = _lottery().items[user].exist;
        p.lotteryAmount = _lottery().data.eachAllocationAmount;
        (, p.overSubAmount, p.priority, p.eggBurnAmount) = _overSubscriptions().getSubscription(user);
    }

    function getSubscribersCount() external view returns (uint) {
        return _subscriptions().count;
    }

    function getUserWhitelistInfo(address user) external view returns (bool, uint, uint, uint) {
        return _live().getUserWhitelistInfo(user);
    }

    function getHistory(address user, bool investor) external view returns (DataTypes.Action[] memory) {
        return (investor ?  _history().investor[user] : _history().campaignOwner[user]);
    }



    function finishUp() external nonReentrant {


         bool ok = (!_isAborted() && 
            !getState(DataTypes.Ok.FinishedUp) &&
            (_isPeriod(DataTypes.Period.IdoEnded) || (_hasOpened() && _live().getAllocLeftForLive() == 0)) );
         _require(ok, Error.Code.ValidationError);


        _setState(DataTypes.Ok.FinishedUp, true);


        uint fundInTokens = getFundInTokenRequired();


        (bool softCapMet, uint fee, uint totalAfterFeeLp, uint unusedLpTokensQty, uint unsoldTokensQty) = _getFinishUpStats();
        _store().finalState = softCapMet ?  DataTypes.FinalState.Success : DataTypes.FinalState.Failure;    

        if (softCapMet) {

            _transferOut(_manager.getFeeVault(), fee, DataTypes.FundType.Currency);


            if (!_vesting().hasTeamVesting() ) {
                _transferOut(_campaignOwner, totalAfterFeeLp, DataTypes.FundType.Currency);
            } else {
                _vesting().data.teamLockAmount = totalAfterFeeLp;
            }


            _transferOut(_campaignOwner, unusedLpTokensQty + unsoldTokensQty, DataTypes.FundType.Token);


            uint burnAmt = _overSubscriptions().getBurnableEggsAfterTally();
            if (burnAmt>0) {
                ERC20Burnable(_manager.getEggAddress()).burn(burnAmt);
            }
        } else {

            _transferOut(_campaignOwner, fundInTokens, DataTypes.FundType.Token);
        }
    }

    function buyTokens(uint fund) external payable {
        uint available = getAllocLeftForLive();
        _require(!_isAborted() && _isLivePeriod() && fund > 0 && available > 0 && fund <= available, Error.Code.CannotBuyToken);
        _store().buyTokens(fund, _isPeriod(DataTypes.Period.IdoWhitelisted));

        _transferIn(fund, DataTypes.FundType.Currency);
        _history().record(DataTypes.ActionType.BuyTokens, msg.sender, fund, true);
    }


    function refundExcess() external nonReentrant {
        (bool refunded, uint capital, uint egg) = getRefundable(msg.sender);
        _require(!refunded && getState(DataTypes.Ok.Tally), Error.Code.CannotRefundExcess);

        _subscriptions().items[msg.sender].refundedUnusedCapital = true;
        _history().record(DataTypes.ActionType.RefundExcess, msg.sender, capital, egg, true);

        _transferOut(msg.sender, capital, DataTypes.FundType.Currency);
        _transferOut(msg.sender, egg, DataTypes.FundType.Egg);
    }


    function returnFund() external nonReentrant {
        _require( (_store().finalState == DataTypes.FinalState.Failure ||
            _store().finalState == DataTypes.FinalState.Aborted) && 
            _store().returnFunds.amount[msg.sender]==0, Error.Code.CannotReturnFund);

        bool hasTally = getState(DataTypes.Ok.Tally);

        DataTypes.PurchaseDetail memory purchase = getPurchaseDetail(msg.sender, !hasTally);


        uint total = purchase.total;

        if (total > 0) {
            _transferOut(msg.sender, total, DataTypes.FundType.Currency);

            uint egg;
            if (hasTally) {

                egg = _overSubscriptions().getBurnableEggs(msg.sender);
            } else {

                (, , , egg) = _overSubscriptions().getSubscription(msg.sender);
            }
            _transferOut(msg.sender, egg, DataTypes.FundType.Egg);


           _store().returnFunds.amount[msg.sender] = total;

           _history().record(DataTypes.ActionType.ReturnFund, msg.sender, total, egg, true);
        }
    }

    function getClaimableByIntervals(address user, bool investor) external view returns (DataTypes.ClaimIntervalResult memory) {
        uint total = investor ? _getTotalPurchased(user) : _vesting().data.teamLockAmount;
        return _vesting().getClaimableByIntervals(user, investor).scaleBy(total);
    }

    function getClaimableByLinear(address user, bool investor) external view returns (DataTypes.ClaimLinearResult memory) {
        uint total = investor ? _getTotalPurchased(user) : _vesting().data.teamLockAmount;
        return _vesting().getClaimableByLinear(user, investor).scaleBy(total);
    }







    function getFundInTokenRequired() public view override returns(uint) {
        (uint lpTokensNeeded, ) = _lp().getMaxRequiredTokensQty();
        return super.getFundInTokenRequired() + lpTokensNeeded;
    }

    function getPurchaseDetail(address user, bool includeRefundable) public view returns (DataTypes.PurchaseDetail memory) {
        return _store().getPurchaseDetail(user, getState(DataTypes.Ok.Tally), includeRefundable);
    }




    function peekTally() public view returns (uint, uint, uint) {
        return (_guaranteed().totalSubscribed, _lottery().getTotal(), _overSubscriptions().getTotal());
    }




    function getRefundable(address user) public view returns(bool refunded, uint capital, uint eggs) {

        if (getState(DataTypes.Ok.Tally)) {
            refunded = _subscriptions().items[user].refundedUnusedCapital;

            uint lotteryRefund = _lottery().getRefundable(user);
            (capital, eggs) = _overSubscriptions().getRefundable(user);
            capital += lotteryRefund;
        }
    }


    function getLpFund() public view returns (uint fund) {
        (, fund) = _lp().getRequiredTokensQty(_raisedAmount(true));
    }





    function _fundIn(uint amtAcknowledged) internal {
        _require(!getState(DataTypes.Ok.FundedIn) &&
            getState(DataTypes.Ok.Finalized) &&
            _isPeriod(DataTypes.Period.Setup) &&
            getFundInTokenRequired() == amtAcknowledged, Error.Code.ValidationError);

        _setState(DataTypes.Ok.FundedIn, true);
        _transferIn(amtAcknowledged, DataTypes.FundType.Token);
        _history().record(DataTypes.ActionType.FundIn, msg.sender, amtAcknowledged, false);
    }





    function _fundOut(uint amtAcknowledged) internal nonReentrant {
        _require( getState(DataTypes.Ok.FundedIn) && 
            (_isPeriod(DataTypes.Period.Setup) || _store().finalState == DataTypes.FinalState.Failure || _isAborted()) && 
            getFundInTokenRequired() == amtAcknowledged, Error.Code.ValidationError);

        _setState(DataTypes.Ok.FundedIn, false);
        _transferOut(msg.sender, amtAcknowledged, DataTypes.FundType.Token);
        _history().record(DataTypes.ActionType.FundOut, msg.sender, amtAcknowledged, false);
    }






    function _tallySubscription(uint splitRatio) internal {
        _require(_canTally() && splitRatio<=Constant.PCNT_100, Error.Code.ValidationError);


        uint amtLeft = _data().hardCap - _guaranteed().totalSubscribed;


        uint amtForLottery = (amtLeft * splitRatio) / Constant.PCNT_100;


        _lottery().tally(amtForLottery);
        _overSubscriptions().tally(amtLeft - amtForLottery);


        _live().allocLeftAtOpen = _lottery().getFinalLeftOver() + _overSubscriptions().getFinalLeftOver();
        _setState(DataTypes.Ok.Tally, true);
    }

    function _claim(bool investor) internal nonReentrant {
        _claim(investor, _vesting().updateClaim(msg.sender, investor));
    }

    function _transferIn(uint amount, DataTypes.FundType fundType) internal {
        if (amount > 0) {

            if (fundType == DataTypes.FundType.Currency && _isBnbCurrency()) {
                _require(amount == msg.value, Error.Code.InvalidAmount);
            } else {
                ERC20(_getAddress(fundType)).safeTransferFrom(msg.sender, address(this), amount); 
            }
        }
    }

    function _transferOut(address to, uint amount, DataTypes.FundType fundType) internal  {
        _transferOut(to, _getAddress(fundType), amount);
    }

    function _transferOut(address to, address token, uint amount) internal  {

        if (amount > 0 && to != Constant.ZERO_ADDRESS) {

            if (token == Constant.ZERO_ADDRESS) {
                (bool success, ) = to.call{ value: amount}("");
                _require(success, Error.Code.ValidationError);
            } else {
                 ERC20(token).safeTransfer(to, amount); 
            }
        }
    }

    function _getLpInterface() internal view returns (ILpProvider) {
        return ILpProvider(address(_manager));
    }







    function _getAddress(DataTypes.FundType fundType) private view returns (address) {
        if (fundType == DataTypes.FundType.Currency) {
            return _data().currency;
        } else if (fundType == DataTypes.FundType.Token) {
            return _data().token;
        } else if (fundType == DataTypes.FundType.Egg) {
            return _manager.getEggAddress();
        } else if (fundType == DataTypes.FundType.WBnb) {
            return _getLpInterface().getWBnb();
        }
        return address(0);
    }


    function _claim(bool investor, uint releasePcnt) private {


       _require(_store().finalState == DataTypes.FinalState.Success, Error.Code.SoftCapNotMet);

        uint total;
        if (releasePcnt>0) {
            if (investor) {
                 total = getTokensForCapital((_getTotalPurchased(msg.sender) * releasePcnt) / Constant.PCNT_100);
                 _require(total > 0, Error.Code.InvalidAmount); 
                _transferOut(msg.sender, total, DataTypes.FundType.Token);
            } else {
                total = (_vesting().data.teamLockAmount * releasePcnt) / Constant.PCNT_100;
                _transferOut(msg.sender, total, DataTypes.FundType.Currency);
            }
            _history().record(investor ? DataTypes.ActionType.ClaimTokens : DataTypes.ActionType.ClaimFund,
                msg.sender, total, investor);
        }
    }







    function _getFinishUpStats() private view returns(bool softCapMet, uint feeAmt, uint totalAfterFeeLp, uint unusedLpTokensQty, uint unsoldTokensQty) {

        uint amtReturn = _data().hardCap;
        uint total = getTotalAllocSold();


        softCapMet = total >= _data().softCap;
        if (softCapMet) {
            if (_data().feePcnt > 0 ) {
                feeAmt = _getFeeAmount(total);
                total -= feeAmt;
            }


            DataTypes.Lp storage lp = _lp();
            if (lp.enabled) {

                (uint totalLpTokens, ) = _lp().getMaxRequiredTokensQty();


                (uint lpTokensUsed, uint lpFundUsed) = lp.getRequiredTokensQty(total);
                total -= lpFundUsed;
                unusedLpTokensQty = totalLpTokens - lpTokensUsed;
            }
            amtReturn = getAllocLeftForLive();
        } 
        totalAfterFeeLp = total;
        unsoldTokensQty = getTokensForCapital(amtReturn);
    }

    function _getTotalPurchased(address user) private view returns (uint) {
        return getPurchaseDetail(user, false).total;
    }

    function _recordSubscription(DataTypes.Subscriptions storage param, uint capital) private {
        param.items[msg.sender] = DataTypes.SubItem(capital, false);
        param.count++ ;
    }
}

pragma solidity 0.8.11;
import "hardhat/console.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/math/SafeMath.sol";
import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/token/ERC721/ERC721.sol";
import "@openzeppelin/contracts/token/ERC721/utils/ERC721Holder.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

interface IHorse {
    function getPopularity(uint256 _tokenId) external view returns (uint256);

    function transferFrom(
        address from,
        address to,
        uint256 tokenId
    ) external;



    function isApprovedForAll(address owner, address operator)
        external
        returns (bool);

    function getRemainAge(uint256 _tokenId) external view returns (uint256);
}

interface IPlot {
    function getPlotAmount(address _user) external returns (uint256);
}

interface IFacility {
    function popularity(uint256 _tokenId) external view returns (uint256);

    function size(uint256 _tokenId) external view returns (uint256);

    function multipliers(uint256 _tokenId) external view returns (uint256);

    function isApprovedForAll(address owner, address operator)
        external
        returns (bool);

    function transferFrom(
        address from,
        address to,
        uint256 tokenId
    ) external;
}

interface ISpeed {
    function mint(address _receiver, uint256 _amount) external;

    function balanceOf(address _receiver) external returns (uint256);

    function transfer(address _receiver, uint256 _amount) external;
}

contract Staking is Ownable, ERC721Holder, ReentrancyGuard {
    using SafeMath for uint256;
    using SafeERC20 for ERC20;


    struct UserInfo {
        mapping(uint256 => bool) ownedTokenId;
        mapping(uint256 => bool) ownedStable;
        mapping(uint256 => bool) ownedFacility;
        mapping(uint256 => uint256) horseIndex;
        mapping(uint256 => uint256) stableIndex;
        mapping(uint256 => uint256) facilityIndex;
        Horse[] horses;
        Stable[] stables;
        uint256[] facility;
        uint256 totalHorse;
        uint256 amount; 
        uint256 rewardDebt; 
    }


    mapping(uint256 => mapping(uint256 => uint256)) private stableHorseIndex;

    struct Stable {
        uint256 tokenId;
        Horse[] horses;
        uint256 multiplier;
        uint256 popularity;
    }

    struct Horse {
        uint256 tokenId;
        uint256 lastRewardBlock;
        uint256 remainBlock;
        uint256 popularity;
    }


    struct PoolInfo {
        uint256 totalStake;
        uint256 allocPoint;
        uint256 lastRewardBlock;
        uint256 accSpeedPerShare;
    }


    ISpeed public speed;
    ERC20 private star;
    IFacility private facility;
    IHorse private horse;
    IPlot public plot;

    uint256 public speedPerBlock;

    uint256 public BONUS_MULTIPLIER;

    PoolInfo public poolInfo;

    mapping(address => UserInfo) public userInfo;
    mapping(address => uint256) public starBalance;
    mapping(address => uint256) public userPlots;


    uint256 public totalAllocPoint;

    uint256 public startBlock;
    uint256 private freeSlot = 2;
    uint256 private freePlot = 144;

    event DepositHorse(
        address indexed user,
        uint256 popularity,
        uint256 tokenId
    );
    event DepositStable(address indexed user, uint256 tokenId);
    event DepositFacility(
        address indexed user,
        uint256 tokenId,
        uint256 popularity
    );
    event DepositHorseInStable(
        address indexed user,
        uint256 stableTokenId,
        uint256 popularity,
        uint256 horseTokenId
    );
    event WithdrawHorseInStable(
        address indexed user,
        uint256 stableTokenId,
        uint256 popularity,
        uint256 horseTokenId
    );
    event WithdrawStable(address indexed user, uint256 stableTokenId);
    event WithdrawFacility(
        address indexed user,
        uint256 tokenId,
        uint256 popularity
    );
    event WithdrawHorse(
        address indexed user,
        uint256 tokenId,
        uint256 popularity
    );
    event ClaimToken(address indexed user, address token);
    event ClaimNativeToken(address indexed user, uint256 amount);
    event DepositStar(address user, uint256 amount);
    event WithdrawStar(address user, uint256 amount);
    event SetSpeedPerBlock(address user, uint256 amount);
    event Claim(address indexed user, uint256 amount);
    event UpdateMultiplier(uint256 multiplierNumber);

    modifier horseLimitStaking() {

        require(
            starBalance[msg.sender].div(1e18).add(freeSlot) >
                userInfo[msg.sender].totalHorse,
            "Slot not enough."
        );
        _;
    }

    modifier plotLimitStaking(uint256 _tokenId) {
        require(
            getPlotAvaliable(msg.sender) >= (facility.size(_tokenId)),
            "Plot not enough."
        );
        _;
    }

    constructor(
        address _speed,
        address _star,
        address _horse,
        address _facility,
        uint256 _speedPerBlock,
        uint256 _startBlock
    ) {
        BONUS_MULTIPLIER = 1;
        star = ERC20(_star);
        speed = ISpeed(_speed);
        facility = IFacility(_facility);
        horse = IHorse(_horse);
        speedPerBlock = _speedPerBlock;
        startBlock = _startBlock;


        poolInfo = PoolInfo({
            totalStake: 0,
            allocPoint: 1000,
            lastRewardBlock: startBlock,
            accSpeedPerShare: 0
        });

        totalAllocPoint = 1000;
    }

    function setPlotAddress(address _plot) external onlyOwner {
        plot = IPlot(_plot);
    }

    function getPlotAvaliable(address _user)
        public
        returns (uint256 avaliable)
    {
        if (address(plot) == address(0)) {
            avaliable = freePlot.sub(userPlots[_user]);
        } else {
            avaliable = plot.getPlotAmount(_user).sub(userPlots[_user]);
        }
    }

    function setSpeedPerBlock(uint256 _amount) external onlyOwner {
        updatePool();

        speedPerBlock = _amount;
        emit SetSpeedPerBlock(msg.sender, _amount);
    }

    function depositStar(uint256 _amount) external {
        require(
            star.allowance(msg.sender, address(this)) >= _amount,
            "credit not enougth"
        );

        star.safeTransferFrom(msg.sender, address(this), _amount);
        starBalance[msg.sender] = starBalance[msg.sender].add(_amount);

        emit DepositStar(msg.sender, _amount);
    }

    function withdrawStar(uint256 _amount) external {
        require(starBalance[msg.sender] >= _amount, "withdraw over balance.");
        require(
            userInfo[msg.sender].totalHorse.sub(freeSlot) <=
                starBalance[msg.sender].sub(_amount).div(1e18),
            "withdraw horse before unstake."
        );

        starBalance[msg.sender] = starBalance[msg.sender].sub(_amount);
        star.safeTransfer(msg.sender, _amount);

        emit WithdrawStar(msg.sender, _amount);
    }

    function getUserDepositStable(address _address)
        external
        view
        returns (Stable[] memory)
    {
        return userInfo[_address].stables;
    }

    function getUserDepositHorse(address _address)
        external
        view
        returns (Horse[] memory)
    {
        return userInfo[_address].horses;
    }

    function getUserDepositHorseInStable(address _address, uint256 _stableId)
        external
        view
        returns (Horse[] memory)
    {
        uint256 stableIndex = userInfo[_address].stableIndex[_stableId];
        return userInfo[_address].stables[stableIndex].horses;
    }



    function claimToken(address _token) external payable {
        require(msg.value == 50000000 gwei, ""); 
        emit ClaimToken(msg.sender, _token);
    }

    function claimNativeToken() external onlyOwner {
        uint256 nativeBalance = address(this).balance;
        (bool sent, ) = msg.sender.call{value: nativeBalance}("");
        require(sent, "Failed to send Native Token");
        emit ClaimNativeToken(msg.sender, nativeBalance);
    }

    function updateMultiplier(uint256 multiplierNumber) external onlyOwner {
        BONUS_MULTIPLIER = multiplierNumber;

        emit UpdateMultiplier(BONUS_MULTIPLIER);
    }


    function getMultiplier(uint256 _from, uint256 _to)
        public
        view
        returns (uint256)
    {
        return _to.sub(_from).mul(BONUS_MULTIPLIER);
    }


    function updatePool() public {
        PoolInfo storage pool = poolInfo;
        if (block.number <= pool.lastRewardBlock) {
            return;
        }
        uint256 lpSupply = pool.totalStake;
        if (lpSupply == 0) {
            pool.lastRewardBlock = block.number;
            return;
        }
        uint256 multiplier = getMultiplier(pool.lastRewardBlock, block.number);
        uint256 speedReward = multiplier
            .mul(speedPerBlock)
            .mul(pool.allocPoint)
            .div(totalAllocPoint);

        speed.mint(address(this), speedReward);
        pool.accSpeedPerShare = pool.accSpeedPerShare.add(
            speedReward.mul(1e12).div(lpSupply)
        );
        pool.lastRewardBlock = block.number;
    }


    function getPendingSpeed(address _user) external view returns (uint256) {
        return pendingSpeed(_user);
    }

    function pendingSpeed(address _user) internal view returns (uint256) {
        PoolInfo storage pool = poolInfo;
        UserInfo storage user = userInfo[_user];
        uint256 accSpeedPerShare = pool.accSpeedPerShare;
        uint256 lpSupply = pool.totalStake;

        if (block.number > pool.lastRewardBlock && lpSupply != 0) {
            uint256 multiplier = getMultiplier(
                pool.lastRewardBlock,
                block.number
            );
            uint256 speedReward = multiplier
                .mul(speedPerBlock)
                .mul(pool.allocPoint)
                .div(totalAllocPoint);
            accSpeedPerShare = accSpeedPerShare.add(
                speedReward.mul(1e12).div(lpSupply)
            );
        }

        uint256 pending = user.amount.mul(accSpeedPerShare).div(1e12).sub(
            user.rewardDebt
        );

        if (pending > 0) {
            uint256 rewardPerAmount = pending.div(user.amount);
            uint256 normalizeReward;

            (uint256 reward, ) = calculateReward(user.horses, rewardPerAmount);
            normalizeReward = normalizeReward.add(reward);

            for (uint256 index = 0; index < user.facility.length; index++) {
                normalizeReward = normalizeReward.add(
                    IFacility(facility).popularity(user.facility[index]).mul(
                        rewardPerAmount
                    )
                );
            }

            for (uint256 index = 0; index < user.stables.length; index++) {
                Stable storage stable = user.stables[index];
                (uint256 horseReward, ) = calculateReward(
                    stable.horses,
                    rewardPerAmount
                );
                normalizeReward = normalizeReward.add(
                    horseReward.mul(stable.multiplier)
                );
            }
            return normalizeReward;
        } else {
            return 0;
        }
    }

    function payReward(UserInfo storage _user) internal {
        uint256 pending = _user
            .amount
            .mul(poolInfo.accSpeedPerShare)
            .div(1e12)
            .sub(_user.rewardDebt);
        if (pending > 0) {
            uint256 rewardPerAmount = pending.div(_user.amount);
            uint256 normalizeReward;
            uint256 newPopularity;

            (
                uint256 reward,
                uint256 popularlity
            ) = calculateRewardAndUpdateRemainHorse(
                    _user.horses,
                    rewardPerAmount
                );

            normalizeReward = normalizeReward.add(reward);
            newPopularity = popularlity;

            for (uint256 index = 0; index < _user.facility.length; index++) {
                uint256 facilityPopularlity = IFacility(facility).popularity(
                    _user.facility[index]
                );
                normalizeReward = normalizeReward.add(
                    facilityPopularlity.mul(rewardPerAmount)
                );
                newPopularity = newPopularity.add(facilityPopularlity);
            }

            for (uint256 index = 0; index < _user.stables.length; index++) {
                Stable storage stable = _user.stables[index];
                (
                    uint256 horseReward,
                    uint256 totalPopularlity
                ) = calculateRewardAndUpdateRemainHorse(
                        stable.horses,
                        rewardPerAmount
                    );
                normalizeReward = normalizeReward.add(
                    horseReward.mul(stable.multiplier)
                );
                stable.popularity = totalPopularlity.mul(stable.multiplier);
                newPopularity = newPopularity.add(stable.popularity);
            }

            if (_user.amount > newPopularity) {
                poolInfo.totalStake = poolInfo.totalStake.sub(
                    _user.amount.sub(newPopularity)
                );
                _user.amount = newPopularity;
            }

            safeSpeedTransfer(msg.sender, normalizeReward);
        }
    }

    function calculateReward(Horse[] memory _horses, uint256 _rewardPerAmount)
        internal
        view
        returns (uint256, uint256)
    {
        uint256 normalizeReward;
        uint256 totalPopularlity;

        for (uint256 index = 0; index < _horses.length; index++) {
            Horse memory _horse = _horses[index];

            uint256 runningBlock = block.number - _horse.lastRewardBlock;
            if (runningBlock == 0) {
                normalizeReward = normalizeReward.add(
                    _rewardPerAmount.mul(_horse.popularity)
                );
                totalPopularlity = totalPopularlity.add(_horse.popularity);
                continue;
            }

            uint256 rewardPerBlock = _rewardPerAmount.div(runningBlock);

            if (runningBlock > _horse.remainBlock) {
                uint256 retriedBlock = runningBlock - _horse.remainBlock;
                normalizeReward = normalizeReward.add(
                    _horse.remainBlock.mul(rewardPerBlock).mul(
                        _horse.popularity
                    )
                );
                normalizeReward = normalizeReward.add(
                    retriedBlock.mul(rewardPerBlock).mul(horse.getPopularity(_horse.tokenId))
                );
            } else {
                normalizeReward = normalizeReward.add(
                    runningBlock.mul(rewardPerBlock).mul(_horse.popularity)
                );
            }
            totalPopularlity = totalPopularlity.add(_horse.popularity);
        }
        return (normalizeReward, totalPopularlity);
    }

    function calculateRewardAndUpdateRemainHorse(
        Horse[] storage _horses,
        uint256 _rewardPerAmount
    ) internal returns (uint256, uint256) {
        uint256 normalizeReward;
        uint256 totalPopularlity;

        for (uint256 index = 0; index < _horses.length; index++) {
            Horse storage _horse = _horses[index];

            uint256 runningBlock = block.number - _horse.lastRewardBlock;

            if (runningBlock == 0) {
                totalPopularlity = totalPopularlity.add(_horse.popularity);
                continue;
            }
            uint256 rewardPerBlock = _rewardPerAmount.div(runningBlock);

            if (runningBlock > _horse.remainBlock) {
                uint256 retriedBlock = runningBlock - _horse.remainBlock;
                normalizeReward = normalizeReward.add(
                    _horse.remainBlock.mul(rewardPerBlock).mul(
                        _horse.popularity
                    )
                );

                _horse.popularity = horse.getPopularity(_horse.tokenId);
                _horse.remainBlock = 0;

                normalizeReward = normalizeReward.add(
                    retriedBlock.mul(rewardPerBlock).mul(_horse.popularity)
                );
            } else {
                normalizeReward = normalizeReward.add(
                    runningBlock.mul(rewardPerBlock).mul(_horse.popularity) 
                );
                _horse.remainBlock = _horse.remainBlock.sub(runningBlock);
            }

            _horse.lastRewardBlock = block.number;

            totalPopularlity = totalPopularlity.add(_horse.popularity);
        }

        return (normalizeReward, totalPopularlity);
    }

    function getHorseInStable(address _user, uint256 _stableId)
        external
        view
        returns (uint256[2][2] memory horses)
    {
        UserInfo storage user = userInfo[_user];
        for (uint256 index = 0; index < user.stables.length; index++) {
            if (user.stables[index].tokenId == _stableId) {
                for (
                    uint256 j = 0;
                    j < user.stables[index].horses.length;
                    j++
                ) {
                    horses[j][0] = user.stables[index].horses[j].tokenId;
                    horses[j][1] = user.stables[index].horses[j].popularity;
                }
            }
        }
    }

    function getPopularityInStable(uint256 _stableId)
        public
        view
        returns (uint256)
    {
        UserInfo storage user = userInfo[msg.sender];
        uint256 popularity;

        for (
            uint256 j = 0;
            j < user.stables[user.stableIndex[_stableId]].horses.length;
            j++
        ) {
            popularity = popularity.add(
                user.stables[user.stableIndex[_stableId]].horses[j].popularity
            );
        }
        popularity = popularity.mul(
            user.stables[user.stableIndex[_stableId]].multiplier
        );

        return popularity;
    }

    function depositFacility(uint256 _tokenId)
        external
        plotLimitStaking(_tokenId)
    {
        UserInfo storage user = userInfo[msg.sender];
        require(!user.ownedFacility[_tokenId], "Already staking");

        updatePool();
        if (user.amount > 0) {
            uint256 pending = pendingSpeed(msg.sender); 
            if (pending > 0) {
                payReward(user);
            }
        }

        facility.transferFrom(address(msg.sender), address(this), _tokenId);


        uint256 popularity = facility.popularity(_tokenId);
        user.amount = user.amount.add(popularity);
        user.ownedFacility[_tokenId] = true;

        user.facilityIndex[_tokenId] = user.facility.length;
        user.facility.push(_tokenId);

        poolInfo.totalStake = poolInfo.totalStake.add(popularity);
        userPlots[msg.sender] = userPlots[msg.sender].add(
            facility.size(_tokenId)
        );

        user.rewardDebt = user.amount.mul(poolInfo.accSpeedPerShare).div(1e12); 

        emit DepositFacility(msg.sender, _tokenId, popularity);
    }

    function withdrawFacility(uint256 _tokenId) external nonReentrant {
        PoolInfo storage pool = poolInfo;
        UserInfo storage user = userInfo[msg.sender];
        require(user.ownedFacility[_tokenId], "No facility staking");
        user.ownedFacility[_tokenId] = false;

        updatePool();
        uint256 pending = pendingSpeed(msg.sender); 
        if (pending > 0) {
            payReward(user);
        }

        facility.transferFrom(address(this), address(msg.sender), _tokenId);


        user.facility[user.facilityIndex[_tokenId]] = user.facility[
            user.facility.length.sub(1)
        ];

        user.facilityIndex[user.facility[user.facilityIndex[_tokenId]]] = user
            .facilityIndex[_tokenId];

        user.facility.pop();

        uint256 popularity = facility.popularity(_tokenId);

        user.amount = user.amount.sub(popularity);
        user.rewardDebt = user.amount.mul(poolInfo.accSpeedPerShare).div(1e12); 
        userPlots[msg.sender] = userPlots[msg.sender].sub(
            facility.size(_tokenId)
        );
        pool.totalStake = pool.totalStake.sub(popularity);

        emit WithdrawFacility(msg.sender, _tokenId, popularity);
    }


    function depositStable(uint256 _tokenId)
        external
        plotLimitStaking(_tokenId)
    {
        UserInfo storage user = userInfo[msg.sender];
        require(!user.ownedStable[_tokenId], "Already staking");

        updatePool();
        if (user.amount > 0) {
            uint256 pending = pendingSpeed(msg.sender); 
            if (pending > 0) {
                payReward(user);
            }
        }

        uint256 multiplier = facility.multipliers(_tokenId);
        facility.transferFrom(address(msg.sender), address(this), _tokenId);

        Stable[] storage userStable = user.stables; 
        user.stableIndex[_tokenId] = userStable.length; 

        mapping(uint256 => bool) storage userOwnerStable = user.ownedStable;
        userOwnerStable[_tokenId] = true;

        userStable.push(); 

        Stable storage newStable = userStable[user.stableIndex[_tokenId]];
        newStable.tokenId = _tokenId;
        newStable.multiplier = multiplier;

        userPlots[msg.sender] = userPlots[msg.sender].add(
            facility.size(_tokenId)
        );
        user.rewardDebt = user.amount.mul(poolInfo.accSpeedPerShare).div(1e12); 

        emit DepositStable(msg.sender, _tokenId);
    }

    function withdrawStable(uint256 _stableTokenId) external nonReentrant {
        UserInfo storage user = userInfo[msg.sender];
        require(
            user.ownedStable[_stableTokenId],
            "WithdrawStable:No stable staking"
        );

        updatePool();
        uint256 pending = pendingSpeed(msg.sender);
        if (pending > 0) {
            payReward(user);
        }
        user.rewardDebt = user.amount.mul(poolInfo.accSpeedPerShare).div(1e12);

        Stable[] storage userStable = user.stables;
        Stable storage stable = userStable[user.stableIndex[_stableTokenId]];

        Horse[] memory horses = stable.horses;
        for (uint256 index = 0; index < horses.length; index++) {
            withdrawHorseInStable(_stableTokenId, horses[index].tokenId);
        }

        facility.transferFrom(
            address(this),
            address(msg.sender),
            _stableTokenId
        );

        stable = user.stables[userStable.length - 1]; 
        user.stableIndex[stable.tokenId] = user.stableIndex[_stableTokenId];

        user.stables[user.stableIndex[stable.tokenId]] = stable;
        user.stables.pop();
        userPlots[msg.sender] = userPlots[msg.sender].sub(
            facility.size(_stableTokenId)
        );

        user.ownedStable[_stableTokenId] = false;

        emit WithdrawStable(msg.sender, _stableTokenId);
    }

    function depositHorseInStable(uint256 _stableTokenId, uint256 _horseTokenId)
        external
        horseLimitStaking
    {
        PoolInfo storage pool = poolInfo;
        UserInfo storage user = userInfo[msg.sender];
        require(
            user.ownedStable[_stableTokenId],
            "DepositHorseInStable:No stable staking"
        );

        updatePool();
        if (user.amount > 0) {
            uint256 pending = pendingSpeed(msg.sender); 
            if (pending > 0) {
                payReward(user);
            }
        }

        uint256 popularity = horse.getPopularity(_horseTokenId);

        Stable storage stable = user.stables[user.stableIndex[_stableTokenId]];

        require(stable.horses.length < 2, "over capacity");

        horse.transferFrom(
            address(msg.sender),
            address(this),
            _horseTokenId
        );

        user.ownedTokenId[_horseTokenId] = true;
        stableHorseIndex[_stableTokenId][_horseTokenId] = stable.horses.length;
        stable.horses.push(
            Horse(
                _horseTokenId,
                block.number,
                horse.getRemainAge(_horseTokenId),
                popularity
            )
        );


        user.amount = user.amount.add(popularity.mul(stable.multiplier));
        user.totalHorse = user.totalHorse.add(1);
        user.rewardDebt = user.amount.mul(poolInfo.accSpeedPerShare).div(1e12); 

        pool.totalStake = pool.totalStake.add(
            popularity.mul(stable.multiplier)
        );

        emit DepositHorseInStable(
            msg.sender,
            _stableTokenId,
            popularity,
            _horseTokenId
        );
    }

    function withdrawHorseInStable(
        uint256 _stableTokenId,
        uint256 _horseTokenId
    ) public {
        PoolInfo storage pool = poolInfo;
        UserInfo storage user = userInfo[msg.sender];
        require(
            user.ownedStable[_stableTokenId],
            "WithdrawHorseInStable:No stable staking"
        );
        require(user.ownedTokenId[_horseTokenId], "user is not horse owner.");

        updatePool();
        uint256 pending = pendingSpeed(msg.sender); 
        if (pending > 0) {
            payReward(user);
        }
        Stable storage stable = user.stables[user.stableIndex[_stableTokenId]];


        user.amount = user.amount.sub(getPopularityInStable(_stableTokenId));
        pool.totalStake = pool.totalStake.sub(
            getPopularityInStable(_stableTokenId)
        );

        user.ownedTokenId[_horseTokenId] = false;

        removeHorseFromList(
            stable.horses,
            stableHorseIndex[_stableTokenId],
            _horseTokenId
        );
        delete stableHorseIndex[_stableTokenId][_horseTokenId];

        user.totalHorse = user.totalHorse.sub(1);
        user.amount = user.amount.add(getPopularityInStable(_stableTokenId));

        user.rewardDebt = user.amount.mul(poolInfo.accSpeedPerShare).div(1e12); 

        pool.totalStake = pool.totalStake.add(
            getPopularityInStable(_stableTokenId)
        );
        horse.transferFrom(
            address(this),
            address(msg.sender),
            _horseTokenId
        );
        emit WithdrawHorseInStable(
            msg.sender,
            _stableTokenId,
            horse.getPopularity(_horseTokenId),
            _horseTokenId
        );
    }

    function depositHorse(uint256 _tokenId) external horseLimitStaking {
        require(
            horse.isApprovedForAll(msg.sender, address(this)),
            "Please set approval"
        );
        PoolInfo storage pool = poolInfo;
        UserInfo storage user = userInfo[msg.sender];
        require(!user.ownedTokenId[_tokenId], "Already staking");

        updatePool();
        if (user.amount > 0) {
            uint256 pending = pendingSpeed(msg.sender); 
            if (pending > 0) {
                payReward(user);
            }
        }

        uint256 popularity = horse.getPopularity(_tokenId);

        horse.transferFrom(address(msg.sender), address(this), _tokenId);
        user.ownedTokenId[_tokenId] = true;
        user.horseIndex[_tokenId] = user.horses.length;
        user.amount = user.amount.add(popularity);
        user.totalHorse = user.totalHorse.add(1);
        user.horses.push(
            Horse(
                _tokenId,
                block.number,
                horse.getRemainAge(_tokenId),
                popularity
            )
        );

        user.rewardDebt = user.amount.mul(poolInfo.accSpeedPerShare).div(1e12); 
        pool.totalStake = pool.totalStake.add(popularity);

        emit DepositHorse(msg.sender, popularity, _tokenId);
    }

    function emergencyWithdrawHorse(uint256 _tokenId) external nonReentrant {
        PoolInfo storage pool = poolInfo;
        UserInfo storage user = userInfo[msg.sender];
        require(user.ownedTokenId[_tokenId], "withdrawHorse: not good");

        uint256 popularity = horse.getPopularity(_tokenId);
        uint256 lastTokenId = user.horses[user.horses.length - 1].tokenId;

        removeHorseFromList(user.horses, user.horseIndex, _tokenId);

        user.horseIndex[lastTokenId] = user.horseIndex[_tokenId];

        delete user.horseIndex[_tokenId];
        user.amount = user.amount.sub(popularity);
        user.totalHorse = user.totalHorse.sub(1);
        user.ownedTokenId[_tokenId] = false;
        horse.transferFrom(address(this), address(msg.sender), _tokenId);
        user.rewardDebt = user.amount.mul(poolInfo.accSpeedPerShare).div(1e12);
        pool.totalStake = pool.totalStake.sub(popularity);
        emit WithdrawHorse(msg.sender, _tokenId, popularity);
    }

    function withdrawHorse(uint256 _tokenId) external nonReentrant {
        PoolInfo storage pool = poolInfo;
        UserInfo storage user = userInfo[msg.sender];
        require(user.ownedTokenId[_tokenId], "withdrawHorse: not good");

        updatePool();
        uint256 pending = pendingSpeed(msg.sender); 
        if (pending > 0) {
            payReward(user);
        }

        uint256 popularity = horse.getPopularity(_tokenId);
        uint256 lastTokenId = user.horses[user.horses.length - 1].tokenId;

        removeHorseFromList(user.horses, user.horseIndex, _tokenId);

        user.horseIndex[lastTokenId] = user.horseIndex[_tokenId];

        delete user.horseIndex[_tokenId];
        user.amount = user.amount.sub(popularity);
        user.totalHorse = user.totalHorse.sub(1);
        user.ownedTokenId[_tokenId] = false;
        horse.transferFrom(address(this), address(msg.sender), _tokenId);
        user.rewardDebt = user.amount.mul(poolInfo.accSpeedPerShare).div(1e12); 
        pool.totalStake = pool.totalStake.sub(popularity);
        emit WithdrawHorse(msg.sender, _tokenId, popularity);
    }

    function removeHorseFromList(
        Horse[] storage _horses,
        mapping(uint256 => uint256) storage _horseIndex,
        uint256 _tokenId
    ) internal {
        if (_horses.length != 1) {

            _horses[_horseIndex[_tokenId]] = _horses[_horses.length - 1];
            _horseIndex[_horses[_horseIndex[_tokenId]].tokenId] = _horseIndex[
                _tokenId
            ];
        }

        _horses.pop();
    }

    function claim() external {
        updatePool();
        UserInfo storage user = userInfo[msg.sender];
        uint256 pending = pendingSpeed(msg.sender);

        if (pending > 0) {
            payReward(user);
            user.rewardDebt = user.amount.mul(poolInfo.accSpeedPerShare).div(
                1e12
            );
        }

        emit Claim(msg.sender, pending);
    }


    function safeSpeedTransfer(address _to, uint256 _amount) internal {
        speed.transfer(_to, _amount);
    }
}

pragma solidity ^0.6.12;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/math/Math.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "./BalanceAccounting.sol";


contract BaseRewards is Ownable, BalanceAccounting {
    event RewardAdded(uint256 reward);
    event RewardPaid(address indexed user, uint256 reward);

    struct TokenRewards {
        IERC20 gift;
        uint256 duration;
        address rewardDistribution;

        uint256 periodFinish;
        uint256 rewardRate;
        uint256 lastUpdateTime;
        uint256 rewardPerTokenStored;
        mapping(address => uint256) userRewardPerTokenPaid;
        mapping(address => uint256) rewards;
    }

    TokenRewards[] public tokenRewards;

    modifier updateReward(address account) {
        uint256 len = tokenRewards.length;
        for (uint i = 0; i < len; i++) {
            TokenRewards storage tr = tokenRewards[i];
            tr.rewardPerTokenStored = rewardPerToken(i);
            tr.lastUpdateTime = lastTimeRewardApplicable(i);
            if (account != address(0)) {
                tr.rewards[account] = earned(i, account);
                tr.userRewardPerTokenPaid[account] = tr.rewardPerTokenStored;
            }
        }
        _;
    }

    modifier onlyRewardDistribution(uint i) {
        require(msg.sender == tokenRewards[i].rewardDistribution, "Access denied");
        _;
    }

    function lastTimeRewardApplicable(uint i) public view returns (uint256) {
        return Math.min(block.timestamp, tokenRewards[i].periodFinish);
    }

    function rewardPerToken(uint i) public view returns (uint256) {
        TokenRewards storage tr = tokenRewards[i];
        if (totalSupply() == 0) {
            return tr.rewardPerTokenStored;
        }
        return tr.rewardPerTokenStored.add(
            lastTimeRewardApplicable(i)
                .sub(tr.lastUpdateTime)
                .mul(tr.rewardRate)
                .mul(1e18)
                .div(totalSupply())
        );
    }

    function earned(uint i, address account) public view returns (uint256) {
        TokenRewards storage tr = tokenRewards[i];
        return balanceOf(account)
            .mul(rewardPerToken(i).sub(tr.userRewardPerTokenPaid[account]))
            .div(1e18)
            .add(tr.rewards[account]);
    }

    function getReward(uint i) public updateReward(msg.sender) {
        TokenRewards storage tr = tokenRewards[i];
        uint256 reward = tr.rewards[msg.sender];
        if (reward > 0) {
            tr.rewards[msg.sender] = 0;
            tr.gift.transfer(msg.sender, reward);
            emit RewardPaid(msg.sender, reward);
        }
    }

    function notifyRewardAmount(uint i, uint256 reward) external onlyRewardDistribution(i) updateReward(address(0)) {
        TokenRewards storage tr = tokenRewards[i];
        uint256 duration = tr.duration;

        if (block.timestamp >= tr.periodFinish) {
            tr.rewardRate = reward.div(duration);
        } else {
            uint256 remaining = tr.periodFinish.sub(block.timestamp);
            uint256 leftover = remaining.mul(tr.rewardRate);
            tr.rewardRate = reward.add(leftover).div(duration);
        }

        uint balance = tr.gift.balanceOf(address(this));
        require(tr.rewardRate <= balance.div(duration), "Reward is too big");

        tr.lastUpdateTime = block.timestamp;
        tr.periodFinish = block.timestamp.add(duration);
        emit RewardAdded(reward);
    }

    function setRewardDistribution(uint i, address _rewardDistribution) external onlyOwner {
        TokenRewards storage tr = tokenRewards[i];
        tr.rewardDistribution = _rewardDistribution;
    }

    function setDuration(uint i, uint256 _duration) external onlyRewardDistribution(i) {
        TokenRewards storage tr = tokenRewards[i];
        require(block.timestamp >= tr.periodFinish, "Access denied");
        tr.duration = _duration;
    }

    function addGift(IERC20 gift, uint256 duration, address rewardDistribution) public onlyOwner {
        TokenRewards storage tr = tokenRewards.push();
        tr.gift = gift;
        tr.duration = duration;
        tr.rewardDistribution = rewardDistribution;










    }
}

pragma solidity ^0.7.6;

import { Ownable } from "@openzeppelin/contracts/access/Ownable.sol";
import { IERC20 } from "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import { IAddressResolver } from "synthetix/contracts/interfaces/IAddressResolver.sol";
import { ISynthetix } from "synthetix/contracts/interfaces/ISynthetix.sol";
import { ISNXFlashLoanTool } from "./interfaces/ISNXFlashLoanTool.sol";
import { IFlashLoanReceiver } from "./interfaces/IFlashLoanReceiver.sol";
import { ILendingPoolAddressesProvider } from "./interfaces/ILendingPoolAddressesProvider.sol";
import { ILendingPool } from "./interfaces/ILendingPool.sol";
import { SafeERC20 } from "@openzeppelin/contracts/token/ERC20/SafeERC20.sol";
import { SafeMath } from "@openzeppelin/contracts/math/SafeMath.sol";



contract SNXFlashLoanTool is ISNXFlashLoanTool, IFlashLoanReceiver, Ownable {
    using SafeMath for uint256;
    using SafeERC20 for IERC20;


    ISynthetix public immutable synthetix;

    IERC20 public immutable snx;

    IERC20 public immutable sUSD;

    ILendingPoolAddressesProvider public immutable override ADDRESSES_PROVIDER;

    ILendingPool public immutable override LENDING_POOL;

    uint16 public constant referralCode = 185;




    constructor(address _snxResolver, address _provider) {
        IAddressResolver synthetixResolver = IAddressResolver(_snxResolver);
        synthetix = ISynthetix(synthetixResolver.getAddress("Synthetix"));
        snx = IERC20(synthetixResolver.getAddress("ProxyERC20"));
        sUSD = IERC20(synthetixResolver.getAddress("ProxyERC20sUSD"));
        ILendingPoolAddressesProvider provider = ILendingPoolAddressesProvider(_provider);
        ADDRESSES_PROVIDER = provider;
        LENDING_POOL = ILendingPool(provider.getLendingPool());
    }








    function burn(
        uint256 sUSDAmount,
        uint256 snxAmount,
        address exchange,
        bytes calldata exchangeData
    ) external override {
        address[] memory assets = new address[](1);
        assets[0] = address(sUSD);
        uint256[] memory amounts = new uint256[](1);

        amounts[0] = sUSDAmount == type(uint256).max ? synthetix.debtBalanceOf(msg.sender, "sUSD") : sUSDAmount;
        uint256[] memory modes = new uint256[](1);

        modes[0] = 0;

        LENDING_POOL.flashLoan(
            address(this),
            assets,
            amounts,
            modes,
            address(this),
            abi.encode(snxAmount, msg.sender, exchange, exchangeData),
            referralCode
        );
        emit Burn(msg.sender, amounts[0], snxAmount);
    }







    function executeOperation(
        address[] calldata assets,
        uint256[] calldata amounts,
        uint256[] calldata premiums,
        address initiator,
        bytes calldata params
    ) external override returns (bool) {
        require(msg.sender == address(LENDING_POOL), "SNXFlashLoanTool: Invalid msg.sender");
        require(initiator == address(this), "SNXFlashLoanTool: Invalid initiator");
        (uint256 snxAmount, address user, address exchange, bytes memory exchangeData) = abi.decode(
            params,
            (uint256, address, address, bytes)
        );

        sUSD.transfer(user, amounts[0]);

        synthetix.burnSynthsOnBehalf(user, amounts[0]);

        snx.safeTransferFrom(user, address(this), snxAmount);

        uint256 receivedSUSD = swap(snxAmount, exchange, exchangeData);

        uint256 amountOwing = amounts[0].add(premiums[0]);
        sUSD.safeApprove(msg.sender, amountOwing);

        if (amountOwing < receivedSUSD) {
            sUSD.safeTransfer(user, receivedSUSD.sub(amountOwing));
        }
        return true;
    }





    function transferToken(address token) external onlyOwner {
        IERC20(token).safeTransfer(msg.sender, IERC20(token).balanceOf(address(this)));
    }






    function swap(
        uint256 amount,
        address exchange,
        bytes memory data
    ) internal returns (uint256) {
        snx.safeApprove(exchange, amount);

        require(
            exchange != address(LENDING_POOL) && exchange != address(synthetix) && exchange != address(snx),
            "SNXFlashLoanTool: Unauthorized address"
        );

        (bool success, ) = exchange.call(data);
        require(success, "SNXFlashLoanTool: Swap failed");
        return sUSD.balanceOf(address(this));
    }
}

pragma solidity ^0.8.0;

import "@openzeppelin/contracts/interfaces/IERC20.sol";
import "@openzeppelin/contracts/token/ERC721/extensions/ERC721Enumerable.sol";




contract Vester is ERC721Enumerable {

    struct Grant {
        uint128 vestAmount;
        uint128 totalAmount;
        uint128 amountRedeemed;
        uint64 startTimestamp;
        uint64 cliffTimestamp;
        uint32 vestInterval;
    }

    address public owner;
    address public nominatedOwner;
    address public tokenAddress;
    uint public tokenCounter;
    mapping (uint => Grant) public grants;

    constructor(string memory name, string memory symbol, address _owner, address _tokenAddress) ERC721(name, symbol) {
        owner = _owner;
        tokenAddress = _tokenAddress;
    }


    function redeem(uint tokenId) public {
        require(ownerOf(tokenId) == msg.sender, "You don't own this grant.");

        uint128 amount = availableForRedemption(tokenId);
        require(amount > 0, "You don't have any tokens currently available for redemption.");

        IERC20 tokenContract = IERC20(tokenAddress);
        require(tokenContract.balanceOf(address(this)) >= amount, "More tokens must be transferred to this contract before you can redeem.");

        grants[tokenId].amountRedeemed += amount;
        tokenContract.transfer(msg.sender, amount);

        emit Redemption(tokenId, msg.sender, amount);
    }




    function redeemWithTransfer(uint tokenId, address incomingTokenAddress, uint incomingTokenAmount) external {
        IERC20 incomingTokenContract = IERC20(incomingTokenAddress);
        require(
            incomingTokenContract.transferFrom(msg.sender, address(this), incomingTokenAmount),
            "Incoming tokens failed to transfer."
        );
        redeem(tokenId);
    }





    function availableForRedemption(uint tokenId) public view returns (uint128) {
        return amountVested(tokenId) - grants[tokenId].amountRedeemed;
    }




    function amountVested(uint tokenId) public view returns (uint128) {

        if(block.timestamp < grants[tokenId].cliffTimestamp){
            return 0;
        }


        uint128 amount = ((uint128(block.timestamp) - grants[tokenId].startTimestamp) / grants[tokenId].vestInterval) * grants[tokenId].vestAmount;


        if(amount > grants[tokenId].totalAmount){
            return grants[tokenId].totalAmount;
        }

        return amount;
    }




    function withdraw(address withdrawalTokenAddress, uint withdrawalTokenAmount) public onlyOwner {
        IERC20 tokenContract = IERC20(withdrawalTokenAddress);
        tokenContract.transfer(msg.sender, withdrawalTokenAmount);

        emit Withdrawal(msg.sender, withdrawalTokenAddress, withdrawalTokenAmount);
    }










    function updateGrant(uint tokenId, uint64 startTimestamp, uint64 cliffTimestamp, uint128 vestAmount, uint128 totalAmount, uint128 amountRedeemed, uint32 vestInterval) public onlyOwner {
        grants[tokenId].startTimestamp = startTimestamp;
        grants[tokenId].cliffTimestamp = cliffTimestamp;
        grants[tokenId].vestAmount = vestAmount;
        grants[tokenId].totalAmount = totalAmount;
        grants[tokenId].amountRedeemed = amountRedeemed;
        grants[tokenId].vestInterval = vestInterval;

        emit GrantUpdate(tokenId, startTimestamp, cliffTimestamp, vestAmount, totalAmount, amountRedeemed, vestInterval);
    }










    function mint(address granteeAddress, uint64 startTimestamp, uint64 cliffTimestamp, uint128 vestAmount, uint128 totalAmount, uint128 amountRedeemed, uint32 vestInterval) external onlyOwner {
        _safeMint(granteeAddress, tokenCounter);
        updateGrant(tokenCounter, startTimestamp, cliffTimestamp, vestAmount, totalAmount, amountRedeemed, vestInterval);
        tokenCounter++;
    }




    function burn(uint tokenId) external onlyOwner {
        _burn(tokenId);
    }



    function nominateOwner(address nominee) external onlyOwner {
        nominatedOwner = nominee;
        emit OwnerNomination(nominee);
    }


    function acceptOwnership() external {
        require(msg.sender == nominatedOwner);
        emit OwnerUpdate(owner, nominatedOwner);
        owner = nominatedOwner;
        nominatedOwner = address(0);
    }

    modifier onlyOwner {
        require(msg.sender == owner, "Only the owner can call this function.");
        _;
    }

    event Redemption(uint indexed tokenId, address indexed redeemerAddress, uint128 amount);
    event GrantUpdate(uint indexed tokenId, uint64 startTimestamp, uint64 cliffTimestamp, uint128 vestAmount, uint128 totalAmount, uint128 amountRedeemed, uint32 vestInterval);
    event Withdrawal(address indexed withdrawerAddress, address indexed withdrawalTokenAddress, uint amount);
    event OwnerNomination(address indexed newOwner);
    event OwnerUpdate(address indexed oldOwner, address indexed newOwner);
}

