        uint _bal = available();
        token.safeTransfer(controller, _bal);
        Controller(controller).earn(address(token), _bal);
    }

    function depositAll() external {
        deposit(token.balanceOf(msg.sender));
    }

    function deposit(uint _amount) public onlyRestrictContractCall {
		require(_amount > 0, "Cannot deposit 0");
        uint _pool = balance();
        uint _before = token.balanceOf(address(this));
        token.safeTransferFrom(msg.sender, address(this), _amount);
        uint _after = token.balanceOf(address(this));
        _amount = _after.sub(_before); 
        uint shares = 0;
        if (totalSupply() == 0) {
            shares = _amount;
        } else {
            shares = (_amount.mul(totalSupply())).div(_pool);
        }
        _mint(msg.sender, shares);
        userDepoistTime[msg.sender] = now;
        if (token.balanceOf(address(this))>earnLowerlimit){
          earn();
        }
    }

    function withdrawAll() external {
        withdraw(balanceOf(msg.sender));
    }




    function withdraw(uint _shares) public onlyRestrictContractCall {
		require(_shares > 0, "Cannot withdraw 0");

        uint r = (balance().mul(_shares)).div(totalSupply());
        _burn(msg.sender, _shares);


        uint b = token.balanceOf(address(this));
        if (b < r) {
            uint _withdraw = r.sub(b);
            Controller(controller).withdraw(address(token), _withdraw);
            uint _after = token.balanceOf(address(this));
            uint _diff = _after.sub(b);
            if (_diff < _withdraw) {
                r = b.add(_diff);
            }
        }
        uint feeRatio = getFeeRatio();
        if(feeRatio>0){
            uint fee = r.mul(feeRatio).div(feeMax);
            r = r.sub(fee);
            token.safeTransfer(feeAddress,fee);
        }
        token.safeTransfer(msg.sender, r);
    }

    function getFeeRatio() internal view returns(uint)
    {
        uint256 t = now - userDepoistTime[msg.sender];
        if(t > 604800) {
            return fee3;
        }
        if(t>86400) {
            return fee2;
        }
        return fee1;
    }

    function getPricePerFullShare() public view returns (uint) {
        if (totalSupply()==0) {
            return 0;
        }
        return balance().mul(1e18).div(totalSupply());
    }

    function setFeeRatio(uint[3] memory fees) public
    {
        require(msg.sender == timelock, "!timelock");
        require(fees[0]<feeMax&&fees[1]<feeMax&&fees[2]<feeMax,"The fee is too high");
        fee1 = fees[0];
        fee2 = fees[1];
        fee3 = fees[2];
    }

    function setFeeAddress(address fadd) public 
    {
        require(msg.sender == timelock, "!timelock");
        feeAddress = fadd;
    }

	function setTimeLock(address _timelock) public 
    {
        require(msg.sender == timelock, "!timelock");
        timelock = _timelock;
    }

    function setRestrictContractCall(bool enabled) public {
        require(msg.sender == governance, "!governance");
        RestrictContractCall = enabled;
    }
}

pragma solidity ^0.8.0;



import "../Pool/BufferBNBPool.sol";

import "@openzeppelin/contracts/token/ERC721/extensions/ERC721Burnable.sol";
import "@openzeppelin/contracts/token/ERC721/extensions/ERC721Enumerable.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";

import "@openzeppelin/contracts/access/Ownable.sol";

import "@chainlink/contracts/src/v0.8/interfaces/AggregatorV3Interface.sol";


contract BufferBNBOptions is
    IBufferOptions,
    Ownable,
    ERC721,
    ERC721Enumerable,
    ERC721Burnable,
    AccessControl
{
    uint256 public nextTokenId = 0;

    IBufferStakingBNB public settlementFeeRecipient;
    mapping(uint256 => Option) public options;
    uint256 public impliedVolRate;
    uint256 public optionCollateralizationRatio = 100;
    uint256 public settlementFeePercentage = 4;
    uint256 public stakingFeePercentage = 75;
    uint256 public referralRewardPercentage = 50;
    uint256 internal constant PRICE_DECIMALS = 1e8;
    uint256 internal contractCreationTimestamp;
    bool internal migrationProcess = true;
    AggregatorV3Interface public priceProvider;
    BufferBNBPool public pool;


    constructor(
        AggregatorV3Interface pp,
        IBufferStakingBNB staking,
        BufferBNBPool _pool
    ) ERC721("Buffer", "BFR") {
        _setupRole(DEFAULT_ADMIN_ROLE, msg.sender);
        pool = _pool;
        priceProvider = pp;
        settlementFeeRecipient = staking;
        impliedVolRate = 4500;
        contractCreationTimestamp = block.timestamp;
    }


    function setImpliedVolRate(uint256 value) external onlyOwner {
        require(value >= 1000, "ImpliedVolRate limit is too small");
        impliedVolRate = value;
    }


    function setSettlementFeePercentage(uint256 value) external onlyOwner {
        require(value < 20, "SettlementFeePercentage is too high");
        settlementFeePercentage = value;
    }


    function setSettlementFeeRecipient(IBufferStakingBNB recipient)
        external
        onlyOwner
    {
        require(address(recipient) != address(0));
        settlementFeeRecipient = recipient;
    }


    function setStakingFeePercentage(uint256 value) external onlyOwner {
        require(value <= 100, "StakingFeePercentage is too high");
        stakingFeePercentage = value;
    }


    function setReferralRewardPercentage(uint256 value) external onlyOwner {
        require(value <= 100, "ReferralRewardPercentage is too high");
        referralRewardPercentage = value;
    }


    function setOptionCollaterizationRatio(uint256 value) external onlyOwner {
        require(50 <= value && value <= 100, "wrong value");
        optionCollateralizationRatio = value;
    }



    function create(
        uint256 period,
        uint256 amount,
        uint256 strike,
        OptionType optionType,
        address referrer
    ) external payable returns (uint256 optionID) {
        (uint256 totalFee, uint256 settlementFee, uint256 strikeFee, ) = fees(
            period,
            amount,
            strike,
            optionType
        );

        require(
            optionType == OptionType.Call || optionType == OptionType.Put,
            "Wrong option type"
        );
        require(period >= 1 days, "Period is too short");
        require(period <= 90 days, "Period is too long");
        require(amount > strikeFee, "Price difference is too large");
        require(msg.value >= totalFee, "Wrong value");
        if (msg.value > totalFee) {
            payable(msg.sender).transfer(msg.value - totalFee);
        }

        uint256 strikeAmount = amount - strikeFee;
        uint256 lockedAmount = ((strikeAmount * optionCollateralizationRatio) / 100) + strikeFee;

        Option memory option = Option(
            State.Active,
            strike,
            amount,
            lockedAmount,
            totalFee - settlementFee,
            block.timestamp + period,
            optionType
        );

        optionID = createOptionFor(msg.sender);
        options[optionID] = option;

        uint256 stakingAmount = distributeSettlementFee(settlementFee, referrer);

        pool.lock{value: option.premium}(optionID, option.lockedAmount);

        emit Create(optionID, msg.sender, stakingAmount, totalFee);
    }


    function canExercise(uint256 optionID) internal view returns (bool){
        require(_exists(optionID), "ERC721: operator query for nonexistent token");

        address tokenOwner = ERC721.ownerOf(optionID);
        bool isAutoExerciseTrue = autoExerciseStatus[tokenOwner] && msg.sender == owner();

        Option storage option = options[optionID];
        bool isWithinLastHalfHourOfExpiry = block.timestamp > (option.expiration - 30 minutes);

        return (tokenOwner == msg.sender) || (isAutoExerciseTrue && isWithinLastHalfHourOfExpiry);
    }


    function exercise(uint256 optionID) external {
        require(
            canExercise(optionID),
            "msg.sender is not eligible to exercise the option"
        );

        Option storage option = options[optionID];

        require(option.expiration >= block.timestamp, "Option has expired");
        require(option.state == State.Active, "Wrong state");

        option.state = State.Exercised;
        uint256 profit = payProfit(optionID);


        _burn(optionID);

        emit Exercise(optionID, profit);
    }


    function unlockAll(uint256[] calldata optionIDs) external {
        uint256 arrayLength = optionIDs.length;
        for (uint256 i = 0; i < arrayLength; i++) {
            unlock(optionIDs[i]);
        }
    }


    function unlock(uint256 optionID) public {
        Option storage option = options[optionID];
        require(
            option.expiration < block.timestamp,
            "Option has not expired yet"
        );
        require(option.state == State.Active, "Option is not active");
        option.state = State.Expired;
        pool.unlock(optionID);


        _burn(optionID);

        emit Expire(optionID, option.premium);
    }


    function payProfit(uint256 optionID) internal returns (uint256 profit) {
        Option memory option = options[optionID];
        (, int256 latestPrice, , , ) = priceProvider.latestRoundData();
        uint256 currentPrice = uint256(latestPrice);
        if (option.optionType == OptionType.Call) {
            require(option.strike <= currentPrice, "Current price is too low");
            profit =
                ((currentPrice - option.strike) * option.amount) /
                currentPrice;
        } else {
            require(option.strike >= currentPrice, "Current price is too high");
            profit =
                ((option.strike - currentPrice) * option.amount) /
                currentPrice;
        }

        pool.send(optionID, payable(ownerOf(optionID)), profit);
    }


    function distributeSettlementFee(uint256 settlementFee, address referrer) internal returns (uint256 stakingAmount){
        stakingAmount = ((settlementFee * stakingFeePercentage) / 100);


        if(stakingAmount > 0){
            settlementFeeRecipient.sendProfit{value: stakingAmount}();
        }

        uint256 adminFee = settlementFee - stakingAmount;

        if(adminFee > 0){
            if(referralRewardPercentage > 0 && referrer != owner() && referrer != msg.sender){
                uint256 referralReward = (adminFee * referralRewardPercentage)/100;
                adminFee = adminFee - referralReward;
                payable(referrer).transfer(referralReward);
            }
            payable(owner()).transfer(adminFee);
        }
    }


    function fees(
        uint256 period,
        uint256 amount,
        uint256 strike,
        OptionType optionType
    )
        public
        view
        returns (
            uint256 total,
            uint256 settlementFee,
            uint256 strikeFee,
            uint256 periodFee
        )
    {
        (, int256 latestPrice, , , ) = priceProvider.latestRoundData();
        uint256 currentPrice = uint256(latestPrice);
        settlementFee = getSettlementFee(amount);
        periodFee = getPeriodFee(
            amount,
            period,
            strike,
            currentPrice,
            optionType
        );
        strikeFee = getStrikeFee(amount, strike, currentPrice, optionType);
        total = periodFee + strikeFee + settlementFee;
    }



    function getPeriodFee(
        uint256 amount,
        uint256 period,
        uint256 strike,
        uint256 currentPrice,
        OptionType optionType
    ) internal view returns (uint256 fee) {
        if (optionType == OptionType.Put)
            return
                (amount * sqrt(period) * impliedVolRate * strike) /
                (currentPrice * PRICE_DECIMALS);
        else
            return
                (amount * sqrt(period) * impliedVolRate * currentPrice) /
                (strike * PRICE_DECIMALS);
    }


    function getStrikeFee(
        uint256 amount,
        uint256 strike,
        uint256 currentPrice,
        OptionType optionType
    ) internal pure returns (uint256 fee) {
        if (strike > currentPrice && optionType == OptionType.Put)
            return ((strike - currentPrice) * amount) / currentPrice;
        if (strike < currentPrice && optionType == OptionType.Call)
            return ((currentPrice - strike) * amount) / currentPrice;
        return 0;
    }


    function getSettlementFee(uint256 amount)
        internal
        view
        returns (uint256 fee)
    {
        return (amount * settlementFeePercentage) / 100;
    }


    function createOptionFor(address holder) internal returns (uint256 id) {
        id = nextTokenId++;
        _safeMint(holder, id);
    }


    function _baseURI() internal pure override returns (string memory) {
        return "https:
    }



    function _beforeTokenTransfer(
        address from,
        address to,
        uint256 tokenId
    ) internal override(ERC721, ERC721Enumerable) {
        super._beforeTokenTransfer(from, to, tokenId);
    }

    function supportsInterface(bytes4 interfaceId)
        public
        view
        override(ERC721, ERC721Enumerable, AccessControl)
        returns (bool)
    {
        return super.supportsInterface(interfaceId);
    }


    function sqrt(uint256 x) internal pure returns (uint256 result) {
        result = x;
        uint256 k = (x / 2) + 1;
        while (k < result) (result, k) = (k, ((x / k) + k) / 2);
    }




    mapping(address => bool) public autoExerciseStatus;

    event AutoExerciseStatusChange(address indexed account, bool status);

    function setAutoExerciseStatus(bool status) public {
        autoExerciseStatus[msg.sender] = status;
        emit AutoExerciseStatusChange(msg.sender, status);
    }

}

pragma solidity >=0.6.0 <0.8.0;

interface MSiG {

    function owners() external view returns (address[] memory addresses, uint256[] memory vPowers);
    function request() external view returns (address destination, uint256 value, bytes memory data);
    function requestProgress() external view returns (uint32 requestId, uint64 timestamp, uint16 currentVote, uint16 requiredVote);
    function voteRequirement() external view returns (uint16 requiredVote, uint16 totalVote);
    function hasVoted(address owner) external view returns (bool voted, uint16 vPower);
    function createRequest(address destination, uint256 value, bytes memory data) external returns (bool);
    function vote() external returns (bool);
    function cancelRequest() external returns (bool);
    function changeOwners(address[] memory nOwners, uint16[] memory vPowers, uint16 vRate) external returns (bool);

    event Requested(uint256 requestId, address indexed destination, uint256 value, bytes data, uint16 currentVote, uint16 requiredVote);
    event Voted(address owner, uint256 requestId, uint16 currentVote, uint16 requiredVote);
    event Executed(bool status, uint256 requestId, address indexed destination, uint256 value, bytes data);
    event Cancelled(uint256 requestId);
    event OwnersChanged(address[] owners, uint16 requireVote, uint16 totalVote);
    event Deposited(address indexed sender, uint256 value);
}

contract C98MSiG is MSiG {

    address[] private _owners;
    mapping(address => uint16) private _votePowers;
    VoteRequirement private _voteRequirement;

    uint32 private _requestId;
    Request private _request;
    mapping(address => uint32) private _votes;
    VoteProgress private _voteProgress;





    constructor(address[] memory owners_, uint16[] memory vPowers_, uint16 requiredVote_) {
        _changeOwners(owners_, vPowers_, requiredVote_);
    }


    struct Request {
        address destination;
        uint256 value;
        bytes data;
    }


    struct VoteProgress {
        uint32 requestId;
        uint64 timestamp;
        uint16 currentVote;
        uint16 requiredVote;
    }


    struct VoteRequirement {
        uint16 requiredVote;
        uint16 totalVote;
    }

    modifier selfOnly() {
        require(msg.sender == address(this), "C98MSiG: Wallet only");
        _;
    }

    modifier isOwner(address owner) {
        require(_votePowers[owner] > 0, "C98MSiG: Not an owner");
        _;
    }

    modifier notOwner(address owner) {
        require(_votePowers[owner] == 0, "C98MSiG: Already an owner");
        _;
    }

    modifier validVotingPower(uint256 vPower) {
        require(vPower > 0, "C98MSiG: Invalid vote weight");
        _;
    }

    fallback() external payable {
        if (msg.value > 0) {
            emit Deposited(msg.sender, msg.value);
        }
    }


    receive() external payable {
        if (msg.value > 0) {
            emit Deposited(msg.sender, msg.value);
        }
    }




    function owners() external view override returns (address[] memory addresses, uint256[] memory vPowers) {
        uint256[] memory values = new uint256[](_owners.length);
        uint256 i;
        for (i = 0; i < _owners.length; i++) {
            values[i] = (_votePowers[_owners[i]]);
        }
        return (_owners, values);
    }





    function request() external view override returns (address destination, uint256 value, bytes memory data) {
        Request memory req = _request;
        return (req.destination, req.value, req.data);
    }






    function requestProgress() external view override returns (uint32 requestId, uint64 timestamp, uint16 currentVote, uint16 requiredVote) {
        VoteProgress memory progress = _voteProgress;
        return (progress.requestId, progress.timestamp, progress.currentVote, progress.requiredVote);
    }




    function voteRequirement() external view override returns (uint16 requiredVote, uint16 totalVote) {
        VoteRequirement memory requirement = _voteRequirement;
        return (requirement.requiredVote, requirement.totalVote);
    }




    function hasVoted(address owner) external view override returns (bool voted, uint16 vPower) {
        VoteProgress memory progress = _voteProgress;
        uint16 power = _votePowers[owner];
        if (progress.requestId == 0) {
            return (false, power);
        }
        return (progress.requestId == _votes[owner], power);
    }





    function createRequest(address destination, uint256 value, bytes memory data)
        isOwner(msg.sender)
        external override returns (bool) {
        VoteProgress memory progress = _voteProgress;
        require(progress.requestId == 0, "C98MSiG: Request pending");

        Request memory req;
        req.destination = destination;
        req.value = value;
        req.data = data;
        progress.requestId = _requestId + 1;
        progress.timestamp = uint64(block.timestamp);
        progress.requiredVote = _voteRequirement.requiredVote;
        _request = req;
        _requestId = progress.requestId;
        _voteProgress = progress;
        vote();

        emit Requested(progress.requestId, req.destination, req.value, req.data, progress.currentVote, progress.requiredVote);
        return true;
    }



    function vote()
        isOwner(msg.sender)
        public override returns (bool) {
        VoteProgress memory progress = _voteProgress;
        require(progress.requestId > 0, "C98MSiG: No pending request");
        if (_votes[msg.sender] < progress.requestId) {
            _votes[msg.sender] = progress.requestId;
            progress.currentVote += _votePowers[msg.sender];
            _voteProgress = progress;
            emit Voted(msg.sender, progress.requestId, progress.currentVote, progress.requiredVote);
        }
        if (progress.currentVote >= progress.requiredVote) {
            Request memory req = _request;
            (bool success,) = req.destination.call{value: req.value}(req.data);
            if (success) {
                delete _request;
                delete _voteProgress;
                Executed(true, progress.requestId, req.destination, req.value, req.data);
            }
            else {
                Executed(false, progress.requestId, req.destination, req.value, req.data);
            }
        }
        return true;
    }


    function cancelRequest()
        isOwner(msg.sender)
        external override returns (bool) {
        VoteProgress memory progress = _voteProgress;
        require(progress.requestId > 0, "C98MSiG: No pending request");
        require(block.timestamp - progress.timestamp > 600, "C98MSiG: 10 mins not passed");

        delete _request;
        delete _voteProgress;

        emit Cancelled(progress.requestId);
        return true;
    }






    function changeOwners(address[] memory nOwners, uint16[] memory vPowers, uint16 vRate)
        selfOnly()
        external override returns (bool) {
        _changeOwners(nOwners, vPowers, vRate);
        return true;
    }

    function _changeOwners(address[] memory nOwners, uint16[] memory vPowers, uint16 vRate) internal {
        VoteRequirement memory requirement = _voteRequirement;
        uint256 i;
        for (i = 0; i < nOwners.length; i++) {
            address nOwner = nOwners[i];
            uint16 cPower = _votePowers[nOwner];
            uint16 vPower = vPowers[i];
            require(vPower <= 256, "C98MSiG: Invalid vRate");
            if (cPower > 0) {
                if (vPower == 0) {
                    uint256 j;
                    for(j = 0; j < _owners.length; j++) {
                        if (_owners[j] == nOwner) {
                            _owners[j] = _owners[_owners.length - 1];
                            _owners.pop();
                            delete _votes[nOwner];
                            break;
                        }
                    }
                }
                requirement.totalVote -= cPower;
            }
            else {
                if (vPower > 0) {
                    _owners.push(nOwner);
                }
            }
            _votePowers[nOwner] = vPower;
            requirement.totalVote += vPower;
        }
        if (vRate > 0) {
            requirement.requiredVote = vRate;
        }
        uint256 ownerCount = _owners.length;
        require(requirement.requiredVote > 0, "C98MSiG: Invalid vRate");
        require(requirement.requiredVote <= requirement.totalVote, "C98MSiG: Invalid vRate");
        require(requirement.totalVote <= 4096, "C98MSiG: Max weight reached");
        require(ownerCount > 0, "C98MSiG: At least 1 owner");
        require(ownerCount <= 64, "C98MSiG: Max owner reached");
        _voteRequirement = requirement;

        OwnersChanged(nOwners, requirement.requiredVote, requirement.totalVote);
    }
}

contract C98MSiGFactory {
    event Created(address indexed wallet, address[] owners);





    function createMulitSig(address[] memory owners_, uint16[] memory vPowers_, uint16 requiredVote_)
        external returns (C98MSiG wallet) {
        wallet = new C98MSiG(owners_, vPowers_, requiredVote_);
        emit Created(address(wallet), owners_);
    }
}

pragma solidity 0.8.10;

import "./interfaces/IProxyVault.sol";
import "./interfaces/IFeeRegistry.sol";
import "./interfaces/IFraxFarmUniV3.sol";
import "./interfaces/IRewards.sol";
import "./interfaces/INonfungiblePositionManager.sol";
import '@openzeppelin/contracts/token/ERC20/IERC20.sol';
import '@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol';


contract StakingProxyUniV3 is IProxyVault{
    using SafeERC20 for IERC20;

    address public constant fxs = address(0x3432B6A60D23Ca0dFCa7761B7ab56459D9C964D0);
    address public constant vefxsProxy = address(0x59CFCD384746ec3035299D90782Be065e466800B);
    address public constant positionManager = address(0xC36442b4a4522E871399CD717aBDD847Ab11FE88);
    address public immutable feeRegistry; 

    address public owner; 
    address public stakingAddress; 
    address public rewards; 

    uint256 public constant FEE_DENOMINATOR = 10000;

    constructor(address _feeRegistry) {
        feeRegistry = _feeRegistry;
    }

    function vaultType() external pure returns(VaultType){
        return VaultType.UniV3;
    }

    function vaultVersion() external pure returns(uint256){
        return 1;
    }


    function initialize(address _owner, address _stakingAddress, address _stakingToken, address _rewardsAddress) external{
        require(owner == address(0),"already init");


        owner = _owner;
        stakingAddress = _stakingAddress;
        rewards = _rewardsAddress;


        IFraxFarmUniV3(_stakingAddress).stakerSetVeFXSProxy(vefxsProxy);


        INonfungiblePositionManager(positionManager).setApprovalForAll(_stakingAddress, true);
    }

    modifier onlyOwner() {
        require(owner == msg.sender, "!auth");
        _;
    }


    function onERC721Received(
        address,
        address,
        uint256,
        bytes memory
    ) external pure returns (bytes4) {
        return this.onERC721Received.selector;
    }


    function stakeLocked(uint256 _token_id, uint256 _secs) external onlyOwner{

        uint256 userLiq = IFraxFarmUniV3(stakingAddress).lockedLiquidityOf(address(this));

        if(_token_id > 0){

            INonfungiblePositionManager(positionManager).safeTransferFrom(msg.sender, address(this), _token_id);


            IFraxFarmUniV3(stakingAddress).stakeLocked(_token_id, _secs);
        }



        if(IRewards(rewards).active()){

            userLiq = IFraxFarmUniV3(stakingAddress).lockedLiquidityOf(address(this)) - userLiq;
            IRewards(rewards).deposit(owner,userLiq);
        }
    }



    function lockAdditional(uint256 _token_id, uint256 _token0_amt, uint256 _token1_amt) external onlyOwner{
        uint256 userLiq = IFraxFarmUniV3(stakingAddress).lockedLiquidityOf(address(this));

        if(_token_id > 0 && _token0_amt > 0 && _token1_amt > 0){
            address token0 = IFraxFarmUniV3(stakingAddress).uni_token0();
            address token1 = IFraxFarmUniV3(stakingAddress).uni_token1();

            IERC20(token0).safeTransferFrom(msg.sender, stakingAddress, _token0_amt);
            IERC20(token1).safeTransferFrom(msg.sender, stakingAddress, _token1_amt);


            IFraxFarmUniV3(stakingAddress).lockAdditional(_token_id, _token0_amt, _token1_amt, 0, 0, true);
        }


        if(IRewards(rewards).active()){
            userLiq = IFraxFarmUniV3(stakingAddress).lockedLiquidityOf(address(this)) - userLiq;
            IRewards(rewards).deposit(owner,userLiq);
        }
    }


    function withdrawLocked(uint256 _token_id) external onlyOwner{

        uint256 userLiq = IFraxFarmUniV3(stakingAddress).lockedLiquidityOf(address(this));


        IFraxFarmUniV3(stakingAddress).withdrawLocked(_token_id, msg.sender);


        if(IRewards(rewards).active()){

            userLiq -= IFraxFarmUniV3(stakingAddress).lockedLiquidityOf(address(this));
            IRewards(rewards).withdraw(owner,userLiq);
        }
    }


    function earned() external view returns (address[] memory token_addresses, uint256[] memory total_earned) {

        address[] memory rewardTokens = IFraxFarmUniV3(stakingAddress).getAllRewardTokens();
        uint256[] memory stakedearned = IFraxFarmUniV3(stakingAddress).earned(address(this));

        token_addresses = new address[](rewardTokens.length + IRewards(rewards).rewardTokenLength());
        total_earned = new uint256[](rewardTokens.length + IRewards(rewards).rewardTokenLength());


        for(uint256 i = 0; i < rewardTokens.length; i++){
            token_addresses[i] = rewardTokens[i];
            total_earned[i] = stakedearned[i] + IERC20(rewardTokens[i]).balanceOf(address(this));
        }

        IRewards.EarnedData[] memory extraRewards = IRewards(rewards).claimableRewards(address(this));
        for(uint256 i = 0; i < extraRewards.length; i++){
            token_addresses[i+rewardTokens.length] = extraRewards[i].token;
            total_earned[i+rewardTokens.length] = extraRewards[i].amount;
        }
    }


    function getReward() external onlyOwner{
        getReward(true);
    }





    function getReward(bool _claim) public onlyOwner{


        if(_claim){


            IFraxFarmUniV3(stakingAddress).getReward(address(this), false);
            IFraxFarmUniV3(stakingAddress).getReward(owner, true);
        }


        _processFxs();


        address[] memory rewardTokens = IFraxFarmUniV3(stakingAddress).getAllRewardTokens();


        _transferTokens(rewardTokens);


        _processExtraRewards();
    }





    function getReward(bool _claim, address[] calldata _rewardTokenList) external onlyOwner{


        if(_claim){


            IFraxFarmUniV3(stakingAddress).getReward(address(this), false);
            IFraxFarmUniV3(stakingAddress).getReward(owner, true);
        }


        _processFxs();


        _transferTokens(_rewardTokenList);


        _processExtraRewards();
    }


    function _processExtraRewards() internal{
        if(IRewards(rewards).active()){

            uint256 bal = IRewards(rewards).balanceOf(address(this));
            if(bal == 0){

                uint256 userLiq = IFraxFarmUniV3(stakingAddress).lockedLiquidityOf(address(this));
                IRewards(rewards).deposit(owner,userLiq);
            }
            IRewards(rewards).getReward(owner);
        }
    }


    function _processFxs() internal{


        uint256 totalFees = IFeeRegistry(feeRegistry).totalFees();


        uint256 fxsBalance = IERC20(fxs).balanceOf(address(this));
        uint256 sendAmount = fxsBalance * totalFees / FEE_DENOMINATOR;
        if(sendAmount > 0){
            IERC20(fxs).transfer(IFeeRegistry(feeRegistry).feeDeposit(), sendAmount);
        }


        sendAmount = IERC20(fxs).balanceOf(address(this));
        if(sendAmount > 0){
            IERC20(fxs).transfer(msg.sender, sendAmount);
        }
    }


    function _transferTokens(address[] memory _tokens) internal{

        for(uint256 i = 0; i < _tokens.length; i++){
            if(_tokens[i] != fxs){
                uint256 bal = IERC20(_tokens[i]).balanceOf(address(this));
                if(bal > 0){
                    IERC20(_tokens[i]).transfer(msg.sender, bal);
                }
            }
        }
    }



    function recoverERC721(address _tokenAddress, uint256 _token_id) external onlyOwner {
        INonfungiblePositionManager(_tokenAddress).safeTransferFrom(address(this), owner, _token_id);
    }
}

pragma solidity ^0.6.12;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/SafeERC20.sol";
import "@openzeppelin/contracts/utils/EnumerableSet.sol";
import "@openzeppelin/contracts/token
import "@openzeppelin/contracts/math/SafeMath.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "./CryptoHeroes.sol";



contract CryptoHeroesUniverse is Ownable {
  using SafeMath for uint256;
  using SafeERC20 for IERC20;


  struct UserInfo {
    uint256 amount;     
    uint256 rewardDebt; 
    uint256 requestAmount; 
    uint256 requestBlock; 












  }


  struct PoolInfo
  {
    IERC20 lpToken;           
    bool NFTisNeeded;         
    IERC721 acceptedNFT;     
    uint256 allocPoint;       
    uint256 lastRewardBlock;  
    uint256 accCheroesPerShare; 
  }


  CryptoHeroes public cheroes;

  address public devaddr;

  uint256 public cheroesPerBlock;

  address private devadr;


  PoolInfo[] public poolInfo;

  mapping (uint256 => mapping (address => UserInfo)) public userInfo;
  mapping (IERC20 => bool) public lpTokenIsExist;

  uint256 public totalAllocPoint = 0;


  event Deposit(address indexed user, uint256 indexed pid, uint256 amount);
  event Withdraw(address indexed user, uint256 indexed pid, uint256 amount);

  constructor(
    CryptoHeroes _cheroes,
    address _devaddr,
    uint256 _cheroesPerBlock
  ) public {
    cheroes = _cheroes;
    devaddr = _devaddr;
    cheroesPerBlock = _cheroesPerBlock;
  }

  function poolLength() external view returns (uint256) {
    return poolInfo.length;
  }



  function add(uint256 _allocPoint, IERC20 _lpToken, bool _withUpdate, bool _NFTisNeeded, IERC721 _acceptedNFT) public onlyOwner {
    require(lpTokenIsExist[_lpToken] == false,"This lpToken already added");
    if (_withUpdate) {
      massUpdatePools();
    }
    uint256 lastRewardBlock = block.number;
    totalAllocPoint = totalAllocPoint.add(_allocPoint);
    poolInfo.push(PoolInfo({
    lpToken: _lpToken,
    NFTisNeeded: _NFTisNeeded,
    acceptedNFT: _acceptedNFT,
    allocPoint: _allocPoint,
    lastRewardBlock: lastRewardBlock,
    accCheroesPerShare: 0
    }));
    lpTokenIsExist[_lpToken] = true;
  }


  function set(uint256 _pid, uint256 _allocPoint, bool _withUpdate) public onlyOwner {
    if (_withUpdate) {
      massUpdatePools();
    }
    totalAllocPoint = totalAllocPoint.sub(poolInfo[_pid].allocPoint).add(_allocPoint);
    poolInfo[_pid].allocPoint = _allocPoint;
  }



  function getMultiplier(uint256 _from, uint256 _to) public pure returns (uint256) {
    return _to.sub(_from);
  }


  function pendingCheroes(uint256 _pid, address _user) external view returns (uint256) {
    PoolInfo storage pool = poolInfo[_pid];
    UserInfo storage user = userInfo[_pid][_user];
    uint256 accCheroesPerShare = pool.accCheroesPerShare;
    uint256 lpSupply = pool.lpToken.balanceOf(address(this));
    if (block.number > pool.lastRewardBlock && lpSupply != 0) {
      uint256 multiplier = getMultiplier(pool.lastRewardBlock, block.number);
      uint256 cheroesReward = multiplier.mul(cheroesPerBlock).mul(pool.allocPoint).div(totalAllocPoint);
      accCheroesPerShare = accCheroesPerShare.add(cheroesReward.mul(1e12).div(lpSupply));
    }
    return user.amount.mul(accCheroesPerShare).div(1e12).sub(user.rewardDebt);
  }


  function massUpdatePools() public {
    uint256 length = poolInfo.length;
    for (uint256 pid = 0; pid < length; ++pid) {
      updatePool(pid);
    }
  }


  function dev(address _devaddr) public {
    require(msg.sender == devaddr, "dev: wut?");
    devaddr = _devaddr;
  }



  function updatePool(uint256 _pid) public {
    PoolInfo storage pool = poolInfo[_pid];
    if (block.number <= pool.lastRewardBlock) {
      return;
    }
    uint256 lpSupply = pool.lpToken.balanceOf(address(this));
    if (lpSupply == 0) {
      pool.lastRewardBlock = block.number;
      return;
    }
    uint256 multiplier = getMultiplier(pool.lastRewardBlock, block.number);
    uint256 cheroesReward = multiplier.mul(cheroesPerBlock).mul(pool.allocPoint).div(totalAllocPoint);
    cheroes.mint(address(this), cheroesReward);
    pool.accCheroesPerShare = pool.accCheroesPerShare.add(cheroesReward.mul(1e12).div(lpSupply));
    pool.lastRewardBlock = block.number;
  }



  function deposit(uint256 _pid, uint256 _amount) public {


    PoolInfo storage pool = poolInfo[_pid];
    UserInfo storage user = userInfo[_pid][msg.sender];

    updatePool(_pid);

    if(pool.NFTisNeeded == true)
    {
        require(pool.acceptedNFT.balanceOf(address(msg.sender))>0,"requires NTF token!");
    }

    if (user.amount > 0) {
      uint256 pending = user.amount.mul(pool.accCheroesPerShare).div(1e12).sub(user.rewardDebt);
      if(pending > 0) {
        safeCheroesTransfer(msg.sender, pending);
      }
    }

    if(_amount > 0) {
      pool.lpToken.safeTransferFrom(address(msg.sender), address(this), _amount);
      user.amount = user.amount.add(_amount);
    }

    user.rewardDebt = user.amount.mul(pool.accCheroesPerShare).div(1e12);

    emit Deposit(msg.sender, _pid, _amount);
  }




  function withdraw(uint256 _pid, uint256 _amount) public {
    PoolInfo storage pool = poolInfo[_pid];
    UserInfo storage user = userInfo[_pid][msg.sender];
    require(user.amount >= _amount, "withdraw: not good");
    updatePool(_pid);
    if(pool.NFTisNeeded == true)
    {
        require(pool.acceptedNFT.balanceOf(address(msg.sender))>0,"requires NTF token!");
    }
    uint256 pending = user.amount.mul(pool.accCheroesPerShare).div(1e12).sub(user.rewardDebt);
    if(pending > 0) {
        safeCheroesTransfer(msg.sender, pending);
    }
    if(_amount > 0) {
        user.amount = user.amount.sub(_amount);
        pool.lpToken.safeTransfer(address(msg.sender), _amount);
    }
    user.rewardDebt = user.amount.mul(pool.accCheroesPerShare).div(1e12);
    emit Withdraw(msg.sender, _pid, _amount);

  }



  function safeCheroesTransfer(address _to, uint256 _amount) internal {
    uint256 cheroesBal = cheroes.balanceOf(address(this));
    if (_amount > cheroesBal) {
      cheroes.transfer(_to, cheroesBal);
    } else {
      cheroes.transfer(_to, _amount);
    }
  }


    function setMigrator(IMigratorChef _migrator) public onlyOwner {
        migrator = _migrator;
    }


    function migrate(uint256 _pid) public {
        require(address(migrator) != address(0), "migrate: no migrator");
        PoolInfo storage pool = poolInfo[_pid];
        IERC20 lpToken = pool.lpToken;
        uint256 bal = lpToken.balanceOf(address(this));
        lpToken.safeApprove(address(migrator), bal);
        IERC20 newLpToken = migrator.migrate(lpToken);
        require(bal == newLpToken.balanceOf(address(this)), "migrate: bad");
        pool.lpToken = newLpToken;
    }

  function setCheroesPerBlock(uint256 _cheroesPerBlock) public onlyOwner {
    require(_cheroesPerBlock > 0, "!CheroesPerBlock-0");
    cheroesPerBlock = _cheroesPerBlock;
  }

}

pragma solidity 0.6.12;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/SafeERC20.sol";
import "@openzeppelin/contracts/math/SafeMath.sol";



contract SkyRewardPool {
    using SafeMath for uint256;
    using SafeERC20 for IERC20;


    address public operator;


    struct UserInfo {
        uint256 amount; 
        uint256 rewardDebt; 
    }


    struct PoolInfo {
        IERC20 token; 
        uint256 allocPoint; 
        uint256 lastRewardTime; 
        uint256 accSkyPerShare; 
        bool isStarted; 
    }

    IERC20 public sky;


    PoolInfo[] public poolInfo;


    mapping(uint256 => mapping(address => UserInfo)) public userInfo;


    uint256 public totalAllocPoint = 0;


    uint256 public poolStartTime;


    uint256 public poolEndTime;

    uint256 public rewardPerSecond = 0.00221968543 ether; 
    uint256 public runningTime = 365 days; 
    uint256 public constant TOTAL_REWARDS = 70000 ether;

    event Deposit(address indexed user, uint256 indexed pid, uint256 amount);
    event Withdraw(address indexed user, uint256 indexed pid, uint256 amount);
    event EmergencyWithdraw(address indexed user, uint256 indexed pid, uint256 amount);
    event RewardPaid(address indexed user, uint256 amount);

    constructor(
        address _sky,
        uint256 _poolStartTime
    ) public {
        require(block.timestamp < _poolStartTime, "late");
        if (_sky != address(0)) sky = IERC20(_sky);
        poolStartTime = _poolStartTime;
        poolEndTime = poolStartTime + runningTime;
        operator = msg.sender;
    }

    modifier onlyOperator() {
        require(operator == msg.sender, "SkyRewardPool: caller is not the operator");
        _;
    }

    function checkPoolDuplicate(IERC20 _token) internal view {
        uint256 length = poolInfo.length;
        for (uint256 pid = 0; pid < length; ++pid) {
            require(poolInfo[pid].token != _token, "SkyRewardPool: existing pool?");
        }
    }


    function add(
        uint256 _allocPoint,
        IERC20 _token,
        bool _withUpdate,
        uint256 _lastRewardTime
    ) public onlyOperator {
        checkPoolDuplicate(_token);
        if (_withUpdate) {
            massUpdatePools();
        }
        if (block.timestamp < poolStartTime) {

            if (_lastRewardTime == 0) {
                _lastRewardTime = poolStartTime;
            } else {
                if (_lastRewardTime < poolStartTime) {
                    _lastRewardTime = poolStartTime;
                }
            }
        } else {

            if (_lastRewardTime == 0 || _lastRewardTime < block.timestamp) {
                _lastRewardTime = block.timestamp;
            }
        }
        bool _isStarted =
        (_lastRewardTime <= poolStartTime) ||
        (_lastRewardTime <= block.timestamp);
        poolInfo.push(PoolInfo({
            token : _token,
            allocPoint : _allocPoint,
            lastRewardTime : _lastRewardTime,
            accSkyPerShare : 0,
            isStarted : _isStarted
            }));
        if (_isStarted) {
            totalAllocPoint = totalAllocPoint.add(_allocPoint);
        }
    }


    function set(uint256 _pid, uint256 _allocPoint) public onlyOperator {
        massUpdatePools();
        PoolInfo storage pool = poolInfo[_pid];
        if (pool.isStarted) {
            totalAllocPoint = totalAllocPoint.sub(pool.allocPoint).add(
                _allocPoint
            );
        }
        pool.allocPoint = _allocPoint;
    }


    function getGeneratedReward(uint256 _fromTime, uint256 _toTime) public view returns (uint256) {
        if (_fromTime >= _toTime) return 0;
        if (_toTime >= poolEndTime) {
            if (_fromTime >= poolEndTime) return 0;
            if (_fromTime <= poolStartTime) return poolEndTime.sub(poolStartTime).mul(rewardPerSecond);
            return poolEndTime.sub(_fromTime).mul(rewardPerSecond);
        } else {
            if (_toTime <= poolStartTime) return 0;
            if (_fromTime <= poolStartTime) return _toTime.sub(poolStartTime).mul(rewardPerSecond);
            return _toTime.sub(_fromTime).mul(rewardPerSecond);
        }
    }


    function pendingReward(uint256 _pid, address _user) external view returns (uint256) {
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][_user];
        uint256 accSkyPerShare = pool.accSkyPerShare;
        uint256 tokenSupply = pool.token.balanceOf(address(this));
        if (block.timestamp > pool.lastRewardTime && tokenSupply != 0) {
            uint256 _generatedReward = getGeneratedReward(pool.lastRewardTime, block.timestamp);
            uint256 _skyReward = _generatedReward.mul(pool.allocPoint).div(totalAllocPoint);
            accSkyPerShare = accSkyPerShare.add(_skyReward.mul(1e18).div(tokenSupply));
        }
        return user.amount.mul(accSkyPerShare).div(1e18).sub(user.rewardDebt);
    }


    function massUpdatePools() public {
        uint256 length = poolInfo.length;
        for (uint256 pid = 0; pid < length; ++pid) {
            updatePool(pid);
        }
    }


    function updatePool(uint256 _pid) public {
        PoolInfo storage pool = poolInfo[_pid];
        if (block.timestamp <= pool.lastRewardTime) {
            return;
        }
        uint256 tokenSupply = pool.token.balanceOf(address(this));
        if (tokenSupply == 0) {
            pool.lastRewardTime = block.timestamp;
            return;
        }
        if (!pool.isStarted) {
            pool.isStarted = true;
            totalAllocPoint = totalAllocPoint.add(pool.allocPoint);
        }
        if (totalAllocPoint > 0) {
            uint256 _generatedReward = getGeneratedReward(pool.lastRewardTime, block.timestamp);
            uint256 _skyReward = _generatedReward.mul(pool.allocPoint).div(totalAllocPoint);
            pool.accSkyPerShare = pool.accSkyPerShare.add(_skyReward.mul(1e18).div(tokenSupply));
        }
        pool.lastRewardTime = block.timestamp;
    }


    function deposit(uint256 _pid, uint256 _amount) public {
        address _sender = msg.sender;
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][_sender];
        updatePool(_pid);
        if (user.amount > 0) {
            uint256 _pending = user.amount.mul(pool.accSkyPerShare).div(1e18).sub(user.rewardDebt);
            if (_pending > 0) {
                safeSkyTransfer(_sender, _pending);
                emit RewardPaid(_sender, _pending);
            }
        }
        if (_amount > 0) {
            pool.token.safeTransferFrom(_sender, address(this), _amount);
            user.amount = user.amount.add(_amount);
        }
        user.rewardDebt = user.amount.mul(pool.accSkyPerShare).div(1e18);
        emit Deposit(_sender, _pid, _amount);
    }



    function withdraw(uint256 _pid, uint256 _amount) public {
        address _sender = msg.sender;
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][_sender];
        require(user.amount >= _amount, "withdraw: not good");
        updatePool(_pid);
        uint256 _pending = user.amount.mul(pool.accSkyPerShare).div(1e18).sub(user.rewardDebt);
        if (_pending > 0) {
            safeSkyTransfer(_sender, _pending);
            emit RewardPaid(_sender, _pending);
        }
        if (_amount > 0) {
            user.amount = user.amount.sub(_amount);
            pool.token.safeTransfer(_sender, _amount);
        }
        user.rewardDebt = user.amount.mul(pool.accSkyPerShare).div(1e18);
        emit Withdraw(_sender, _pid, _amount);
    }

    function withdrawAll(uint256 _pid) external {
        withdraw(_pid, userInfo[_pid][msg.sender].amount);
    }

    function harvestAllRewards() public {
        uint256 length = poolInfo.length;
        for (uint256 pid = 0; pid < length; ++pid) {
            if (userInfo[pid][msg.sender].amount > 0) {
                withdraw(pid, 0);
            }
        }
    }


    function emergencyWithdraw(uint256 _pid) public {
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][msg.sender];
        uint256 _amount = user.amount;
        user.amount = 0;
        user.rewardDebt = 0;
        pool.token.safeTransfer(msg.sender, _amount);
        emit EmergencyWithdraw(msg.sender, _pid, _amount);
    }


    function safeSkyTransfer(address _to, uint256 _amount) internal {
        uint256 _skyBal = sky.balanceOf(address(this));
        if (_skyBal > 0) {
            if (_amount > _skyBal) {
                sky.safeTransfer(_to, _skyBal);
            } else {
                sky.safeTransfer(_to, _amount);
            }
        }
    }

    function setOperator(address _operator) external onlyOperator {
        operator = _operator;
    }

    function governanceRecoverUnsupported(IERC20 _token, uint256 amount, address to) external onlyOperator {
        if (block.timestamp < poolEndTime + 90 days) {

            require(_token != sky, "sky");
            uint256 length = poolInfo.length;
            for (uint256 pid = 0; pid < length; ++pid) {
                PoolInfo storage pool = poolInfo[pid];
                require(_token != pool.token, "pool.token");
            }
        }
        _token.safeTransfer(to, amount);
    }
}

pragma solidity =0.6.12;
pragma experimental ABIEncoderV2;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/SafeERC20.sol";
import "@openzeppelin/contracts/math/SafeMath.sol";


contract SinglePool is Ownable {
    using SafeMath for uint256;
    using SafeERC20 for IERC20;


    struct UserInfo {
        uint256 amount;     
        uint256 rewardDebt; 
    }


    struct PoolInfo {
        IERC20 lpToken;           
        uint256 allocPoint;       
        uint256 lastRewardBlock;  
        uint256 accRewardsPerShare; 
    }

    IERC20 public depositToken;
    IERC20 public rewardToken;




    uint256 public rewardPerBlock;


    uint256 public BONUS_MULTIPLIER = 1;


    PoolInfo[] public poolInfo;

    mapping (address => UserInfo) public userInfo;

    uint256 public totalDeposit;

    uint256 private totalAllocPoint = 0;

    uint256 public startBlock;

    uint256 public bonusEndBlock;

    event Deposit(address indexed user, uint256 amount);
    event Withdraw(address indexed user, uint256 amount);
    event EmergencyWithdraw(address indexed user, uint256 amount);

    constructor(
        IERC20 _depositToken,
        IERC20 _rewardToken,
        uint256 _rewardPerBlock,
        uint256 _startBlock,
        uint256 _bonusEndBlock
    ) public {
        depositToken = _depositToken;
        rewardToken = _rewardToken;
        rewardPerBlock = _rewardPerBlock;
        startBlock = _startBlock;
        bonusEndBlock = _bonusEndBlock;


        poolInfo.push(PoolInfo({
            lpToken: _depositToken,
            allocPoint: 1000,
            lastRewardBlock: startBlock,
            accRewardsPerShare: 0
        }));

        totalAllocPoint = 1000;


    }

    function stopReward() public onlyOwner {
        bonusEndBlock = block.number;
    }



    function getMultiplier(uint256 _from, uint256 _to) public view returns (uint256) {
        if (_to <= bonusEndBlock) {
            return _to.sub(_from).mul(BONUS_MULTIPLIER);
        } else if (_from >= bonusEndBlock) {
            return 0;
        } else {
            return bonusEndBlock.sub(_from).mul(BONUS_MULTIPLIER);
        }
    }

    function updateMultiplier(uint256 multiplierNumber) public onlyOwner {
        BONUS_MULTIPLIER = multiplierNumber;
    }


    function pendingReward(address _user) external view returns (uint256) {
        PoolInfo storage pool = poolInfo[0];
        UserInfo storage user = userInfo[_user];
        uint256 accRewardsPerShare = pool.accRewardsPerShare;
        uint256 lpSupply = totalDeposit;
        if (block.number > pool.lastRewardBlock && lpSupply != 0) {
            uint256 multiplier = getMultiplier(pool.lastRewardBlock, block.number);
            uint256 tokenReward = multiplier.mul(rewardPerBlock).mul(pool.allocPoint).div(totalAllocPoint);
            accRewardsPerShare = accRewardsPerShare.add(tokenReward.mul(1e18).div(lpSupply));
        }
        return user.amount.mul(accRewardsPerShare).div(1e18).sub(user.rewardDebt);
    }


    function updatePool(uint256 _pid) public {
        PoolInfo storage pool = poolInfo[_pid];
        if (block.number <= pool.lastRewardBlock) {
            return;
        }
        uint256 lpSupply = totalDeposit;
        if (lpSupply == 0) {
            pool.lastRewardBlock = block.number;
            return;
        }
        uint256 multiplier = getMultiplier(pool.lastRewardBlock, block.number);
        uint256 tokenReward = multiplier.mul(rewardPerBlock).mul(pool.allocPoint).div(totalAllocPoint);
        pool.accRewardsPerShare = pool.accRewardsPerShare.add(tokenReward.mul(1e18).div(lpSupply));
        pool.lastRewardBlock = block.number;
    }


    function massUpdatePools() public {
        uint256 length = poolInfo.length;
        for (uint256 pid = 0; pid < length; ++pid) {
            updatePool(pid);
        }
    }


    function deposit(uint256 _amount) public {
        PoolInfo storage pool = poolInfo[0];
        UserInfo storage user = userInfo[msg.sender];



        updatePool(0);

        if (user.amount > 0) {
            uint256 pending = user.amount.mul(pool.accRewardsPerShare).div(1e18).sub(user.rewardDebt);
            if(pending > 0) {
                uint256 bal = rewardToken.balanceOf(address(this));
                if(bal >= pending) {
                    rewardToken.safeTransfer(address(msg.sender), pending);
                } else {
                    rewardToken.safeTransfer(address(msg.sender), bal);
                }
            }
        }
        if(_amount > 0) {
            uint256 oldBal = pool.lpToken.balanceOf(address(this));
            pool.lpToken.safeTransferFrom(address(msg.sender), address(this), _amount);
            _amount = pool.lpToken.balanceOf(address(this)).sub(oldBal);

            user.amount = user.amount.add(_amount);
            totalDeposit = totalDeposit.add(_amount);
        }
        user.rewardDebt = user.amount.mul(pool.accRewardsPerShare).div(1e18);

        emit Deposit(msg.sender, _amount);
    }


    function withdraw(uint256 _amount) public {
        PoolInfo storage pool = poolInfo[0];
        UserInfo storage user = userInfo[msg.sender];
        require(user.amount >= _amount, "withdraw: not good");
        updatePool(0);
        uint256 pending = user.amount.mul(pool.accRewardsPerShare).div(1e18).sub(user.rewardDebt);
        if(pending > 0) {
            uint256 bal = rewardToken.balanceOf(address(this));
            if(bal >= pending) {
                rewardToken.safeTransfer(address(msg.sender), pending);
            } else {
                rewardToken.safeTransfer(address(msg.sender), bal);
            }
        }
        if(_amount > 0) {
            user.amount = user.amount.sub(_amount);
            totalDeposit = totalDeposit.sub(_amount);
            pool.lpToken.safeTransfer(address(msg.sender), _amount);
        }
        user.rewardDebt = user.amount.mul(pool.accRewardsPerShare).div(1e18);

        emit Withdraw(msg.sender, _amount);
    }



    function emergencyWithdraw() public {
        PoolInfo storage pool = poolInfo[0];
        UserInfo storage user = userInfo[msg.sender];
        pool.lpToken.safeTransfer(address(msg.sender), user.amount);
        if(totalDeposit >= user.amount) {
            totalDeposit = totalDeposit.sub(user.amount);
        } else {
            totalDeposit = 0;
        }
        user.amount = 0;
        user.rewardDebt = 0;
        emit EmergencyWithdraw(msg.sender, user.amount);
    }


    function emergencyRewardWithdraw(uint256 _amount) public onlyOwner {
        require(_amount <= rewardToken.balanceOf(address(this)), 'not enough token');
        rewardToken.safeTransfer(address(msg.sender), _amount);
    }

}

